import type { PublicCard } from '../../../types';

export const businessCards: PublicCard[] = [
  { id: 'dc-business-0001', deck_id: 'deck-business', front: 'Return on Investment (ROI)', back: 'A measure of profitability calculated as (Net Profit / Cost of Investment) × 100. It expresses how efficiently an investment generates returns.', sort_order: 1 , front_translations: {"es":"Retorno sobre Investimento (ROI)","de":"Return on Investment (ROI)","fr":"Retour sur investissement (ROI)","tr":"Yatırım Getirisi (ROI)","nl":"Return on Investment (ROI)","ru":"Рентабельность инвестиций (ROI)","zh":"投资回报率（ROI）","pt_BR":"Retorno sobre Investimento (ROI)","pt_PT":"Retorno sobre Investimento (ROI)"}, back_translations: {"es":"Una medida de rentabilidad calculada como (Lucro Líquido / Custo del Investimento) × 100. Expressa con que eficiencia un inversión genera retornos.","de":"Ein Rentabilitätsmaß, berechnet als (Nettogewinn / Investitionskosten) × 100. Es gibt an, wie effizient eine Investition Erträge erzielt.","fr":"Une mesure de rentabilité calculée comme (Bénéfice net / Coût de l'investissement) × 100. Elle exprime l'efficacité avec laquelle un investissement génère des rendements.","tr":"(Net Kâr / Yatırım Maliyeti) × 100 formülüyle hesaplanan kârlılık ölçüsü. Bir yatırımın ne kadar verimli getiri sağladığını ifade eder.","nl":"Een maatstaf voor winstgevendheid berekend als (Nettowinst / Investeringskosten) × 100. Het geeft aan hoe efficiënt een investering rendementen genereert.","ru":"Показатель рентабельности, рассчитываемый как (Чистая прибыль / Стоимость инвестиций) × 100. Отражает эффективность получения дохода от инвестиций.","zh":"盈利能力指标，计算公式为（净利润 / 投资成本）× 100。用于衡量投资产生回报的效率。","pt_BR":"Uma medida de lucratividade calculada como (Lucro Líquido / Custo do Investimento) × 100. Expressa com que eficiência um investimento gera retornos.","pt_PT":"Uma medida de rentabilidade calculada como (Lucro Líquido / Custo do Investimento) × 100. Expressa a eficiência com que um investimento gera retornos."}},
  { id: 'dc-business-0002', deck_id: 'deck-business', front: 'Net Present Value (NPV)', back: 'The difference between the present value of cash inflows and outflows over a period. A positive NPV indicates a profitable investment.', sort_order: 2 , front_translations: {"es":"Valor Presente Líquido (VPL)","de":"Kapitalwert (NPV)","fr":"Valeur actuelle nette (VAN)","tr":"Net Bugünkü Değer (NBD)","nl":"Netto contante waarde (NCW)","ru":"Чистая приведённая стоимость (NPV)","zh":"净现值（NPV）","pt_BR":"Valor Presente Líquido (VPL)","pt_PT":"Valor Atual Líquido (VAL)"}, back_translations: {"es":"La diferencia entre el valor presente de las entradas y saídas de caixa a lo ancho de un período. Un VPL positivo indica un inversión lucrativo.","de":"Die Differenz zwischen dem Barwert der Mittelzuflüsse und -abflüsse über einen Zeitraum. Ein positiver Kapitalwert weist auf eine rentable Investition hin.","fr":"La différence entre la valeur actuelle des entrées et sorties de trésorerie sur une période. Une VAN positive indique un investissement rentable.","tr":"Bir dönem boyunca nakit girişlerinin ve çıkışlarının bugünkü değerleri arasındaki fark. Pozitif bir NBD, kârlı bir yatırıma işaret eder.","nl":"Het verschil tussen de contante waarde van kasstromen en kasuitstromen over een periode. Een positieve NCW duidt op een winstgevende investering.","ru":"Разница между приведённой стоимостью денежных поступлений и выплат за период. Положительное значение NPV свидетельствует о прибыльности инвестиции.","zh":"一段时间内现金流入与流出现值之差。正净现值表明该投资有利可图。","pt_BR":"A diferença entre o valor presente das entradas e saídas de caixa ao longo de um período. Um VPL positivo indica um investimento lucrativo.","pt_PT":"A diferença entre o valor atual das entradas e saídas de caixa ao longo de um período. Um VAL positivo indica um investimento rentável."}},
  { id: 'dc-business-0003', deck_id: 'deck-business', front: 'EBITDA', back: 'Earnings Before Interest, Taxes, Depreciation, and Amortization. A widely used measure of a company\'s core operational profitability, removing the effects of financing and accounting decisions.', sort_order: 3 , front_translations: {"es":"EBITDA (LAJIDA)","de":"EBITDA","fr":"EBITDA","tr":"FAVÖK","nl":"EBITDA","ru":"EBITDA","zh":"息税折旧摊销前利润（EBITDA）","pt_BR":"EBITDA (LAJIDA)","pt_PT":"EBITDA (LAJIDA)"}, back_translations: {"es":"Lucros antes de juros, impuestos, depreciación y amortización. Una medida amplamente utilizada de la rentabilidad operacional central de una empresa, removendo los efectos de decisões financeras y contábeis.","de":"Ergebnis vor Zinsen, Steuern, Abschreibungen auf Sachanlagen und Abschreibungen auf immaterielle Vermögenswerte. Ein weit verbreitetes Maß für die betriebliche Kernrentabilität, das Finanzierungs- und Bilanzierungseffekte ausblendet.","fr":"Bénéfice avant intérêts, impôts, dépréciation et amortissement. Une mesure largement utilisée de la rentabilité opérationnelle principale d'une entreprise, éliminant les effets des décisions de financement et comptables.","tr":"Faiz, Vergi, Amortisman ve İtfa Öncesi Kazanç. Finansman ve muhasebe kararlarının etkilerini dışlayan, bir şirketin temel operasyonel kârlılığının yaygın kullanılan bir ölçüsüdür.","nl":"Winst vóór rente, belastingen, afschrijvingen op materiële en immateriële activa. Een veelgebruikte maatstaf voor de operationele kernwinstgevendheid van een bedrijf, vrij van financierings- en boekhoudkundige effecten.","ru":"Прибыль до вычета процентов, налогов, износа и амортизации. Широко используемый показатель операционной рентабельности компании, исключающий влияние финансовых и учётных решений.","zh":"即扣除利息、税项、折旧及摊销前的盈利。广泛用于衡量企业核心运营盈利能力，剔除融资和会计决策的影响。","pt_BR":"Lucros antes de juros, impostos, depreciação e amortização. Uma medida amplamente utilizada da lucratividade operacional central de uma empresa, removendo os efeitos de decisões financeiras e contábeis.","pt_PT":"Lucros antes de juros, impostos, depreciação e amortização. Uma medida amplamente utilizada da rentabilidade operacional central de uma empresa, removendo os efeitos de decisões de financiamento e contabilísticas."}},
  { id: 'dc-business-0004', deck_id: 'deck-business', front: 'Internal Rate of Return (IRR)', back: 'The discount rate at which the NPV of an investment equals zero. A higher IRR relative to the cost of capital indicates a more desirable investment.', sort_order: 4 , front_translations: {"es":"Taxa Interna de Retorno (TIR)","de":"Interner Zinsfuß (IRR)","fr":"Taux de rendement interne (TRI)","tr":"İç Verim Oranı (İVO)","nl":"Interne rentevoet (IRR)","ru":"Внутренняя норма доходности (IRR)","zh":"内部收益率（IRR）","pt_BR":"Taxa Interna de Retorno (TIR)","pt_PT":"Taxa Interna de Rentabilidade (TIR)"}, back_translations: {"es":"La taxa de desconto en la qual el VPL de un inversión es igual a zero. Una TIR más alta en relación con el costo de capital indica un inversión más desejable.","de":"Der Abzinsungssatz, bei dem der Kapitalwert einer Investition gleich null ist. Ein höherer IRR im Vergleich zu den Kapitalkosten zeigt eine attraktivere Investition an.","fr":"Le taux d'actualisation auquel la VAN d'un investissement est égale à zéro. Un TRI plus élevé par rapport au coût du capital indique un investissement plus désirable.","tr":"Bir yatırımın NBD'sinin sıfıra eşit olduğu iskonto oranı. Sermaye maliyetine kıyasla daha yüksek bir İVO, daha cazip bir yatırıma işaret eder.","nl":"De discontovoet waarbij de NCW van een investering gelijk is aan nul. Een hogere IRR ten opzichte van de kapitaalkosten duidt op een aantrekkelijkere investering.","ru":"Ставка дисконтирования, при которой NPV инвестиции равна нулю. Чем выше IRR относительно стоимости капитала, тем более привлекательна инвестиция.","zh":"使投资净现值等于零的折现率。相对于资本成本，内部收益率越高，说明投资越具吸引力。","pt_BR":"A taxa de desconto na qual o VPL de um investimento é igual a zero. Uma TIR mais alta em relação ao custo de capital indica um investimento mais desejável.","pt_PT":"A taxa de desconto à qual o VAL de um investimento é igual a zero. Uma TIR mais elevada em relação ao custo de capital indica um investimento mais desejável."}},
  { id: 'dc-business-0005', deck_id: 'deck-business', front: 'Gross Profit Margin', back: 'Calculated as (Revenue − Cost of Goods Sold) / Revenue × 100. It measures how efficiently a company produces goods relative to its revenue.', sort_order: 5 , front_translations: {"es":"Margem de Lucro Bruto","de":"Bruttogewinnmarge","fr":"Marge brute","tr":"Brüt Kâr Marjı","nl":"Brutowinstmarge","ru":"Валовая прибыльность (маржа)","zh":"毛利率","pt_BR":"Margem de Lucro Bruto","pt_PT":"Margem de Lucro Bruto"}, back_translations: {"es":"Calculada como (Receita − Custo de los Produtos Vendidos) / Receita × 100. Mede a eficiencia con que una empresa produce bens en relación con la su ingreso.","de":"Berechnet als (Umsatz − Herstellungskosten) / Umsatz × 100. Misst, wie effizient ein Unternehmen Waren im Verhältnis zu seinem Umsatz produziert.","fr":"Calculée comme (Chiffre d'affaires − Coût des marchandises vendues) / Chiffre d'affaires × 100. Elle mesure l'efficacité avec laquelle une entreprise produit des biens par rapport à ses revenus.","tr":"(Gelir − Satılan Malın Maliyeti) / Gelir × 100 formülüyle hesaplanır. Bir şirketin gelirine oranla malları ne kadar verimli ürettiğini ölçer.","nl":"Berekend als (Omzet − Kostprijs van verkochte goederen) / Omzet × 100. Het meet hoe efficiënt een bedrijf goederen produceert ten opzichte van zijn omzet.","ru":"Рассчитывается как (Выручка − Себестоимость) / Выручка × 100. Отражает эффективность производства товаров относительно выручки компании.","zh":"计算公式为（营收 − 销售成本）/ 营收 × 100。衡量企业相对于营收的产品生产效率。","pt_BR":"Calculada como (Receita − Custo dos Produtos Vendidos) / Receita × 100. Mede a eficiência com que uma empresa produz bens em relação à sua receita.","pt_PT":"Calculada como (Receita − Custo dos Produtos Vendidos) / Receita × 100. Mede a eficiência com que uma empresa produz bens em relação à sua receita."}},
  { id: 'dc-business-0006', deck_id: 'deck-business', front: 'Net Profit Margin', back: 'Net income divided by revenue, expressed as a percentage. It shows how much of each dollar of revenue translates into profit after all expenses.', sort_order: 6 , front_translations: {"es":"Margem de Lucro Líquido","de":"Nettogewinnmarge","fr":"Marge nette","tr":"Net Kâr Marjı","nl":"Nettowinstmarge","ru":"Чистая прибыльность (маржа)","zh":"净利率","pt_BR":"Margem de Lucro Líquido","pt_PT":"Margem de Lucro Líquido"}, back_translations: {"es":"Lucro líquido dividido por la ingreso, expresso como percentual. Mostra quanto de cada real de ingreso se convierte en ganancia após todas las gastos.","de":"Nettogewinn geteilt durch Umsatz, ausgedrückt als Prozentsatz. Zeigt, wie viel von jedem Umsatz-Euro nach allen Aufwendungen als Gewinn verbleibt.","fr":"Résultat net divisé par le chiffre d'affaires, exprimé en pourcentage. Il indique combien de chaque euro de revenu se traduit en profit après toutes les dépenses.","tr":"Net gelire bölünen net kâr, yüzde olarak ifade edilir. Tüm giderler düşüldükten sonra her bir gelir biriminden ne kadarının kâra dönüştüğünü gösterir.","nl":"Nettowinst gedeeld door omzet, uitgedrukt als percentage. Het toont hoeveel van elke euro omzet overblijft als winst na alle kosten.","ru":"Чистая прибыль, делённая на выручку, выраженная в процентах. Показывает, какая доля каждого рубля выручки остаётся в виде прибыли после всех расходов.","zh":"净利润除以营收，以百分比表示。反映扣除所有费用后，每元营收中转化为利润的比例。","pt_BR":"Lucro líquido dividido pela receita, expresso como percentual. Mostra quanto de cada real de receita se converte em lucro após todas as despesas.","pt_PT":"Lucro líquido dividido pela receita, expresso como percentagem. Mostra quanto de cada euro de receita se converte em lucro após todas as despesas."}},
  { id: 'dc-business-0007', deck_id: 'deck-business', front: 'Balance Sheet', back: 'A financial statement summarizing a company\'s assets, liabilities, and shareholders\' equity at a specific point in time; it must always balance: Assets = Liabilities + Equity.', sort_order: 7 , front_translations: {"es":"Balanço Patrimonial","de":"Bilanz","fr":"Bilan comptable","tr":"Bilanço","nl":"Balans","ru":"Бухгалтерский баланс","zh":"资产负债表","pt_BR":"Balanço Patrimonial","pt_PT":"Balanço Patrimonial"}, back_translations: {"es":"Una demonstración financera que resume los ativos, passivos y el patrimonio líquido de una empresa en un momento específico; deve siempre estar equilibrado: Ativos = Passivos + Patrimonio Líquido.","de":"Ein Abschluss, der die Vermögenswerte, Verbindlichkeiten und das Eigenkapital eines Unternehmens zu einem bestimmten Zeitpunkt zusammenfasst; er muss stets ausgeglichen sein: Aktiva = Passiva + Eigenkapital.","fr":"Un état financier résumant les actifs, les passifs et les capitaux propres d'une entreprise à un moment précis ; il doit toujours être équilibré : Actifs = Passifs + Capitaux propres.","tr":"Bir şirketin belirli bir andaki varlıklarını, yükümlülüklerini ve öz kaynaklarını özetleyen bir finansal tablo; her zaman dengeli olmalıdır: Varlıklar = Yükümlülükler + Öz Kaynaklar.","nl":"Een financieel overzicht dat de activa, verplichtingen en het eigen vermogen van een bedrijf op een specifiek moment samenvat; het moet altijd in evenwicht zijn: Activa = Verplichtingen + Eigen vermogen.","ru":"Финансовый отчёт, суммирующий активы, обязательства и собственный капитал компании на определённую дату; всегда должен быть сбалансирован: Активы = Обязательства + Капитал.","zh":"总结企业在特定时点的资产、负债和股东权益的财务报表；必须始终保持平衡：资产 = 负债 + 所有者权益。","pt_BR":"Uma demonstração financeira que resume os ativos, passivos e o patrimônio líquido de uma empresa em um momento específico; deve sempre estar equilibrado: Ativos = Passivos + Patrimônio Líquido.","pt_PT":"Uma demonstração financeira que resume os ativos, passivos e o capital próprio de uma empresa num momento específico; deve estar sempre equilibrado: Ativos = Passivos + Capital Próprio."}},
  { id: 'dc-business-0008', deck_id: 'deck-business', front: 'Income Statement (P&L)', back: 'A financial statement showing revenues, expenses, and profits or losses over a specific period. It is also called the Profit and Loss statement.', sort_order: 8 , front_translations: {"es":"Demonstración del Resultado del Exercício (DRE)","de":"Gewinn- und Verlustrechnung (GuV)","fr":"Compte de résultat (P&L)","tr":"Gelir Tablosu (Kâr/Zarar)","nl":"Winst- en verliesrekening (W&V)","ru":"Отчёт о прибылях и убытках (P&L)","zh":"损益表（P&L）","pt_BR":"Demonstração do Resultado do Exercício (DRE)","pt_PT":"Demonstração de Resultados (DR)"}, back_translations: {"es":"Una demonstración financera que mostra ingresos, gastos y ganancias o prejuízos a lo ancho de un período específico. También es llamada de Demonstración de Lucros y Perdas.","de":"Ein Abschluss, der Umsätze, Aufwendungen sowie Gewinne oder Verluste über einen bestimmten Zeitraum zeigt. Er wird auch als Gewinn- und Verlustrechnung bezeichnet.","fr":"Un état financier présentant les revenus, les charges et les profits ou pertes sur une période donnée. Il est également appelé compte de profits et pertes.","tr":"Belirli bir dönem boyunca gelirleri, giderleri ve kâr ya da zararları gösteren finansal tablo. Kâr ve Zarar tablosu olarak da adlandırılır.","nl":"Een financieel overzicht met inkomsten, kosten en winsten of verliezen over een bepaalde periode. Het wordt ook de winst-en-verliesrekening genoemd.","ru":"Финансовый отчёт, отражающий выручку, расходы и прибыль или убытки за определённый период. Также называется отчётом о прибылях и убытках.","zh":"反映特定期间收入、费用及盈亏情况的财务报表，又称利润表。","pt_BR":"Uma demonstração financeira que mostra receitas, despesas e lucros ou prejuízos ao longo de um período específico. Também é chamada de Demonstração de Lucros e Perdas.","pt_PT":"Uma demonstração financeira que mostra receitas, gastos e lucros ou perdas ao longo de um período específico. Também é chamada de Demonstração de Ganhos e Perdas."}},
  { id: 'dc-business-0009', deck_id: 'deck-business', front: 'Cash Flow Statement', back: 'A financial statement that tracks the movement of cash into and out of a business across operating, investing, and financing activities.', sort_order: 9 , front_translations: {"es":"Demonstración del Fluxo de Caixa (DFC)","de":"Kapitalflussrechnung","fr":"Tableau des flux de trésorerie","tr":"Nakit Akış Tablosu","nl":"Kasstroomoverzicht","ru":"Отчёт о движении денежных средств","zh":"现金流量表","pt_BR":"Demonstração do Fluxo de Caixa (DFC)","pt_PT":"Demonstração dos Fluxos de Caixa (DFC)"}, back_translations: {"es":"Una demonstración financera que rastreia a movimentación de caixa de entrada y saída de un negocio en las atividades operacionais, de inversión y de financiamento.","de":"Ein Abschluss, der die Bewegung von Zahlungsmitteln in und aus einem Unternehmen über betriebliche, investive und finanzielle Tätigkeiten verfolgt.","fr":"Un état financier qui suit les mouvements de trésorerie entrant et sortant d'une entreprise dans les activités d'exploitation, d'investissement et de financement.","tr":"Bir işletmeye giren ve çıkan nakit hareketlerini faaliyet, yatırım ve finansman faaliyetleri kapsamında izleyen finansal tablo.","nl":"Een financieel overzicht dat de beweging van geld in en uit een bedrijf bijhoudt via operationele, investerings- en financieringsactiviteiten.","ru":"Финансовый отчёт, отслеживающий движение денежных средств в компанию и из неё по операционной, инвестиционной и финансовой деятельности.","zh":"追踪企业在经营、投资和筹资活动中现金流入和流出情况的财务报表。","pt_BR":"Uma demonstração financeira que rastreia a movimentação de caixa de entrada e saída de um negócio nas atividades operacionais, de investimento e de financiamento.","pt_PT":"Uma demonstração financeira que acompanha o movimento de caixa de entrada e saída de um negócio nas atividades operacionais, de investimento e de financiamento."}},
  { id: 'dc-business-0010', deck_id: 'deck-business', front: 'Assets', back: 'Resources owned or controlled by a company that are expected to generate future economic benefits; classified as current (short-term) or non-current (long-term).', sort_order: 10 , front_translations: {"es":"Ativos","de":"Vermögenswerte (Assets)","fr":"Actifs","tr":"Varlıklar","nl":"Activa","ru":"Активы","zh":"资产","pt_BR":"Ativos","pt_PT":"Ativos"}, back_translations: {"es":"Recursos possuídos o controlados por una empresa que devem gerar benefícios económicos futuros; classificados como circulantes (corto prazo) o no circulantes (ancho prazo).","de":"Ressourcen, die einem Unternehmen gehören oder von ihm kontrolliert werden und voraussichtlich künftige wirtschaftliche Vorteile bringen; unterteilt in kurzfristige (Umlaufvermögen) und langfristige (Anlagevermögen).","fr":"Ressources possédées ou contrôlées par une entreprise et devant générer des avantages économiques futurs ; classées en actifs courants (court terme) ou non courants (long terme).","tr":"Bir şirketin sahip olduğu veya kontrol ettiği, gelecekte ekonomik fayda sağlaması beklenen kaynaklar; dönen varlıklar (kısa vadeli) veya duran varlıklar (uzun vadeli) olarak sınıflandırılır.","nl":"Hulpbronnen die eigendom zijn van of beheerd worden door een bedrijf en naar verwachting toekomstige economische voordelen zullen genereren; ingedeeld als vlottende (kortlopende) of vaste (langlopende) activa.","ru":"Ресурсы, принадлежащие компании или находящиеся под её контролем, которые должны приносить будущие экономические выгоды; классифицируются как оборотные (краткосрочные) или внеоборотные (долгосрочные).","zh":"企业拥有或控制的、预期能带来未来经济利益的资源；分为流动资产（短期）和非流动资产（长期）。","pt_BR":"Recursos possuídos ou controlados por uma empresa que devem gerar benefícios econômicos futuros; classificados como circulantes (curto prazo) ou não circulantes (longo prazo).","pt_PT":"Recursos possuídos ou controlados por uma empresa que se espera que gerem benefícios económicos futuros; classificados como correntes (curto prazo) ou não correntes (longo prazo)."}},
  { id: 'dc-business-0011', deck_id: 'deck-business', front: 'Liabilities', back: 'Financial obligations a company owes to external parties; classified as current (due within a year) or long-term. They reduce shareholders\' equity.', sort_order: 11 , front_translations: {"es":"Passivos","de":"Verbindlichkeiten (Liabilities)","fr":"Passifs","tr":"Yükümlülükler","nl":"Verplichtingen / Passiva","ru":"Обязательства","zh":"负债","pt_BR":"Passivos","pt_PT":"Passivos"}, back_translations: {"es":"Obrigaciones financeras que una empresa deve a partes externas; classificadas como circulantes (con vencimento en hasta un ano) o de ancho prazo. Reduzem el patrimonio líquido.","de":"Finanzielle Verpflichtungen eines Unternehmens gegenüber externen Parteien; unterteilt in kurzfristige (innerhalb eines Jahres fällig) und langfristige. Sie mindern das Eigenkapital.","fr":"Obligations financières qu'une entreprise doit à des tiers ; classées en courantes (exigibles dans l'année) ou à long terme. Elles réduisent les capitaux propres.","tr":"Bir şirketin dış taraflara karşı finansal yükümlülükleri; kısa vadeli (bir yıl içinde vadesi gelen) veya uzun vadeli olarak sınıflandırılır. Öz kaynakları azaltır.","nl":"Financiële verplichtingen van een bedrijf aan externe partijen; ingedeeld als kortlopend (binnen een jaar verschuldigd) of langlopend. Ze verminderen het eigen vermogen.","ru":"Финансовые обязательства компании перед внешними сторонами; классифицируются как краткосрочные (подлежащие погашению в течение года) или долгосрочные. Уменьшают собственный капитал.","zh":"企业对外部各方所承担的财务义务；分为流动负债（一年内到期）和长期负债。负债会减少股东权益。","pt_BR":"Obrigações financeiras que uma empresa deve a partes externas; classificadas como circulantes (com vencimento em até um ano) ou de longo prazo. Reduzem o patrimônio líquido.","pt_PT":"Obrigações financeiras que uma empresa deve a partes externas; classificadas como correntes (com vencimento dentro de um ano) ou de longo prazo. Reduzem o capital próprio."}},
  { id: 'dc-business-0012', deck_id: 'deck-business', front: 'Shareholders\' Equity', back: 'The residual interest in a company\'s assets after deducting liabilities; also called net assets or book value. It represents the owners\' stake in the company.', sort_order: 12 , front_translations: {"es":"Patrimonio Líquido","de":"Eigenkapital (Shareholders' Equity)","fr":"Capitaux propres","tr":"Öz Kaynaklar (Öz Sermaye)","nl":"Eigen vermogen","ru":"Собственный капитал акционеров","zh":"股东权益","pt_BR":"Patrimônio Líquido","pt_PT":"Capital Próprio"}, back_translations: {"es":"El interesse residual en los ativos de una empresa após a dedución de los passivos; también llamado de ativos líquidos o valor contábil. Representa a participación de los proprietários en la empresa.","de":"Das Restinteresse an den Vermögenswerten eines Unternehmens nach Abzug der Verbindlichkeiten; auch Nettovermögen oder Buchwert genannt. Es stellt den Anteil der Eigentümer am Unternehmen dar.","fr":"L'intérêt résiduel dans les actifs d'une entreprise après déduction des passifs ; également appelé actif net ou valeur comptable. Il représente la participation des propriétaires dans l'entreprise.","tr":"Yükümlülükler düşüldükten sonra bir şirketin varlıklarındaki kalan pay; net varlık veya defter değeri olarak da adlandırılır. Sahiplerin şirketteki hissesini temsil eder.","nl":"Het resterende belang in de activa van een bedrijf na aftrek van de verplichtingen; ook wel nettoactiva of boekwaarde genoemd. Het vertegenwoordigt het aandeel van de eigenaren in het bedrijf.","ru":"Остаточная доля в активах компании после вычета обязательств; также называется чистыми активами или балансовой стоимостью. Представляет долю собственников в компании.","zh":"扣除负债后企业资产中的剩余权益；也称净资产或账面价值。代表所有者在企业中的权益份额。","pt_BR":"O interesse residual nos ativos de uma empresa após a dedução dos passivos; também chamado de ativos líquidos ou valor contábil. Representa a participação dos proprietários na empresa.","pt_PT":"O interesse residual nos ativos de uma empresa após a dedução dos passivos; também denominado ativos líquidos ou valor contabilístico. Representa a participação dos proprietários na empresa."}},
  { id: 'dc-business-0013', deck_id: 'deck-business', front: 'Depreciation', back: 'The systematic allocation of the cost of a tangible asset over its useful life. It is a non-cash expense that reduces taxable income.', sort_order: 13 , front_translations: {"es":"Depreciación","de":"Abschreibung (Depreciation)","fr":"Dépréciation / Amortissement (immobilisations corporelles)","tr":"Amortisman (Maddi Duran Varlıklar)","nl":"Afschrijving (materiële vaste activa)","ru":"Амортизация (материальных активов)","zh":"折旧","pt_BR":"Depreciação","pt_PT":"Depreciação"}, back_translations: {"es":"La alocación sistemática del costo de un ativo tangible a lo ancho de su vida útil. É una gasto no monetária que reduce a renda tributable.","de":"Die systematische Verteilung der Kosten eines Sachanlageguts über seine Nutzungsdauer. Es ist ein nicht zahlungswirksamer Aufwand, der das zu versteuernde Einkommen mindert.","fr":"L'allocation systématique du coût d'un actif corporel sur sa durée d'utilité. C'est une charge non monétaire qui réduit le revenu imposable.","tr":"Maddi bir varlığın maliyetinin faydalı ömrü boyunca sistematik olarak dağıtılması. Vergiye tabi geliri azaltan, nakit çıkışı gerektirmeyen bir giderdir.","nl":"De systematische toewijzing van de kosten van een materieel actief over de gebruiksduur. Het is een niet-kasgelduitgave die het belastbare inkomen vermindert.","ru":"Систематическое распределение стоимости материального актива на протяжении срока его полезного использования. Неденежный расход, уменьшающий налогооблагаемую прибыль.","zh":"将有形资产的成本在其使用寿命内系统性地分摊。这是一种非现金费用，可减少应税收入。","pt_BR":"A alocação sistemática do custo de um ativo tangível ao longo de sua vida útil. É uma despesa não monetária que reduz a renda tributável.","pt_PT":"A alocação sistemática do custo de um ativo tangível ao longo da sua vida útil. É um gasto não monetário que reduz o rendimento tributável."}},
  { id: 'dc-business-0014', deck_id: 'deck-business', front: 'Amortization', back: 'The gradual write-off of an intangible asset (e.g., patent, goodwill) over its useful life; analogous to depreciation for tangible assets.', sort_order: 14 , front_translations: {"es":"Amortización (ativos intangibles)","de":"Amortisation (immaterieller Vermögenswerte)","fr":"Amortissement (immobilisations incorporelles)","tr":"İtfa (Maddi Olmayan Duran Varlıklar)","nl":"Afschrijving (immateriële vaste activa)","ru":"Амортизация (нематериальных активов)","zh":"摊销","pt_BR":"Amortização (ativos intangíveis)","pt_PT":"Amortização (ativos intangíveis)"}, back_translations: {"es":"La extinción gradual de un ativo intangible (ex.: patente, goodwill) a lo ancho de su vida útil; análoga a la depreciación de ativos tangibles.","de":"Die schrittweise Abschreibung eines immateriellen Vermögenswerts (z. B. Patent, Geschäftswert) über seine Nutzungsdauer; analog zur Abschreibung bei Sachanlagen.","fr":"L'extinction progressive d'un actif incorporel (par ex. brevet, goodwill) sur sa durée d'utilité ; analogue à la dépréciation pour les actifs corporels.","tr":"Maddi olmayan bir varlığın (örneğin patent, şerefiye) faydalı ömrü boyunca kademeli olarak silinmesi; maddi varlıklardaki amortismana benzerdir.","nl":"De geleidelijke afschrijving van een immaterieel actief (bijv. patent, goodwill) over de gebruiksduur; analoog aan afschrijving voor materiële activa.","ru":"Постепенное списание нематериального актива (например, патента, гудвилла) на протяжении срока его полезного использования; аналогично амортизации материальных активов.","zh":"将无形资产（如专利、商誉）的价值在其使用寿命内逐步核销；类似于有形资产的折旧。","pt_BR":"A extinção gradual de um ativo intangível (ex.: patente, goodwill) ao longo de sua vida útil; análoga à depreciação de ativos tangíveis.","pt_PT":"A extinção gradual de um ativo intangível (ex.: patente, goodwill) ao longo da sua vida útil; análoga à depreciação de ativos tangíveis."}},
  { id: 'dc-business-0015', deck_id: 'deck-business', front: 'Working Capital', back: 'Current Assets minus Current Liabilities. It measures a company\'s short-term liquidity and operational efficiency.', sort_order: 15 , front_translations: {"es":"Capital de Giro","de":"Nettoumlaufvermögen (Working Capital)","fr":"Fonds de roulement (Working Capital)","tr":"İşletme Sermayesi","nl":"Nettowerkkapitaal","ru":"Оборотный капитал (рабочий)","zh":"营运资金","pt_BR":"Capital de Giro","pt_PT":"Fundo de Maneio"}, back_translations: {"es":"Ativos Circulantes menos Passivos Circulantes. Mede a liquidez de corto prazo y a eficiencia operacional de una empresa.","de":"Umlaufvermögen minus kurzfristige Verbindlichkeiten. Misst die kurzfristige Liquidität und operative Effizienz eines Unternehmens.","fr":"Actifs courants moins passifs courants. Il mesure la liquidité à court terme et l'efficacité opérationnelle d'une entreprise.","tr":"Dönen Varlıklar eksi Kısa Vadeli Yükümlülükler. Bir şirketin kısa vadeli likiditesini ve operasyonel verimliliğini ölçer.","nl":"Vlottende activa minus kortlopende verplichtingen. Het meet de kortetermijnliquiditeit en operationele efficiëntie van een bedrijf.","ru":"Оборотные активы минус краткосрочные обязательства. Измеряет краткосрочную ликвидность и операционную эффективность компании.","zh":"流动资产减去流动负债。衡量企业的短期流动性和运营效率。","pt_BR":"Ativos Circulantes menos Passivos Circulantes. Mede a liquidez de curto prazo e a eficiência operacional de uma empresa.","pt_PT":"Ativos Correntes menos Passivos Correntes. Mede a liquidez de curto prazo e a eficiência operacional de uma empresa."}},
  { id: 'dc-business-0016', deck_id: 'deck-business', front: 'Current Ratio', back: 'Current Assets divided by Current Liabilities. A ratio above 1 indicates a company can meet short-term obligations; a ratio below 1 signals potential liquidity risk.', sort_order: 16 , front_translations: {"es":"Índice de Liquidez Corrente","de":"Liquiditätsgrad (Current Ratio)","fr":"Ratio de liquidité générale","tr":"Cari Oran","nl":"Current ratio (kortetermijnliquiditeitsratio)","ru":"Коэффициент текущей ликвидности","zh":"流动比率","pt_BR":"Índice de Liquidez Corrente","pt_PT":"Rácio de Liquidez Corrente"}, back_translations: {"es":"Ativos Circulantes divididos por los Passivos Circulantes. Un índice por encima de 1 indica que a empresa puede cumprir obrigaciones de corto prazo; por debajo de 1 sinaliza riesgo potencial de liquidez.","de":"Umlaufvermögen geteilt durch kurzfristige Verbindlichkeiten. Ein Wert über 1 zeigt, dass ein Unternehmen kurzfristige Verpflichtungen erfüllen kann; ein Wert unter 1 signalisiert ein potenzielles Liquiditätsrisiko.","fr":"Actifs courants divisés par passifs courants. Un ratio supérieur à 1 indique qu'une entreprise peut faire face à ses obligations à court terme ; un ratio inférieur à 1 signale un risque de liquidité potentiel.","tr":"Dönen Varlıklar, Kısa Vadeli Yükümlülüklere bölünür. 1'in üzerindeki bir oran, şirketin kısa vadeli yükümlülüklerini karşılayabileceğini gösterir; 1'in altındaki oran potansiyel bir likidite riskine işaret eder.","nl":"Vlottende activa gedeeld door kortlopende verplichtingen. Een ratio boven 1 geeft aan dat een bedrijf kortetermijnverplichtingen kan nakomen; een ratio onder 1 wijst op potentieel liquiditeitsrisico.","ru":"Оборотные активы, делённые на краткосрочные обязательства. Коэффициент выше 1 свидетельствует о способности компании выполнять краткосрочные обязательства; ниже 1 — о потенциальном риске ликвидности.","zh":"流动资产除以流动负债。比率高于1表明企业能够偿还短期债务；低于1则预示潜在的流动性风险。","pt_BR":"Ativos Circulantes divididos pelos Passivos Circulantes. Um índice acima de 1 indica que a empresa pode cumprir obrigações de curto prazo; abaixo de 1 sinaliza risco potencial de liquidez.","pt_PT":"Ativos Correntes divididos pelos Passivos Correntes. Um rácio acima de 1 indica que a empresa pode cumprir obrigações de curto prazo; abaixo de 1 sinaliza risco potencial de liquidez."}},
  { id: 'dc-business-0017', deck_id: 'deck-business', front: 'Quick Ratio (Acid-Test)', back: '(Current Assets − Inventory) / Current Liabilities. A stricter liquidity measure that excludes inventory, as it may not be easily converted to cash.', sort_order: 17 , front_translations: {"es":"Índice de Liquidez Seca (Teste Ácido)","de":"Quick Ratio (Acid-Test)","fr":"Ratio de liquidité immédiate (Acid-Test)","tr":"Asit-Test Oranı (Likidite Oranı)","nl":"Quick ratio (zuurtest)","ru":"Коэффициент быстрой ликвидности (кислотный тест)","zh":"速动比率（酸性测试）","pt_BR":"Índice de Liquidez Seca (Teste Ácido)","pt_PT":"Rácio de Liquidez Reduzida (Teste Ácido)"}, back_translations: {"es":"(Ativos Circulantes − Estoques) / Passivos Circulantes. Una medida de liquidez más rigorosa que exclui estoques, pois pueden no ser fácilmente convertidos en caixa.","de":"(Umlaufvermögen − Vorräte) / Kurzfristige Verbindlichkeiten. Ein strengeres Liquiditätsmaß, das Vorräte ausschließt, da diese möglicherweise nicht leicht in Barmittel umgewandelt werden können.","fr":"(Actifs courants − Stocks) / Passifs courants. Une mesure de liquidité plus stricte qui exclut les stocks, car ils peuvent ne pas être facilement convertis en liquidités.","tr":"(Dönen Varlıklar − Stoklar) / Kısa Vadeli Yükümlülükler. Nakde kolayca dönüştürülemeyebileceği için stokları dışlayan, daha katı bir likidite ölçüsüdür.","nl":"(Vlottende activa − Voorraden) / Kortlopende verplichtingen. Een strengere liquiditeitsmaatstaf die voorraden uitsluit, omdat deze mogelijk niet gemakkelijk in contanten kunnen worden omgezet.","ru":"(Оборотные активы − Запасы) / Краткосрочные обязательства. Более строгий показатель ликвидности, исключающий запасы, которые могут быть сложно конвертировать в наличные.","zh":"（流动资产 − 存货）/ 流动负债。更严格的流动性指标，剔除可能难以快速变现的存货。","pt_BR":"(Ativos Circulantes − Estoques) / Passivos Circulantes. Uma medida de liquidez mais rigorosa que exclui estoques, pois podem não ser facilmente convertidos em caixa.","pt_PT":"(Ativos Correntes − Existências) / Passivos Correntes. Uma medida de liquidez mais restritiva que exclui as existências, pois podem não ser facilmente convertidas em caixa."}},
  { id: 'dc-business-0018', deck_id: 'deck-business', front: 'Accounts Receivable', back: 'Money owed to a company by customers for goods or services delivered but not yet paid for; recorded as a current asset on the balance sheet.', sort_order: 18 , front_translations: {"es":"Contas a Receber","de":"Forderungen aus Lieferungen und Leistungen (Accounts Receivable)","fr":"Créances clients","tr":"Alacak Hesapları (Ticari Alacaklar)","nl":"Debiteuren (te ontvangen bedragen)","ru":"Дебиторская задолженность","zh":"应收账款","pt_BR":"Contas a Receber","pt_PT":"Contas a Receber (Clientes)"}, back_translations: {"es":"Dinhero que los clientes devem a una empresa por bens o serviços entregues, pero aún no pagos; registrado como ativo circulante en el balanço patrimonial.","de":"Gelder, die Kunden einem Unternehmen für gelieferte, aber noch nicht bezahlte Waren oder Dienstleistungen schulden; in der Bilanz als kurzfristiger Vermögenswert ausgewiesen.","fr":"Argent dû à une entreprise par ses clients pour des biens ou services livrés mais pas encore payés ; comptabilisé comme actif courant au bilan.","tr":"Müşterilerin teslim edilen ancak henüz ödenmeyen mal veya hizmetler karşılığında bir şirkete borçlu olduğu para; bilançoda dönen varlık olarak kaydedilir.","nl":"Geld dat klanten aan een bedrijf verschuldigd zijn voor geleverde goederen of diensten die nog niet zijn betaald; opgenomen als vlottend actief op de balans.","ru":"Денежные средства, которые клиенты должны компании за поставленные, но ещё не оплаченные товары или услуги; отражаются как оборотный актив в балансе.","zh":"客户因收到货物或服务但尚未付款而欠企业的资金；在资产负债表上列为流动资产。","pt_BR":"Dinheiro que os clientes devem a uma empresa por bens ou serviços entregues, mas ainda não pagos; registrado como ativo circulante no balanço patrimonial.","pt_PT":"Dinheiro que os clientes devem a uma empresa por bens ou serviços entregues, mas ainda não pagos; registado como ativo corrente no balanço patrimonial."}},
  { id: 'dc-business-0019', deck_id: 'deck-business', front: 'Accounts Payable', back: 'Money a company owes to its suppliers for goods or services received but not yet paid for; recorded as a current liability on the balance sheet.', sort_order: 19 , front_translations: {"es":"Contas a Pagar","de":"Verbindlichkeiten aus Lieferungen und Leistungen (Accounts Payable)","fr":"Dettes fournisseurs","tr":"Borç Hesapları (Ticari Borçlar)","nl":"Crediteuren (te betalen bedragen)","ru":"Кредиторская задолженность","zh":"应付账款","pt_BR":"Contas a Pagar","pt_PT":"Contas a Pagar (Fornecedores)"}, back_translations: {"es":"Dinhero que una empresa deve a sus proveedores por bens o serviços recebidos, pero aún no pagos; registrado como passivo circulante en el balanço patrimonial.","de":"Gelder, die ein Unternehmen seinen Lieferanten für erhaltene, aber noch nicht bezahlte Waren oder Dienstleistungen schuldet; in der Bilanz als kurzfristige Verbindlichkeit ausgewiesen.","fr":"Argent qu'une entreprise doit à ses fournisseurs pour des biens ou services reçus mais pas encore payés ; comptabilisé comme passif courant au bilan.","tr":"Bir şirketin alınan ancak henüz ödenmeyen mal veya hizmetler karşılığında tedarikçilerine borçlu olduğu para; bilançoda kısa vadeli yükümlülük olarak kaydedilir.","nl":"Geld dat een bedrijf aan zijn leveranciers verschuldigd is voor ontvangen goederen of diensten die nog niet zijn betaald; opgenomen als kortlopende verplichting op de balans.","ru":"Денежные средства, которые компания должна поставщикам за полученные, но ещё не оплаченные товары или услуги; отражаются как краткосрочное обязательство в балансе.","zh":"企业因收到货物或服务但尚未付款而欠供应商的资金；在资产负债表上列为流动负债。","pt_BR":"Dinheiro que uma empresa deve a seus fornecedores por bens ou serviços recebidos, mas ainda não pagos; registrado como passivo circulante no balanço patrimonial.","pt_PT":"Dinheiro que uma empresa deve aos seus fornecedores por bens ou serviços recebidos, mas ainda não pagos; registado como passivo corrente no balanço patrimonial."}},
  { id: 'dc-business-0020', deck_id: 'deck-business', front: 'Accrual Accounting', back: 'An accounting method that records revenues and expenses when they are earned or incurred, regardless of when cash is received or paid.', sort_order: 20 , front_translations: {"es":"Contabilidad por el Regime de Competencia","de":"Periodengerechte Buchführung (Accrual Accounting)","fr":"Comptabilité d'exercice","tr":"Tahakkuk Esaslı Muhasebe","nl":"Accrual accounting (toerekeningsstelsel)","ru":"Метод начисления (учёт по начислению)","zh":"权责发生制会计","pt_BR":"Contabilidade pelo Regime de Competência","pt_PT":"Contabilidade pelo Regime de Acréscimo (Especialização)"}, back_translations: {"es":"Un método contábil que registra ingresos y gastos cuando son auferidas o incorridas, independentemente de cuando el caixa es recebido o pago.","de":"Eine Buchführungsmethode, die Erlöse und Aufwendungen erfasst, wenn sie erwirtschaftet oder entstanden sind, unabhängig davon, wann Barmittel eingehen oder ausgezahlt werden.","fr":"Une méthode comptable qui enregistre les produits et les charges lorsqu'ils sont gagnés ou engagés, indépendamment du moment où les liquidités sont reçues ou payées.","tr":"Gelirleri ve giderleri kazanıldıklarında veya tahakkuk ettiklerinde kaydeden muhasebe yöntemi; nakit alındığında veya ödendiğinde değil.","nl":"Een boekhoudmethode die inkomsten en uitgaven registreert wanneer ze worden verdiend of gemaakt, ongeacht wanneer geld wordt ontvangen of betaald.","ru":"Метод бухгалтерского учёта, при котором доходы и расходы признаются в момент их возникновения, независимо от фактического получения или выплаты денежных средств.","zh":"在收入实现或费用发生时予以确认的会计方法，而不考虑现金的实际收付时间。","pt_BR":"Um método contábil que registra receitas e despesas quando são auferidas ou incorridas, independentemente de quando o caixa é recebido ou pago.","pt_PT":"Um método contabilístico que regista receitas e gastos quando são obtidos ou incorridos, independentemente do momento em que o caixa é recebido ou pago."}},
  { id: 'dc-business-0021', deck_id: 'deck-business', front: 'Cash Basis Accounting', back: 'An accounting method that records revenues and expenses only when cash is received or paid; simpler than accrual accounting but less accurate for larger businesses.', sort_order: 21 , front_translations: {"es":"Contabilidad por el Regime de Caixa","de":"Kassenbuchführung (Cash Basis Accounting)","fr":"Comptabilité de caisse","tr":"Nakit Esaslı Muhasebe","nl":"Kasstelsel (cash basis accounting)","ru":"Кассовый метод учёта","zh":"收付实现制会计","pt_BR":"Contabilidade pelo Regime de Caixa","pt_PT":"Contabilidade pelo Regime de Caixa"}, back_translations: {"es":"Un método contábil que registra ingresos y gastos solamente cuando el caixa es recebido o pago; más simples del que el regime de competencia, pero menos preciso para empresas mayores.","de":"Eine Buchführungsmethode, die Erlöse und Aufwendungen nur erfasst, wenn Barmittel eingehen oder ausgezahlt werden; einfacher als die periodengerechte Buchführung, aber für größere Unternehmen weniger aussagekräftig.","fr":"Une méthode comptable qui n'enregistre les produits et les charges que lorsque les liquidités sont reçues ou payées ; plus simple que la comptabilité d'exercice mais moins précise pour les grandes entreprises.","tr":"Gelirleri ve giderleri yalnızca nakit alındığında veya ödendiğinde kaydeden muhasebe yöntemi; tahakkuk esaslı muhasebeden daha basit ancak büyük işletmeler için daha az doğrudur.","nl":"Een boekhoudmethode die inkomsten en uitgaven alleen registreert wanneer geld wordt ontvangen of betaald; eenvoudiger dan accrual accounting maar minder nauwkeurig voor grotere bedrijven.","ru":"Метод бухгалтерского учёта, при котором доходы и расходы признаются только при фактическом получении или выплате денежных средств; проще метода начисления, но менее точен для крупных предприятий.","zh":"仅在现金实际收付时确认收入和费用的会计方法；比权责发生制更简单，但对较大规模企业而言准确性较低。","pt_BR":"Um método contábil que registra receitas e despesas somente quando o caixa é recebido ou pago; mais simples do que o regime de competência, mas menos preciso para empresas maiores.","pt_PT":"Um método contabilístico que regista receitas e gastos apenas quando o caixa é recebido ou pago; mais simples do que o regime de especialização, mas menos preciso para empresas de maior dimensão."}},
  { id: 'dc-business-0022', deck_id: 'deck-business', front: 'Break-Even Point', back: 'The level of sales at which total revenues equal total costs, resulting in neither profit nor loss. It is calculated as Fixed Costs / (Price − Variable Cost per Unit).', sort_order: 22 , front_translations: {"es":"Ponto de Equilíbrio (Break-Even)","de":"Gewinnschwelle (Break-Even Point)","fr":"Seuil de rentabilité","tr":"Başabaş Noktası","nl":"Break-evenpunt","ru":"Точка безубыточности","zh":"盈亏平衡点","pt_BR":"Ponto de Equilíbrio (Break-Even)","pt_PT":"Ponto de Equilíbrio (Break-Even)"}, back_translations: {"es":"El nivel de ventas en el qual las ingresos totais igualam los costos totais, sin ganancia nem prejuízo. Calculado como Custos Fixos / (Preço − Custo Variable por Unidad).","de":"Das Umsatzniveau, bei dem Gesamterlöse den Gesamtkosten entsprechen und weder Gewinn noch Verlust entsteht. Berechnet als Fixkosten / (Preis − Variable Kosten je Einheit).","fr":"Le niveau de ventes auquel le total des revenus est égal au total des coûts, sans profit ni perte. Il est calculé comme Coûts fixes / (Prix − Coût variable par unité).","tr":"Toplam gelirlerin toplam maliyetlere eşit olduğu, ne kâr ne de zarar oluşan satış düzeyi. Sabit Maliyetler / (Fiyat − Birim Değişken Maliyet) olarak hesaplanır.","nl":"Het verkoopniveau waarbij totale inkomsten gelijk zijn aan totale kosten, zonder winst of verlies. Berekend als Vaste kosten / (Prijs − Variabele kosten per eenheid).","ru":"Уровень продаж, при котором суммарная выручка равна суммарным затратам, без прибыли и без убытка. Рассчитывается как Постоянные затраты / (Цена − Переменные затраты на единицу).","zh":"总收入等于总成本、既无盈利也无亏损的销售水平。计算公式为：固定成本 /（单价 − 单位变动成本）。","pt_BR":"O nível de vendas no qual as receitas totais igualam os custos totais, sem lucro nem prejuízo. Calculado como Custos Fixos / (Preço − Custo Variável por Unidade).","pt_PT":"O nível de vendas no qual as receitas totais igualam os custos totais, sem lucro nem prejuízo. Calculado como Custos Fixos / (Preço − Custo Variável por Unidade)."}},
  { id: 'dc-business-0023', deck_id: 'deck-business', front: 'Fixed Costs', back: 'Business expenses that do not change with the level of production or sales, such as rent, salaries, and insurance premiums.', sort_order: 23 , front_translations: {"es":"Custos Fixos","de":"Fixkosten","fr":"Coûts fixes","tr":"Sabit Maliyetler","nl":"Vaste kosten","ru":"Постоянные затраты","zh":"固定成本","pt_BR":"Custos Fixos","pt_PT":"Custos Fixos"}, back_translations: {"es":"Despesas operacionais que no variam con el nivel de producción o ventas, como aluguel, salários y premios de seguro.","de":"Betriebliche Aufwendungen, die sich nicht mit dem Produktions- oder Verkaufsvolumen verändern, wie Miete, Gehälter und Versicherungsprämien.","fr":"Charges d'exploitation qui ne varient pas avec le niveau de production ou de ventes, telles que le loyer, les salaires et les primes d'assurance.","tr":"Üretim veya satış düzeyiyle değişmeyen işletme giderleri; kira, maaşlar ve sigorta primleri gibi.","nl":"Bedrijfskosten die niet veranderen met het productie- of verkoopniveau, zoals huur, salarissen en verzekeringspremies.","ru":"Производственные расходы, не изменяющиеся с объёмом производства или продаж, например аренда, зарплаты и страховые взносы.","zh":"不随生产或销售水平变化的经营费用，如租金、薪酬和保险费。","pt_BR":"Despesas operacionais que não variam com o nível de produção ou vendas, como aluguel, salários e prêmios de seguro.","pt_PT":"Gastos operacionais que não variam com o nível de produção ou vendas, como renda, salários e prémios de seguro."}},
  { id: 'dc-business-0024', deck_id: 'deck-business', front: 'Variable Costs', back: 'Costs that change in proportion to the level of production or sales, such as raw materials and direct labor. They rise with output and fall when output decreases.', sort_order: 24 , front_translations: {"es":"Custos Variables","de":"Variable Kosten","fr":"Coûts variables","tr":"Değişken Maliyetler","nl":"Variabele kosten","ru":"Переменные затраты","zh":"变动成本","pt_BR":"Custos Variáveis","pt_PT":"Custos Variáveis"}, back_translations: {"es":"Custos que variam proporcionalmente al nivel de producción o ventas, como materias primas y mano de obra direta. Aumentam con el aumento de la producción y disminuyen cuando a producción cai.","de":"Kosten, die sich proportional zum Produktions- oder Verkaufsvolumen verändern, wie Rohstoffe und direkte Arbeitslöhne. Sie steigen mit der Produktion und sinken, wenn die Produktion abnimmt.","fr":"Coûts qui varient proportionnellement au niveau de production ou de ventes, tels que les matières premières et la main-d'œuvre directe. Ils augmentent avec la production et diminuent lorsqu'elle baisse.","tr":"Üretim veya satış düzeyiyle orantılı olarak değişen maliyetler; hammadde ve doğrudan işçilik gibi. Çıktıyla birlikte artar ve çıktı azaldığında düşer.","nl":"Kosten die proportioneel veranderen met het productie- of verkoopniveau, zoals grondstoffen en directe arbeid. Ze stijgen bij hogere productie en dalen wanneer de productie afneemt.","ru":"Затраты, изменяющиеся пропорционально объёму производства или продаж, например сырьё и прямые трудозатраты. Растут с увеличением выпуска и снижаются при его уменьшении.","zh":"随生产或销售水平成比例变化的成本，如原材料和直接人工。产量增加时上升，产量减少时下降。","pt_BR":"Custos que variam proporcionalmente ao nível de produção ou vendas, como matérias-primas e mão de obra direta. Aumentam com o aumento da produção e diminuem quando a produção cai.","pt_PT":"Custos que variam proporcionalmente ao nível de produção ou vendas, como matérias-primas e mão de obra direta. Aumentam com o crescimento da produção e diminuem quando esta cai."}},
  { id: 'dc-business-0025', deck_id: 'deck-business', front: 'Contribution Margin', back: 'Revenue minus variable costs; it represents the amount available to cover fixed costs and generate profit. Contribution Margin per unit = Selling Price − Variable Cost.', sort_order: 25 , front_translations: {"es":"Margem de Contribuición","de":"Deckungsbeitrag (Contribution Margin)","fr":"Marge sur coûts variables","tr":"Katkı Payı","nl":"Contributiemarge (dekkingsbijdrage)","ru":"Маржинальная прибыль (вклад на покрытие)","zh":"贡献边际（边际贡献）","pt_BR":"Margem de Contribuição","pt_PT":"Margem de Contribuição"}, back_translations: {"es":"Receita menos costos variables; representa el valor disponible para cobrir los costos fixos y gerar ganancia. Margem de Contribuición por unidad = Preço de Venda − Custo Variable.","de":"Umsatz minus variable Kosten; er gibt den Betrag an, der zur Deckung der Fixkosten und zur Erzielung von Gewinn verfügbar ist. Deckungsbeitrag je Einheit = Verkaufspreis − Variable Kosten.","fr":"Chiffre d'affaires moins coûts variables ; il représente le montant disponible pour couvrir les coûts fixes et générer du profit. Marge sur coûts variables par unité = Prix de vente − Coût variable.","tr":"Gelir eksi değişken maliyetler; sabit maliyetleri karşılamak ve kâr elde etmek için mevcut tutarı temsil eder. Birim Katkı Payı = Satış Fiyatı − Değişken Maliyet.","nl":"Omzet minus variabele kosten; het vertegenwoordigt het bedrag dat beschikbaar is om vaste kosten te dekken en winst te genereren. Contributiemarge per eenheid = Verkoopprijs − Variabele kosten.","ru":"Выручка минус переменные затраты; представляет собой сумму, доступную для покрытия постоянных затрат и получения прибыли. Маржинальная прибыль на единицу = Цена продажи − Переменные затраты.","zh":"营收减去变动成本；代表用于弥补固定成本并产生利润的可用金额。单位贡献边际 = 销售价格 − 单位变动成本。","pt_BR":"Receita menos custos variáveis; representa o valor disponível para cobrir os custos fixos e gerar lucro. Margem de Contribuição por unidade = Preço de Venda − Custo Variável.","pt_PT":"Receita menos custos variáveis; representa o valor disponível para cobrir os custos fixos e gerar lucro. Margem de Contribuição por unidade = Preço de Venda − Custo Variável."}},
  { id: 'dc-business-0026', deck_id: 'deck-business', front: 'Leverage', back: 'The use of borrowed capital (debt) to increase the potential return on an investment. High leverage amplifies both gains and losses.', sort_order: 26 , front_translations: {"es":"Alavancaje","de":"Hebel (Leverage)","fr":"Effet de levier","tr":"Kaldıraç","nl":"Hefboomwerking","ru":"Кредитное плечо (леверидж)","zh":"杠杆","pt_BR":"Alavancagem","pt_PT":"Alavancagem"}, back_translations: {"es":"El uso de capital emprestado (dívida) para aumentar el retorno potencial de un inversión. Alta alavancaje amplifica tanto los ganhos quanto las perdas.","de":"Der Einsatz von Fremdkapital (Schulden), um die potenzielle Rendite einer Investition zu steigern. Ein hoher Hebel verstärkt sowohl Gewinne als auch Verluste.","fr":"L'utilisation de capitaux empruntés (dettes) pour augmenter le rendement potentiel d'un investissement. Un fort effet de levier amplifie à la fois les gains et les pertes.","tr":"Bir yatırımın potansiyel getirisini artırmak için ödünç alınan sermayenin (borcun) kullanılması. Yüksek kaldıraç hem kazançları hem de kayıpları artırır.","nl":"Het gebruik van geleend kapitaal (schuld) om het potentiële rendement op een investering te verhogen. Een hoge hefboomwerking versterkt zowel winsten als verliezen.","ru":"Использование заёмного капитала (долга) для увеличения потенциальной доходности инвестиций. Высокое кредитное плечо усиливает как прибыль, так и убытки.","zh":"使用借入资本（债务）来提高投资潜在回报的方式。高杠杆会同时放大收益和损失。","pt_BR":"O uso de capital emprestado (dívida) para aumentar o retorno potencial de um investimento. Alta alavancagem amplifica tanto os ganhos quanto as perdas.","pt_PT":"O uso de capital emprestado (dívida) para aumentar o retorno potencial de um investimento. Uma alavancagem elevada amplifica tanto os ganhos como as perdas."}},
  { id: 'dc-business-0027', deck_id: 'deck-business', front: 'Debt-to-Equity Ratio', back: 'Total Liabilities divided by Shareholders\' Equity. It measures a company\'s financial leverage; a higher ratio implies more reliance on debt financing.', sort_order: 27 , front_translations: {"es":"Índice de Dívida sobre Patrimonio Líquido","de":"Verschuldungsgrad (Debt-to-Equity Ratio)","fr":"Ratio dettes/capitaux propres","tr":"Borç/Özkaynak Oranı","nl":"Schuld-tot-eigen-vermogenratio","ru":"Коэффициент долга к собственному капиталу","zh":"债务权益比率","pt_BR":"Índice de Dívida sobre Patrimônio Líquido","pt_PT":"Rácio Dívida/Capital Próprio"}, back_translations: {"es":"Total de passivos dividido por el patrimonio líquido. Mede a alavancaje financera de una empresa; un índice más alto implica mayor dependencia de financiamento por dívida.","de":"Gesamtverbindlichkeiten geteilt durch das Eigenkapital der Aktionäre. Er misst den finanziellen Hebel eines Unternehmens; ein höherer Wert deutet auf eine stärkere Abhängigkeit von Fremdfinanzierung hin.","fr":"Total des dettes divisé par les capitaux propres. Il mesure le levier financier d'une entreprise ; un ratio élevé implique une plus grande dépendance au financement par emprunt.","tr":"Toplam yükümlülüklerin özkaynaklara bölünmesiyle hesaplanır. Bir şirketin finansal kaldıracını ölçer; daha yüksek oran, borç finansmanına daha fazla bağımlılık anlamına gelir.","nl":"Totale verplichtingen gedeeld door het eigen vermogen van aandeelhouders. Het meet de financiële hefboomwerking van een bedrijf; een hogere ratio impliceert meer afhankelijkheid van vreemd vermogen.","ru":"Общие обязательства, делённые на собственный капитал акционеров. Измеряет финансовый рычаг компании; более высокое значение означает большую зависимость от долгового финансирования.","zh":"总负债除以股东权益。它衡量公司的财务杠杆；比率越高，表明对债务融资的依赖程度越高。","pt_BR":"Total de passivos dividido pelo patrimônio líquido. Mede a alavancagem financeira de uma empresa; um índice mais alto implica maior dependência de financiamento por dívida.","pt_PT":"Total de passivos dividido pelo capital próprio dos acionistas. Mede a alavancagem financeira de uma empresa; um rácio mais elevado implica maior dependência do financiamento por dívida."}},
  { id: 'dc-business-0028', deck_id: 'deck-business', front: 'Bond', back: 'A fixed-income debt instrument in which an investor loans money to a borrower (government or corporation) for a defined period at a fixed or variable interest rate.', sort_order: 28 , front_translations: {"es":"Título (Bond)","de":"Anleihe","fr":"Obligation","tr":"Tahvil","nl":"Obligatie","ru":"Облигация","zh":"债券","pt_BR":"Título (Bond)","pt_PT":"Obrigação"}, back_translations: {"es":"Un instrumento de dívida de renda fixa en el qual un investidor empresta dinhero a un tomador (gobierno o empresa) por un período definido a una taxa de juros fixa o variable.","de":"Ein festverzinsliches Schuldinstrument, bei dem ein Investor einem Kreditnehmer (Staat oder Unternehmen) für einen definierten Zeitraum zu einem festen oder variablen Zinssatz Geld leiht.","fr":"Un instrument de dette à revenu fixe par lequel un investisseur prête de l'argent à un emprunteur (gouvernement ou entreprise) pour une période définie à un taux d'intérêt fixe ou variable.","tr":"Bir yatırımcının belirli bir süre için sabit veya değişken faiz oranıyla bir borçluya (hükümet veya şirket) para ödünç verdiği, sabit getirili bir borçlanma aracı.","nl":"Een vastrentend schuldinstrument waarbij een investeerder geld uitleent aan een lener (overheid of onderneming) voor een bepaalde periode tegen een vaste of variabele rente.","ru":"Долговой инструмент с фиксированным доходом, при котором инвестор предоставляет заём заёмщику (государству или корпорации) на определённый срок под фиксированную или переменную процентную ставку.","zh":"一种固定收益债务工具，投资者以固定或浮动利率向借款人（政府或企业）贷款，期限明确。","pt_BR":"Um instrumento de dívida de renda fixa no qual um investidor empresta dinheiro a um tomador (governo ou empresa) por um período definido a uma taxa de juros fixa ou variável.","pt_PT":"Um instrumento de dívida de rendimento fixo em que um investidor empresta dinheiro a um mutuário (governo ou empresa) por um período definido a uma taxa de juro fixa ou variável."}},
  { id: 'dc-business-0029', deck_id: 'deck-business', front: 'Stock (Equity)', back: 'A share representing partial ownership in a corporation; stockholders may receive dividends and benefit from capital appreciation if the company\'s value grows.', sort_order: 29 , front_translations: {"es":"Ación (Patrimonio)","de":"Aktie (Eigenkapital)","fr":"Action (Capital)","tr":"Hisse Senedi (Özkaynak)","nl":"Aandeel (Eigen vermogen)","ru":"Акция (долевой капитал)","zh":"股票（股权）","pt_BR":"Ação (Patrimônio)","pt_PT":"Ação (Capital Próprio)"}, back_translations: {"es":"Una participación que representa propiedad parcial en una corporación; accionistas pueden recibir dividendos y se beneficiar de la valorización del capital se el valor de la empresa crescer.","de":"Ein Anteil, der eine teilweise Eigentümerschaft an einem Unternehmen darstellt; Aktionäre können Dividenden erhalten und von Kapitalzuwächsen profitieren, wenn der Unternehmenswert steigt.","fr":"Une part représentant une propriété partielle dans une société ; les actionnaires peuvent recevoir des dividendes et bénéficier d'une plus-value si la valeur de l'entreprise augmente.","tr":"Bir şirkette kısmi mülkiyeti temsil eden bir pay; hissedarlar temettü alabilir ve şirketin değeri artarsa sermaye kazancından yararlanabilir.","nl":"Een aandeel dat gedeeltelijk eigendom vertegenwoordigt in een vennootschap; aandeelhouders kunnen dividenden ontvangen en profiteren van vermogensgroei als de waarde van het bedrijf stijgt.","ru":"Доля, представляющая частичное владение корпорацией; акционеры могут получать дивиденды и выигрывать от прироста капитала при росте стоимости компании.","zh":"代表公司部分所有权的股份；股东可获得股息，并在公司价值增长时从资本增值中获益。","pt_BR":"Uma participação que representa propriedade parcial em uma corporação; acionistas podem receber dividendos e se beneficiar da valorização do capital se o valor da empresa crescer.","pt_PT":"Uma participação que representa propriedade parcial numa sociedade; os acionistas podem receber dividendos e beneficiar da valorização do capital se o valor da empresa crescer."}},
  { id: 'dc-business-0030', deck_id: 'deck-business', front: 'Dividend', back: 'A payment made by a corporation to its shareholders, usually from profits; can be issued as cash or additional shares of stock.', sort_order: 30 , front_translations: {"es":"Dividendo","de":"Dividende","fr":"Dividende","tr":"Temettü","nl":"Dividend","ru":"Дивиденд","zh":"股息","pt_BR":"Dividendo","pt_PT":"Dividendo"}, back_translations: {"es":"Un pagamento feito por una empresa a los sus accionistas, generalmente proveniente de los ganancias; puede ser distribuído como dinhero o acciones adicionais.","de":"Eine Zahlung, die ein Unternehmen an seine Aktionäre leistet, normalerweise aus dem Gewinn; kann als Bargeld oder als zusätzliche Aktien ausgegeben werden.","fr":"Un paiement effectué par une société à ses actionnaires, généralement prélevé sur les bénéfices ; peut être versé sous forme de liquidités ou d'actions supplémentaires.","tr":"Bir şirketin genellikle kârlarından hissedarlarına yaptığı ödeme; nakit veya ek hisse senedi olarak dağıtılabilir.","nl":"Een betaling door een vennootschap aan haar aandeelhouders, doorgaans uit winsten; kan worden uitgekeerd als contant geld of als extra aandelen.","ru":"Выплата, производимая корпорацией своим акционерам, как правило, из прибыли; может выплачиваться в виде денежных средств или дополнительных акций.","zh":"公司向股东支付的款项，通常来自利润；可以现金或额外股份的形式发放。","pt_BR":"Um pagamento feito por uma empresa aos seus acionistas, geralmente proveniente dos lucros; pode ser distribuído como dinheiro ou ações adicionais.","pt_PT":"Um pagamento efetuado por uma sociedade aos seus acionistas, normalmente proveniente dos lucros; pode ser distribuído em dinheiro ou em ações adicionais."}},
  { id: 'dc-business-0031', deck_id: 'deck-business', front: 'Dividend Yield', back: 'Annual dividends per share divided by the stock\'s current price, expressed as a percentage. It indicates the income return from holding a stock.', sort_order: 31 , front_translations: {"es":"Rendimento de Dividendos","de":"Dividendenrendite","fr":"Rendement du dividende","tr":"Temettü Verimi","nl":"Dividendrendement","ru":"Дивидендная доходность","zh":"股息收益率","pt_BR":"Rendimento de Dividendos","pt_PT":"Rendimento de Dividendos"}, back_translations: {"es":"Dividendos anuais por acción divididos por el precio atual de la acción, expresso como percentual. Indica el retorno de renda obtenido al mantener una acción.","de":"Jährliche Dividenden je Aktie geteilt durch den aktuellen Kurs der Aktie, ausgedrückt als Prozentsatz. Er zeigt die Einkommensrendite aus dem Halten einer Aktie.","fr":"Dividendes annuels par action divisés par le prix actuel de l'action, exprimés en pourcentage. Il indique le rendement en revenus de la détention d'une action.","tr":"Yıllık hisse başına temettünün hissenin mevcut fiyatına bölünmesiyle yüzde olarak ifade edilir. Bir hisse senedini elinde bulundurmanın sağladığı gelir getirisini gösterir.","nl":"Jaarlijkse dividenden per aandeel gedeeld door de huidige koers van het aandeel, uitgedrukt als een percentage. Het geeft het inkomensrendement aan van het houden van een aandeel.","ru":"Годовые дивиденды на акцию, делённые на текущую цену акции, выраженные в процентах. Показывает доходность от владения акцией.","zh":"每股年度股息除以股票当前价格，以百分比表示。它反映持有股票所获得的收益回报。","pt_BR":"Dividendos anuais por ação divididos pelo preço atual da ação, expresso como percentual. Indica o retorno de renda obtido ao manter uma ação.","pt_PT":"Dividendos anuais por ação divididos pelo preço atual da ação, expresso em percentagem. Indica o retorno de rendimento obtido ao deter uma ação."}},
  { id: 'dc-business-0032', deck_id: 'deck-business', front: 'Price-to-Earnings (P/E) Ratio', back: 'Current stock price divided by earnings per share (EPS). It indicates how much investors are willing to pay per dollar of earnings; a high P/E may suggest growth expectations.', sort_order: 32 , front_translations: {"es":"Índice Preço/Lucro (P/L)","de":"Kurs-Gewinn-Verhältnis (KGV)","fr":"Ratio cours/bénéfice (PER)","tr":"Fiyat/Kazanç (F/K) Oranı","nl":"Koers-winstverhouding (K/W)","ru":"Коэффициент цена/прибыль (P/E)","zh":"市盈率（P/E）","pt_BR":"Índice Preço/Lucro (P/L)","pt_PT":"Rácio Preço/Lucro (P/L)"}, back_translations: {"es":"Preço atual de la acción dividido por el ganancia por acción (LPA). Indica quanto los investidores están dispostos a pagar por cada real de ganancia; un P/L alto puede sugerir expectativas de crecimiento.","de":"Aktueller Aktienkurs geteilt durch den Gewinn je Aktie (EPS). Er zeigt an, wie viel Anleger bereit sind, pro Dollar Gewinn zu zahlen; ein hohes KGV kann Wachstumserwartungen signalisieren.","fr":"Prix actuel de l'action divisé par le bénéfice par action (BPA). Il indique combien les investisseurs sont prêts à payer par dollar de bénéfice ; un PER élevé peut suggérer des attentes de croissance.","tr":"Mevcut hisse senedi fiyatının hisse başına kazanca (HBK) bölünmesiyle hesaplanır. Yatırımcıların her bir dolar kazanç için ne kadar ödemeye razı olduğunu gösterir; yüksek F/K büyüme beklentilerine işaret edebilir.","nl":"De huidige aandelenkoers gedeeld door de winst per aandeel (WPA). Het geeft aan hoeveel beleggers bereid zijn te betalen per dollar winst; een hoge K/W kan groeiverwachtingen suggereren.","ru":"Текущая цена акции, делённая на прибыль на акцию (EPS). Показывает, сколько инвесторы готовы платить за каждый доллар прибыли; высокий P/E может указывать на ожидания роста.","zh":"当前股价除以每股收益（EPS）。它表示投资者愿意为每美元收益支付多少；高市盈率可能反映增长预期。","pt_BR":"Preço atual da ação dividido pelo lucro por ação (LPA). Indica quanto os investidores estão dispostos a pagar por cada real de lucro; um P/L alto pode sugerir expectativas de crescimento.","pt_PT":"Preço atual da ação dividido pelo lucro por ação (LPA). Indica quanto os investidores estão dispostos a pagar por cada euro de lucro; um P/L elevado pode sugerir expectativas de crescimento."}},
  { id: 'dc-business-0033', deck_id: 'deck-business', front: 'Market Capitalization', back: 'The total market value of a company\'s outstanding shares, calculated as Share Price × Number of Shares Outstanding. It classifies companies as small-, mid-, or large-cap.', sort_order: 33 , front_translations: {"es":"Capitalización de Mercado","de":"Marktkapitalisierung","fr":"Capitalisation boursière","tr":"Piyasa Değeri","nl":"Marktkapitalisatie","ru":"Рыночная капитализация","zh":"市值","pt_BR":"Capitalização de Mercado","pt_PT":"Capitalização de Mercado"}, back_translations: {"es":"El valor de mercado total de las acciones en circulación de una empresa, calculado como Preço de la Ación × Número de Aciones en Circulación. Classifica empresas como small-, mid- o large-cap.","de":"Der gesamte Marktwert der ausstehenden Aktien eines Unternehmens, berechnet als Aktienkurs × Anzahl der ausstehenden Aktien. Sie klassifiziert Unternehmen als Small-, Mid- oder Large-Cap.","fr":"La valeur marchande totale des actions en circulation d'une entreprise, calculée comme Prix de l'action × Nombre d'actions en circulation. Elle classe les entreprises en petites, moyennes ou grandes capitalisations.","tr":"Bir şirketin tedavüldeki hisselerinin toplam piyasa değeri; Hisse Fiyatı × Tedavüldeki Hisse Sayısı olarak hesaplanır. Şirketleri küçük, orta veya büyük ölçekli olarak sınıflandırır.","nl":"De totale marktwaarde van de uitstaande aandelen van een bedrijf, berekend als Aandelenkoers × Aantal Uitstaande Aandelen. Het classificeert bedrijven als small-, mid- of large-cap.","ru":"Общая рыночная стоимость акций компании в обращении, рассчитываемая как Цена акции × Количество акций в обращении. Классифицирует компании как малые, средние или крупные по капитализации.","zh":"公司流通股的总市场价值，计算公式为股价×流通股数。它将公司分类为小盘股、中盘股或大盘股。","pt_BR":"O valor de mercado total das ações em circulação de uma empresa, calculado como Preço da Ação × Número de Ações em Circulação. Classifica empresas como small-, mid- ou large-cap.","pt_PT":"O valor de mercado total das ações em circulação de uma empresa, calculado como Preço da Ação × Número de Ações em Circulação. Classifica as empresas como small-, mid- ou large-cap."}},
  { id: 'dc-business-0034', deck_id: 'deck-business', front: 'Initial Public Offering (IPO)', back: 'The process by which a private company first sells its shares to the public on a stock exchange; it raises capital and allows early investors to exit.', sort_order: 34 , front_translations: {"es":"Oferta Pública Inicial (IPO)","de":"Börsengang (IPO)","fr":"Introduction en bourse (IPO)","tr":"Halka Arz (IPO)","nl":"Beursintroductie (IPO)","ru":"Первичное публичное размещение акций (IPO)","zh":"首次公开发行（IPO）","pt_BR":"Oferta Pública Inicial (IPO)","pt_PT":"Oferta Pública Inicial (IPO)"}, back_translations: {"es":"El proceso por el qual una empresa privada vende sus acciones al público por la primera vez en una bolsa de valores; levanta capital y permite que los primeros investidores saiam.","de":"Der Prozess, bei dem ein privates Unternehmen erstmals seine Aktien an einer Börse öffentlich anbietet; es beschafft Kapital und ermöglicht Frühinvestoren den Ausstieg.","fr":"Le processus par lequel une entreprise privée vend ses actions au public pour la première fois sur une bourse ; cela permet de lever des capitaux et aux premiers investisseurs de se retirer.","tr":"Bir özel şirketin hisselerini ilk kez bir borsada kamuya sattığı süreç; sermaye toplar ve erken yatırımcıların çıkış yapmasına olanak tanır.","nl":"Het proces waarbij een privébedrijf voor het eerst zijn aandelen op een beurs aan het publiek verkoopt; het haalt kapitaal op en stelt vroege investeerders in staat te vertrekken.","ru":"Процесс, при котором частная компания впервые выпускает акции для публичной продажи на фондовой бирже; привлекает капитал и позволяет ранним инвесторам выйти из бизнеса.","zh":"私营公司首次在证券交易所向公众出售股票的过程；它筹集资本并允许早期投资者退出。","pt_BR":"O processo pelo qual uma empresa privada vende suas ações ao público pela primeira vez em uma bolsa de valores; levanta capital e permite que os primeiros investidores saiam.","pt_PT":"O processo pelo qual uma empresa privada vende as suas ações ao público pela primeira vez numa bolsa de valores; levanta capital e permite que os primeiros investidores saiam."}},
  { id: 'dc-business-0035', deck_id: 'deck-business', front: 'Venture Capital (VC)', back: 'Private equity financing provided to startups and early-stage companies with high growth potential in exchange for equity ownership.', sort_order: 35 , front_translations: {"es":"Capital de Risco (Venture Capital)","de":"Risikokapital (Venture Capital)","fr":"Capital-risque (Venture Capital)","tr":"Risk Sermayesi (Venture Capital)","nl":"Durfkapitaal (Venture Capital)","ru":"Венчурный капитал (VC)","zh":"风险投资（VC）","pt_BR":"Capital de Risco (Venture Capital)","pt_PT":"Capital de Risco (Venture Capital)"}, back_translations: {"es":"Financiamento de private equity fornecido a startups y empresas en etapa inicial con alto potencial de crecimiento en troca de participación acionária.","de":"Private-Equity-Finanzierung für Startups und Frühphasenunternehmen mit hohem Wachstumspotenzial im Austausch für eine Kapitalbeteiligung.","fr":"Financement en capital-investissement accordé à des startups et des entreprises en phase de démarrage à fort potentiel de croissance en échange d'une participation au capital.","tr":"Yüksek büyüme potansiyeline sahip girişimlere ve erken aşama şirketlere özkaynak karşılığında sağlanan özel sermaye finansmanı.","nl":"Particuliere vermogensfinanciering voor startups en vroegstadiumondernemingen met een hoog groeipotentieel in ruil voor een aandelenbelang.","ru":"Финансирование в форме прямых инвестиций, предоставляемое стартапам и компаниям на ранних стадиях с высоким потенциалом роста в обмен на долю в капитале.","zh":"向具有高增长潜力的初创企业和早期公司提供的私募股权融资，以换取股权所有权。","pt_BR":"Financiamento de private equity fornecido a startups e empresas em estágio inicial com alto potencial de crescimento em troca de participação acionária.","pt_PT":"Financiamento de private equity fornecido a startups e empresas em fase inicial com elevado potencial de crescimento em troca de participação no capital."}},
  { id: 'dc-business-0036', deck_id: 'deck-business', front: 'Angel Investor', back: 'A high-net-worth individual who provides capital to early-stage startups, typically in exchange for equity or convertible debt, often before VC funding is sought.', sort_order: 36 , front_translations: {"es":"Investidor Anjo","de":"Business Angel","fr":"Investisseur providentiel (Business Angel)","tr":"Melek Yatırımcı","nl":"Business angel","ru":"Бизнес-ангел","zh":"天使投资人","pt_BR":"Investidor Anjo","pt_PT":"Investidor Anjo"}, back_translations: {"es":"Un indivíduo de alto patrimonio líquido que proporciona capital a startups en etapa inicial, normalmente en troca de participación acionária o dívida conversible, frecuentemente antes de buscar financiamento de VC.","de":"Eine vermögende Einzelperson, die Kapital für Frühphasen-Startups bereitstellt, typischerweise im Austausch für Eigenkapital oder Wandelschulden, oft bevor eine Risikokapitalfinanzierung angestrebt wird.","fr":"Un particulier fortuné qui apporte des capitaux à des startups en phase de démarrage, généralement en échange de fonds propres ou de dettes convertibles, souvent avant de solliciter un financement par capital-risque.","tr":"Genellikle risk sermayesi finansmanı aranmadan önce, özkaynak veya dönüştürülebilir borç karşılığında erken aşama girişimlere sermaye sağlayan yüksek net değere sahip bir bireydir.","nl":"Een vermogende particulier die kapitaal verstrekt aan startups in een vroeg stadium, doorgaans in ruil voor aandelen of converteerbare schuld, vaak voordat VC-financiering wordt gezocht.","ru":"Состоятельный частный инвестор, предоставляющий капитал стартапам на ранних стадиях, как правило, в обмен на долю в капитале или конвертируемый долг, зачастую до привлечения венчурного финансирования.","zh":"向早期初创企业提供资金的高净值个人，通常以股权或可转换债务为回报，往往在寻求风险投资之前介入。","pt_BR":"Um indivíduo de alto patrimônio líquido que fornece capital a startups em estágio inicial, normalmente em troca de participação acionária ou dívida conversível, frequentemente antes de buscar financiamento de VC.","pt_PT":"Um indivíduo de elevado património líquido que fornece capital a startups em fase inicial, normalmente em troca de capital próprio ou dívida convertível, muitas vezes antes de se procurar financiamento de VC."}},
  { id: 'dc-business-0037', deck_id: 'deck-business', front: 'Bootstrapping', back: 'Building and growing a business using personal savings and revenue from the business itself, without external funding; it retains full equity but limits growth speed.', sort_order: 37 , front_translations: {"es":"Bootstrapping","de":"Bootstrapping","fr":"Autofinancement (Bootstrapping)","tr":"Öz Kaynaklarla Büyüme (Bootstrapping)","nl":"Bootstrapping","ru":"Бутстрэппинг","zh":"自力更生创业（Bootstrapping）","pt_BR":"Bootstrapping","pt_PT":"Bootstrapping"}, back_translations: {"es":"Construir y desenvolver un negocio usando poupanças pessoais y ingresos del propio negocio, sin financiamento externo; mantiene el capital integral, pero limita a velocidad de crecimiento.","de":"Aufbau und Wachstum eines Unternehmens mithilfe von Eigenersparnissen und Umsätzen des Unternehmens selbst, ohne externe Finanzierung; es erhält das volle Eigenkapital, begrenzt aber die Wachstumsgeschwindigkeit.","fr":"Créer et développer une entreprise en utilisant ses économies personnelles et les revenus générés par l'entreprise elle-même, sans financement externe ; cela préserve la pleine propriété mais limite la vitesse de croissance.","tr":"İşletmeyi dış finansman kullanmadan kişisel tasarruflar ve işletmenin kendi gelirleriyle kurma ve büyütme; tam özkaynak elde tutulur ancak büyüme hızı sınırlanır.","nl":"Een bedrijf opbouwen en laten groeien met persoonlijke spaargelden en inkomsten uit het bedrijf zelf, zonder externe financiering; het behoudt het volledige eigen vermogen maar beperkt de groeisnelheid.","ru":"Построение и развитие бизнеса за счёт личных сбережений и выручки самой компании без привлечения внешнего финансирования; сохраняет полный контроль над капиталом, но ограничивает темпы роста.","zh":"利用个人储蓄和企业自身收入来建立和发展业务，无需外部融资；保留完整股权，但限制了增长速度。","pt_BR":"Construir e desenvolver um negócio usando poupanças pessoais e receitas do próprio negócio, sem financiamento externo; mantém o capital integral, mas limita a velocidade de crescimento.","pt_PT":"Construir e desenvolver um negócio usando poupanças pessoais e receitas do próprio negócio, sem financiamento externo; retém o capital integral, mas limita a velocidade de crescimento."}},
  { id: 'dc-business-0038', deck_id: 'deck-business', front: 'Burn Rate', back: 'The rate at which a company spends its cash reserves before generating positive cash flow. Monthly burn rate indicates how many months of runway a startup has.', sort_order: 38 , front_translations: {"es":"Taxa de Queima de Caixa (Burn Rate)","de":"Burn Rate","fr":"Taux de consommation de trésorerie (Burn Rate)","tr":"Nakit Tüketim Hızı (Burn Rate)","nl":"Verbrandingssnelheid (Burn Rate)","ru":"Скорость сжигания капитала (Burn Rate)","zh":"资金消耗速率","pt_BR":"Taxa de Queima de Caixa (Burn Rate)","pt_PT":"Taxa de Consumo de Caixa (Burn Rate)"}, back_translations: {"es":"La taxa en la qual una empresa gasta sus reservas de caixa antes de gerar flujo de caja positivo. La taxa de queima mensal indica quantos meses de pista una startup aún tiene.","de":"Die Rate, mit der ein Unternehmen seine Barreserven ausgibt, bevor es einen positiven Cashflow generiert. Die monatliche Burn Rate gibt an, wie viele Monate ein Startup noch hat.","fr":"Le rythme auquel une entreprise dépense ses réserves de trésorerie avant de générer un flux de trésorerie positif. Le taux mensuel indique combien de mois de fonds un startup possède encore.","tr":"Bir şirketin pozitif nakit akışı elde etmeden önce nakit rezervlerini harcama hızı. Aylık nakit tüketim hızı, bir girişimin kaç aylık fonunun kaldığını gösterir.","nl":"De snelheid waarmee een bedrijf zijn cashreserves uitgeeft voordat het een positieve kasstroom genereert. De maandelijkse burn rate geeft aan hoeveel maanden een startup nog heeft.","ru":"Скорость расходования компанией своих денежных резервов до достижения положительного денежного потока. Ежемесячная burn rate показывает, на сколько месяцев хватит средств стартапа.","zh":"公司在产生正现金流之前消耗现金储备的速度。月度资金消耗速率表明初创公司还有多少个月的资金储备。","pt_BR":"A taxa na qual uma empresa gasta suas reservas de caixa antes de gerar fluxo de caixa positivo. A taxa de queima mensal indica quantos meses de pista uma startup ainda tem.","pt_PT":"A taxa à qual uma empresa gasta as suas reservas de caixa antes de gerar fluxo de caixa positivo. A taxa de consumo mensal indica quantos meses de pista uma startup ainda tem."}},
  { id: 'dc-business-0039', deck_id: 'deck-business', front: 'Runway', back: 'The amount of time a startup can operate before running out of money, calculated as Cash Reserves / Monthly Burn Rate. Typically expressed in months.', sort_order: 39 , front_translations: {"es":"Pista Financera (Runway)","de":"Runway (Kapitalreichweite)","fr":"Piste de décollage financière (Runway)","tr":"Finansal Pist (Runway)","nl":"Financiële startbaan (Runway)","ru":"Финансовый запас (Runway)","zh":"资金跑道","pt_BR":"Pista Financeira (Runway)","pt_PT":"Pista Financeira (Runway)"}, back_translations: {"es":"El tiempo que una startup puede operar antes de ficar sin dinhero, calculado como Reservas de Caixa / Taxa de Queima Mensal. Normalmente expresso en meses.","de":"Die Zeitspanne, die einem Startup verbleibt, bevor ihm das Geld ausgeht, berechnet als Barreserven / Monatliche Burn Rate. Wird typischerweise in Monaten angegeben.","fr":"La durée pendant laquelle une startup peut fonctionner avant de manquer d'argent, calculée comme Réserves de trésorerie / Taux de consommation mensuel. Généralement exprimée en mois.","tr":"Bir girişimin parası bitmeden önce faaliyet gösterebileceği süre; Nakit Rezervleri / Aylık Nakit Tüketim Hızı olarak hesaplanır. Genellikle ay cinsinden ifade edilir.","nl":"De hoeveelheid tijd die een startup heeft voordat het geld op is, berekend als Cashreserves / Maandelijkse Burn Rate. Doorgaans uitgedrukt in maanden.","ru":"Количество времени, в течение которого стартап может работать до исчерпания средств, рассчитывается как Денежные резервы / Ежемесячная burn rate. Обычно выражается в месяцах.","zh":"初创公司在资金耗尽之前能够运营的时间，计算公式为现金储备/月度消耗速率。通常以月为单位表示。","pt_BR":"O tempo que uma startup pode operar antes de ficar sem dinheiro, calculado como Reservas de Caixa / Taxa de Queima Mensal. Normalmente expresso em meses.","pt_PT":"O tempo que uma startup pode operar antes de ficar sem dinheiro, calculado como Reservas de Caixa / Taxa de Consumo Mensal. Normalmente expresso em meses."}},
  { id: 'dc-business-0040', deck_id: 'deck-business', front: 'Valuation', back: 'The process of determining the present worth of a company or asset; methods include Discounted Cash Flow (DCF), comparable company analysis, and precedent transactions.', sort_order: 40 , front_translations: {"es":"Avaliación (Valuation)","de":"Unternehmensbewertung","fr":"Valorisation d'entreprise","tr":"Değerleme","nl":"Waardering","ru":"Оценка стоимости компании","zh":"估值","pt_BR":"Avaliação (Valuation)","pt_PT":"Avaliação (Valuation)"}, back_translations: {"es":"El proceso de determinar el valor presente de una empresa o ativo; los métodos incluyen Fluxo de Caixa Descontado (DCF), análise de empresas comparables y transaciones precedentes.","de":"Der Prozess der Bestimmung des gegenwärtigen Wertes eines Unternehmens oder Vermögenswerts; Methoden umfassen Discounted Cash Flow (DCF), Vergleichsunternehmensanalyse und Präzedenztransaktionen.","fr":"Le processus de détermination de la valeur actuelle d'une entreprise ou d'un actif ; les méthodes comprennent les flux de trésorerie actualisés (DCF), l'analyse de sociétés comparables et les transactions précédentes.","tr":"Bir şirketin veya varlığın mevcut değerini belirleme süreci; yöntemler arasında İndirgenmiş Nakit Akışı (DCF), karşılaştırılabilir şirket analizi ve emsal işlemler yer alır.","nl":"Het proces van het bepalen van de huidige waarde van een bedrijf of actief; methoden omvatten Discounted Cash Flow (DCF), vergelijkbare bedrijfsanalyse en precedenttransacties.","ru":"Процесс определения текущей стоимости компании или актива; методы включают дисконтирование денежных потоков (DCF), анализ сопоставимых компаний и сравнение с прецедентными сделками.","zh":"确定公司或资产当前价值的过程；方法包括折现现金流（DCF）、可比公司分析和先例交易分析。","pt_BR":"O processo de determinar o valor presente de uma empresa ou ativo; os métodos incluem Fluxo de Caixa Descontado (DCF), análise de empresas comparáveis e transações precedentes.","pt_PT":"O processo de determinação do valor presente de uma empresa ou ativo; os métodos incluem Fluxo de Caixa Descontado (DCF), análise de empresas comparáveis e transações precedentes."}},
  { id: 'dc-business-0041', deck_id: 'deck-business', front: 'Pre-Money vs. Post-Money Valuation', back: 'Pre-money valuation is the company\'s value before an investment; post-money valuation is the pre-money value plus the new investment amount. Used to calculate investor equity stake.', sort_order: 41 , front_translations: {"es":"Avaliación Pré-Investimento vs. Pós-Investimento","de":"Pre-Money vs. Post-Money Bewertung","fr":"Valorisation pré-money vs. post-money","tr":"Yatırım Öncesi ve Yatırım Sonrası Değerleme","nl":"Pre-money vs. post-money waardering","ru":"Оценка до и после инвестиций (Pre-Money vs. Post-Money)","zh":"投前估值与投后估值","pt_BR":"Avaliação Pré-Investimento vs. Pós-Investimento","pt_PT":"Avaliação Pré-Investimento vs. Pós-Investimento"}, back_translations: {"es":"La avaliación pré-inversión es el valor de la empresa antes de un aporte; a avaliación pós-inversión es el valor pré-inversión más el nuevo valor aportado. Usada para calcular a participación acionária del investidor.","de":"Die Pre-Money-Bewertung ist der Unternehmenswert vor einer Investition; die Post-Money-Bewertung ist der Pre-Money-Wert zuzüglich des neuen Investitionsbetrags. Wird verwendet, um den Eigenkapitalanteil des Investors zu berechnen.","fr":"La valorisation pré-money est la valeur de l'entreprise avant un investissement ; la valorisation post-money est la valeur pré-money plus le montant du nouvel investissement. Utilisées pour calculer la participation des investisseurs.","tr":"Yatırım öncesi değerleme, yatırımdan önce şirketin değeridir; yatırım sonrası değerleme ise yatırım öncesi değere yeni yatırım tutarının eklenmesiyle elde edilir. Yatırımcının özkaynak payını hesaplamak için kullanılır.","nl":"Pre-money waardering is de waarde van het bedrijf vóór een investering; post-money waardering is de pre-money waarde plus het nieuwe investeringsbedrag. Gebruikt om het aandelenbelang van de investeerder te berekenen.","ru":"Оценка до инвестиций — это стоимость компании до получения вложений; оценка после инвестиций — стоимость до инвестиций плюс сумма нового вложения. Используется для расчёта доли инвестора в капитале.","zh":"投前估值是投资前公司的价值；投后估值是投前估值加上新增投资金额。用于计算投资者的股权比例。","pt_BR":"A avaliação pré-investimento é o valor da empresa antes de um aporte; a avaliação pós-investimento é o valor pré-investimento mais o novo valor aportado. Usada para calcular a participação acionária do investidor.","pt_PT":"A avaliação pré-investimento é o valor da empresa antes de um investimento; a avaliação pós-investimento é o valor pré-investimento acrescido do novo montante investido. Utilizada para calcular a participação acionária do investidor."}},
  { id: 'dc-business-0042', deck_id: 'deck-business', front: 'Cap Table (Capitalization Table)', back: 'A spreadsheet showing all shareholders of a company, their equity ownership percentages, dilution, and value of their equity; critical for startups managing investor relations.', sort_order: 42 , front_translations: {"es":"Tabela de Capitalización (Cap Table)","de":"Cap Table (Kapitalisierungstabelle)","fr":"Tableau de capitalisation (Cap Table)","tr":"Sermaye Tablosu (Cap Table)","nl":"Kapitalisatietabel (Cap Table)","ru":"Таблица капитализации (Cap Table)","zh":"股权结构表（Cap Table）","pt_BR":"Tabela de Capitalização (Cap Table)","pt_PT":"Tabela de Capitalização (Cap Table)"}, back_translations: {"es":"Una planilha mostrando todos los accionistas de una empresa, sus percentuais de participación acionária, diluición y valor del patrimonio; esencial para startups que gerenciam relaciones con investidores.","de":"Eine Tabelle, die alle Aktionäre eines Unternehmens mit ihren Eigenkapitalbeteiligungen, Verwässerungen und dem Wert ihrer Anteile zeigt; entscheidend für Startups bei der Verwaltung von Investorenbeziehungen.","fr":"Un tableau répertoriant tous les actionnaires d'une entreprise, leurs pourcentages de participation, la dilution et la valeur de leurs parts ; essentiel pour les startups gérant les relations avec les investisseurs.","tr":"Bir şirketin tüm hissedarlarını, özkaynak sahiplik yüzdelerini, seyreltmeyi ve özkaynak değerlerini gösteren tablo; yatırımcı ilişkilerini yöneten girişimler için kritik öneme sahiptir.","nl":"Een spreadsheet met alle aandeelhouders van een bedrijf, hun eigendomspercentages, verwatering en de waarde van hun aandelen; cruciaal voor startups die investeerdersrelaties beheren.","ru":"Таблица, отображающая всех акционеров компании, их доли в капитале, степень размытия и стоимость их долей; критически важна для стартапов, управляющих отношениями с инвесторами.","zh":"显示公司所有股东、其股权所有权百分比、稀释情况及股权价值的表格；对于管理投资者关系的初创公司至关重要。","pt_BR":"Uma planilha mostrando todos os acionistas de uma empresa, seus percentuais de participação acionária, diluição e valor do patrimônio; essencial para startups que gerenciam relações com investidores.","pt_PT":"Uma folha de cálculo que mostra todos os acionistas de uma empresa, as suas percentagens de participação, diluição e valor do capital próprio; essencial para startups que gerem relações com investidores."}},
  { id: 'dc-business-0043', deck_id: 'deck-business', front: 'SWOT Analysis', back: 'A strategic planning framework analyzing Strengths, Weaknesses, Opportunities, and Threats. It helps organizations identify internal advantages and external challenges.', sort_order: 43 , front_translations: {"es":"Análise SWOT","de":"SWOT-Analyse","fr":"Analyse SWOT","tr":"SWOT Analizi","nl":"SWOT-analyse","ru":"SWOT-анализ","zh":"SWOT分析","pt_BR":"Análise SWOT","pt_PT":"Análise SWOT"}, back_translations: {"es":"Una estructura de planejamento estratégico que analisa Forças, Fraquezas, Oportunidades y Ameaças. Ajuda las organizaciones a identificar vantajes internas y desafios externos.","de":"Ein strategisches Planungsrahmenwerk zur Analyse von Stärken, Schwächen, Chancen und Risiken. Es hilft Organisationen, interne Vorteile und externe Herausforderungen zu identifizieren.","fr":"Un cadre de planification stratégique analysant les Forces, Faiblesses, Opportunités et Menaces. Il aide les organisations à identifier les avantages internes et les défis externes.","tr":"Güçlü yönleri, Zayıf yönleri, Fırsatları ve Tehditleri analiz eden stratejik planlama çerçevesi. Organizasyonların iç avantajlarını ve dış zorluklarını belirlemelerine yardımcı olur.","nl":"Een strategisch planningskader dat Sterktes, Zwaktes, Kansen en Bedreigingen analyseert. Het helpt organisaties interne voordelen en externe uitdagingen te identificeren.","ru":"Стратегическая аналитическая модель, оценивающая Сильные стороны, Слабые стороны, Возможности и Угрозы. Помогает организациям выявлять внутренние преимущества и внешние вызовы.","zh":"一种分析优势（Strengths）、劣势（Weaknesses）、机会（Opportunities）和威胁（Threats）的战略规划框架，帮助组织识别内部优势和外部挑战。","pt_BR":"Uma estrutura de planejamento estratégico que analisa Forças, Fraquezas, Oportunidades e Ameaças. Ajuda as organizações a identificar vantagens internas e desafios externos.","pt_PT":"Uma estrutura de planeamento estratégico que analisa Forças, Fraquezas, Oportunidades e Ameaças. Ajuda as organizações a identificar vantagens internas e desafios externos."}},
  { id: 'dc-business-0044', deck_id: 'deck-business', front: 'OKR (Objectives and Key Results)', back: 'A goal-setting framework where high-level Objectives are supported by measurable Key Results. Popularized by Intel and Google to align teams toward ambitious goals.', sort_order: 44 , front_translations: {"es":"OKR (Objetivos y Resultados-Chave)","de":"OKR (Ziele und Schlüsselergebnisse)","fr":"OKR (Objectifs et Résultats Clés)","tr":"OKR (Hedefler ve Temel Sonuçlar)","nl":"OKR (Doelstellingen en Kernresultaten)","ru":"OKR (цели и ключевые результаты)","zh":"OKR（目标与关键成果）","pt_BR":"OKR (Objetivos e Resultados-Chave)","pt_PT":"OKR (Objetivos e Resultados-Chave)"}, back_translations: {"es":"Una metodologia de definición de metas donde Objetivos de alto nivel son apoiados por Resultados-Chave mensurables. Popularizada por la Intel y Google para alinhar equipes alrededor de metas ambiciosas.","de":"Ein Zielsetzungsrahmen, bei dem übergeordnete Ziele durch messbare Schlüsselergebnisse unterstützt werden. Popularisiert von Intel und Google, um Teams auf ehrgeizige Ziele auszurichten.","fr":"Un cadre de définition d'objectifs où des Objectifs de haut niveau sont soutenus par des Résultats Clés mesurables. Popularisé par Intel et Google pour aligner les équipes sur des objectifs ambitieux.","tr":"Üst düzey Hedeflerin ölçülebilir Temel Sonuçlarla desteklendiği bir hedef belirleme çerçevesi. Intel ve Google tarafından ekipleri hırslı hedeflere yönlendirmek amacıyla popülerleştirilmiştir.","nl":"Een doelstellingskader waarbij overkoepelende Doelstellingen worden ondersteund door meetbare Kernresultaten. Gepopulariseerd door Intel en Google om teams op ambitieuze doelen te richten.","ru":"Методология постановки целей, в которой высокоуровневые Цели подкрепляются измеримыми Ключевыми результатами. Популяризирована компаниями Intel и Google для выравнивания команд вокруг амбициозных задач.","zh":"一种目标设定框架，高层目标由可量化的关键成果支撑。由英特尔和谷歌推广，用于使团队朝向宏大目标协同努力。","pt_BR":"Uma metodologia de definição de metas onde Objetivos de alto nível são apoiados por Resultados-Chave mensuráveis. Popularizada pela Intel e Google para alinhar equipes em torno de metas ambiciosas.","pt_PT":"Uma metodologia de definição de metas onde Objetivos de alto nível são apoiados por Resultados-Chave mensuráveis. Popularizada pela Intel e Google para alinhar equipas em torno de objetivos ambiciosos."}},
  { id: 'dc-business-0045', deck_id: 'deck-business', front: 'KPI (Key Performance Indicator)', back: 'A measurable value that demonstrates how effectively a company is achieving key business objectives. Examples include monthly revenue, customer acquisition cost, and churn rate.', sort_order: 45 , front_translations: {"es":"KPI (Indicador-Chave de Desempenho)","de":"KPI (Key Performance Indicator)","fr":"KPI (Indicateur Clé de Performance)","tr":"KPI (Temel Performans Göstergesi)","nl":"KPI (Kritieke Prestatie-Indicator)","ru":"KPI (ключевой показатель эффективности)","zh":"KPI（关键绩效指标）","pt_BR":"KPI (Indicador-Chave de Desempenho)","pt_PT":"KPI (Indicador-Chave de Desempenho)"}, back_translations: {"es":"Un valor mensurable que demonstra con que eficácia una empresa está atingindo sus principales objetivos de negocio. Exemplos incluyen ingreso mensal, costo de adquisición de clientes y taxa de churn.","de":"Ein messbarer Wert, der zeigt, wie effektiv ein Unternehmen seine wichtigsten Geschäftsziele erreicht. Beispiele sind monatliche Umsätze, Kundenakquisitionskosten und Abwanderungsrate.","fr":"Une valeur mesurable démontrant l'efficacité avec laquelle une entreprise atteint ses principaux objectifs. Les exemples incluent le chiffre d'affaires mensuel, le coût d'acquisition client et le taux de désabonnement.","tr":"Bir şirketin temel iş hedeflerini ne kadar etkin biçimde gerçekleştirdiğini gösteren ölçülebilir değer. Örnekler arasında aylık gelir, müşteri edinme maliyeti ve kayıp oranı yer alır.","nl":"Een meetbare waarde die aantoont hoe effectief een bedrijf zijn belangrijkste zakelijke doelstellingen bereikt. Voorbeelden zijn maandelijkse omzet, klantwervingskosten en churnpercentage.","ru":"Измеримый показатель, демонстрирующий эффективность достижения компанией ключевых бизнес-целей. Примеры: ежемесячный доход, стоимость привлечения клиента и показатель оттока.","zh":"衡量公司实现关键业务目标效率的可量化指标。示例包括月收入、客户获取成本和客户流失率。","pt_BR":"Um valor mensurável que demonstra com que eficácia uma empresa está atingindo seus principais objetivos de negócio. Exemplos incluem receita mensal, custo de aquisição de clientes e taxa de churn.","pt_PT":"Um valor mensurável que demonstra a eficácia com que uma empresa está a atingir os seus principais objetivos de negócio. Exemplos incluem receita mensal, custo de aquisição de clientes e taxa de churn."}},
  { id: 'dc-business-0046', deck_id: 'deck-business', front: 'Customer Acquisition Cost (CAC)', back: 'The total cost of acquiring a new customer, including marketing and sales expenses, divided by the number of new customers gained. A key metric for evaluating marketing efficiency.', sort_order: 46 , front_translations: {"es":"Custo de Aquisición de Clientes (CAC)","de":"Kundenakquisitionskosten (CAC)","fr":"Coût d'acquisition client (CAC)","tr":"Müşteri Edinme Maliyeti (CAC)","nl":"Klantenwervingskosten (CAC)","ru":"Стоимость привлечения клиента (CAC)","zh":"客户获取成本（CAC）","pt_BR":"Custo de Aquisição de Clientes (CAC)","pt_PT":"Custo de Aquisição de Clientes (CAC)"}, back_translations: {"es":"El costo total de adquisición de un nuevo cliente, incluyendo gastos de marketing y ventas, dividido por el número de nuevos clientes obtidos. Una métrica esencial para avaliar a eficiencia de marketing.","de":"Die Gesamtkosten für die Gewinnung eines neuen Kunden, einschließlich Marketing- und Vertriebskosten, geteilt durch die Anzahl der neu gewonnenen Kunden. Eine Schlüsselkennzahl zur Bewertung der Marketingeffizienz.","fr":"Le coût total d'acquisition d'un nouveau client, incluant les dépenses marketing et commerciales, divisé par le nombre de nouveaux clients acquis. Un indicateur clé pour évaluer l'efficacité marketing.","tr":"Pazarlama ve satış giderleri dahil olmak üzere yeni bir müşteri edinmenin toplam maliyetinin kazanılan yeni müşteri sayısına bölünmesiyle hesaplanır. Pazarlama verimliliğini değerlendirmek için temel bir metriktir.","nl":"De totale kosten van het werven van een nieuwe klant, inclusief marketing- en verkoopkosten, gedeeld door het aantal nieuw gewonnen klanten. Een cruciale maatstaf voor het evalueren van marketingefficiëntie.","ru":"Общие затраты на привлечение одного нового клиента, включая расходы на маркетинг и продажи, делённые на количество привлечённых новых клиентов. Ключевая метрика для оценки эффективности маркетинга.","zh":"获取一个新客户的总成本，包括营销和销售费用，除以新增客户数量。是评估营销效率的关键指标。","pt_BR":"O custo total de aquisição de um novo cliente, incluindo despesas de marketing e vendas, dividido pelo número de novos clientes obtidos. Uma métrica essencial para avaliar a eficiência de marketing.","pt_PT":"O custo total de aquisição de um novo cliente, incluindo despesas de marketing e vendas, dividido pelo número de novos clientes obtidos. Uma métrica essencial para avaliar a eficiência de marketing."}},
  { id: 'dc-business-0047', deck_id: 'deck-business', front: 'Customer Lifetime Value (LTV or CLV)', back: 'The total revenue a business can expect from a single customer over the entire duration of their relationship. LTV should ideally exceed CAC by a ratio of 3:1 or more.', sort_order: 47 , front_translations: {"es":"Valor del Tempo de Vida del Cliente (LTV o CLV)","de":"Customer Lifetime Value (LTV oder CLV)","fr":"Valeur vie client (LTV ou CLV)","tr":"Müşteri Yaşam Boyu Değeri (LTV veya CLV)","nl":"Levenslange klantwaarde (LTV of CLV)","ru":"Пожизненная ценность клиента (LTV или CLV)","zh":"客户终身价值（LTV或CLV）","pt_BR":"Valor do Tempo de Vida do Cliente (LTV ou CLV)","pt_PT":"Valor do Tempo de Vida do Cliente (LTV ou CLV)"}, back_translations: {"es":"La ingreso total que una empresa puede esperar de un único cliente a lo ancho de toda a duración del relacionamento. El LTV deve idealmente superar el CAC en una proporción de 3:1 o más.","de":"Der gesamte Umsatz, den ein Unternehmen von einem einzelnen Kunden über die gesamte Dauer seiner Beziehung erwarten kann. Der LTV sollte den CAC idealerweise um ein Verhältnis von 3:1 oder mehr übersteigen.","fr":"Le total des revenus qu'une entreprise peut espérer tirer d'un seul client tout au long de leur relation. La LTV devrait idéalement dépasser le CAC dans un rapport de 3:1 ou plus.","tr":"Bir işletmenin tek bir müşteriden ilişkilerinin tüm süresi boyunca elde etmeyi bekleyebileceği toplam gelir. LTV, ideal olarak CAC'yi 3:1 veya daha fazla oranında aşmalıdır.","nl":"De totale omzet die een bedrijf kan verwachten van een enkele klant gedurende de gehele duur van hun relatie. LTV moet idealiter CAC overtreffen met een verhouding van 3:1 of meer.","ru":"Общий доход, который бизнес может ожидать от одного клиента за всё время их взаимодействия. В идеале LTV должна превышать CAC в соотношении 3:1 или выше.","zh":"企业在整个客户关系期间可以从单个客户身上获得的总收入。LTV理想情况下应以3:1或更高的比率超过CAC。","pt_BR":"A receita total que uma empresa pode esperar de um único cliente ao longo de toda a duração do relacionamento. O LTV deve idealmente superar o CAC em uma proporção de 3:1 ou mais.","pt_PT":"A receita total que uma empresa pode esperar de um único cliente ao longo de toda a duração do relacionamento. O LTV deve idealmente superar o CAC numa proporção de 3:1 ou mais."}},
  { id: 'dc-business-0048', deck_id: 'deck-business', front: 'Churn Rate', back: 'The percentage of customers who stop using a product or service in a given period. High churn is a warning sign that a business is losing customers faster than it acquires them.', sort_order: 48 , front_translations: {"es":"Taxa de Churn","de":"Abwanderungsrate (Churn Rate)","fr":"Taux de désabonnement (Churn Rate)","tr":"Müşteri Kayıp Oranı (Churn Rate)","nl":"Verlooppercentage (Churn Rate)","ru":"Коэффициент оттока клиентов (Churn Rate)","zh":"客户流失率","pt_BR":"Taxa de Churn","pt_PT":"Taxa de Churn"}, back_translations: {"es":"El percentual de clientes que param de usar un producto o serviço en un determinado período. Alta taxa de churn es un señal de alerta de que una empresa está perdendo clientes más rápido del que los adquire.","de":"Der Prozentsatz der Kunden, die in einem bestimmten Zeitraum aufgehört haben, ein Produkt oder eine Dienstleistung zu nutzen. Eine hohe Abwanderungsrate ist ein Warnsignal, dass ein Unternehmen Kunden schneller verliert, als es neue gewinnt.","fr":"Le pourcentage de clients qui cessent d'utiliser un produit ou service au cours d'une période donnée. Un taux de désabonnement élevé est un signal d'alarme indiquant qu'une entreprise perd des clients plus vite qu'elle n'en acquiert.","tr":"Belirli bir dönemde bir ürün veya hizmeti kullanmayı bırakan müşterilerin yüzdesi. Yüksek kayıp oranı, bir işletmenin kazandığından daha hızlı müşteri kaybettiğine dair uyarı işaretidir.","nl":"Het percentage klanten dat in een bepaalde periode stopt met het gebruik van een product of dienst. Een hoog verlooppercentage is een waarschuwingsteken dat een bedrijf klanten sneller verliest dan het er wint.","ru":"Процент клиентов, прекративших пользоваться продуктом или услугой за определённый период. Высокий показатель оттока — тревожный сигнал того, что бизнес теряет клиентов быстрее, чем привлекает новых.","zh":"在特定时间段内停止使用产品或服务的客户百分比。高流失率是一个警示信号，表明企业失去客户的速度快于获取新客户的速度。","pt_BR":"O percentual de clientes que param de usar um produto ou serviço em um determinado período. Alta taxa de churn é um sinal de alerta de que uma empresa está perdendo clientes mais rápido do que os adquire.","pt_PT":"A percentagem de clientes que deixam de usar um produto ou serviço num determinado período. Uma taxa de churn elevada é um sinal de alerta de que uma empresa está a perder clientes mais rapidamente do que os adquire."}},
  { id: 'dc-business-0049', deck_id: 'deck-business', front: 'Monthly Recurring Revenue (MRR)', back: 'The predictable, recurring revenue a subscription business earns each month. A key metric for SaaS companies indicating business health and growth.', sort_order: 49 , front_translations: {"es":"Receita Recorrente Mensal (MRR)","de":"Monatlich wiederkehrende Einnahmen (MRR)","fr":"Revenu mensuel récurrent (MRR)","tr":"Aylık Yinelenen Gelir (MRR)","nl":"Maandelijks terugkerende omzet (MRR)","ru":"Ежемесячный регулярный доход (MRR)","zh":"月度经常性收入（MRR）","pt_BR":"Receita Recorrente Mensal (MRR)","pt_PT":"Receita Recorrente Mensal (MRR)"}, back_translations: {"es":"La ingreso recorrente previsible que un negocio por assinatura genera mensalmente. Una métrica esencial para empresas SaaS que indica a salud y el crecimiento del negocio.","de":"Der vorhersehbare, wiederkehrende Umsatz, den ein Abonnementunternehmen jeden Monat erzielt. Eine Schlüsselkennzahl für SaaS-Unternehmen, die die Unternehmensgesundheit und das Wachstum anzeigt.","fr":"Le revenu récurrent prévisible qu'une entreprise par abonnement génère chaque mois. Un indicateur clé pour les entreprises SaaS indiquant la santé et la croissance de l'entreprise.","tr":"Bir abonelik işletmesinin her ay kazandığı öngörülebilir, yinelenen gelir. SaaS şirketleri için iş sağlığını ve büyümesini gösteren temel bir metriktir.","nl":"De voorspelbare, terugkerende omzet die een abonnementsbedrijf elke maand verdient. Een sleutelmaatstaf voor SaaS-bedrijven die de bedrijfsgezondheid en groei aangeeft.","ru":"Предсказуемый регулярный доход, который подписочный бизнес получает каждый месяц. Ключевая метрика для SaaS-компаний, отражающая состояние бизнеса и его рост.","zh":"订阅业务每月获得的可预测的经常性收入。是SaaS公司衡量业务健康状况和增长的关键指标。","pt_BR":"A receita recorrente previsível que um negócio por assinatura gera mensalmente. Uma métrica essencial para empresas SaaS que indica a saúde e o crescimento do negócio.","pt_PT":"A receita recorrente previsível que um negócio por subscrição gera mensalmente. Uma métrica essencial para empresas SaaS que indica a saúde e o crescimento do negócio."}},
  { id: 'dc-business-0050', deck_id: 'deck-business', front: 'Annual Recurring Revenue (ARR)', back: 'MRR multiplied by 12; represents the annualized subscription revenue of a business. Used by investors to assess the scale and predictability of SaaS businesses.', sort_order: 50 , front_translations: {"es":"Receita Recorrente Anual (ARR)","de":"Jährlich wiederkehrende Einnahmen (ARR)","fr":"Revenu annuel récurrent (ARR)","tr":"Yıllık Yinelenen Gelir (ARR)","nl":"Jaarlijks terugkerende omzet (ARR)","ru":"Годовой регулярный доход (ARR)","zh":"年度经常性收入（ARR）","pt_BR":"Receita Recorrente Anual (ARR)","pt_PT":"Receita Recorrente Anual (ARR)"}, back_translations: {"es":"MRR multiplicado por 12; representa a ingreso de assinatura anualizada de un negocio. Usado por investidores para avaliar a escala y a previsibilidad de negocios SaaS.","de":"MRR multipliziert mit 12; stellt den annualisierten Abonnementumsatz eines Unternehmens dar. Wird von Investoren verwendet, um den Umfang und die Vorhersehbarkeit von SaaS-Geschäften zu bewerten.","fr":"Le MRR multiplié par 12 ; représente le chiffre d'affaires annualisé par abonnement d'une entreprise. Utilisé par les investisseurs pour évaluer la taille et la prévisibilité des activités SaaS.","tr":"MRR'nin 12 ile çarpımı; bir işletmenin yıllık abonelik gelirini temsil eder. Yatırımcılar tarafından SaaS işletmelerinin ölçeğini ve öngörülebilirliğini değerlendirmek için kullanılır.","nl":"MRR vermenigvuldigd met 12; vertegenwoordigt de geannualiseerde abonnementsomzet van een bedrijf. Gebruikt door investeerders om de omvang en voorspelbaarheid van SaaS-bedrijven te beoordelen.","ru":"MRR, умноженный на 12; представляет собой годовой объём подписочной выручки бизнеса. Используется инвесторами для оценки масштаба и предсказуемости SaaS-компаний.","zh":"MRR乘以12；代表企业的年化订阅收入。投资者用其评估SaaS业务的规模和可预测性。","pt_BR":"MRR multiplicado por 12; representa a receita de assinatura anualizada de um negócio. Usado por investidores para avaliar a escala e a previsibilidade de negócios SaaS.","pt_PT":"MRR multiplicado por 12; representa a receita de subscrição anualizada de um negócio. Usado por investidores para avaliar a escala e a previsibilidade de negócios SaaS."}},
  { id: 'dc-business-0051', deck_id: 'deck-business', front: 'Gross Domestic Product (GDP)', back: 'The total monetary value of all goods and services produced within a country in a specific time period. It is the primary measure of a national economy\'s size.', sort_order: 51 , front_translations: {"es":"Produto Interno Bruto (PIB)","de":"Bruttoinlandsprodukt (BIP)","fr":"Produit intérieur brut (PIB)","tr":"Gayri Safi Yurt İçi Hasıla (GSYİH)","nl":"Bruto binnenlands product (BBP)","ru":"Валовой внутренний продукт (ВВП)","zh":"国内生产总值（GDP）","pt_BR":"Produto Interno Bruto (PIB)","pt_PT":"Produto Interno Bruto (PIB)"}, back_translations: {"es":"El valor monetário total de todos los bens y serviços producidos dentro de un país en un período específico. É a principal medida del tamaño de una economía nacional.","de":"Der gesamte Geldwert aller Waren und Dienstleistungen, die innerhalb eines Landes in einem bestimmten Zeitraum produziert werden. Er ist das wichtigste Maß für die Größe einer Volkswirtschaft.","fr":"La valeur monétaire totale de tous les biens et services produits dans un pays sur une période donnée. C'est la principale mesure de la taille d'une économie nationale.","tr":"Belirli bir dönemde bir ülkede üretilen tüm mal ve hizmetlerin toplam parasal değeri. Ulusal ekonominin büyüklüğünün temel ölçütüdür.","nl":"De totale monetaire waarde van alle goederen en diensten die binnen een land in een bepaalde periode worden geproduceerd. Het is de primaire maatstaf voor de omvang van een nationale economie.","ru":"Совокупная денежная стоимость всех товаров и услуг, произведённых внутри страны за определённый период. Является основным показателем размера национальной экономики.","zh":"一个国家在特定时间段内生产的所有商品和服务的总货币价值。它是衡量国家经济规模的主要指标。","pt_BR":"O valor monetário total de todos os bens e serviços produzidos dentro de um país em um período específico. É a principal medida do tamanho de uma economia nacional.","pt_PT":"O valor monetário total de todos os bens e serviços produzidos num país num período específico. É a principal medida da dimensão de uma economia nacional."}},
  { id: 'dc-business-0052', deck_id: 'deck-business', front: 'Inflation', back: 'The rate at which the general level of prices for goods and services rises over time, reducing purchasing power. Measured by the Consumer Price Index (CPI).', sort_order: 52 , front_translations: {"es":"Inflación","de":"Inflation","fr":"Inflation","tr":"Enflasyon","nl":"Inflatie","ru":"Инфляция","zh":"通货膨胀","pt_BR":"Inflação","pt_PT":"Inflação"}, back_translations: {"es":"La taxa en la qual el nivel geral de precios de bens y serviços sobe a lo ancho del tiempo, reduciendo el poder de compra. Medida por el Índice de Preços al Consumidor (IPC).","de":"Die Rate, mit der das allgemeine Preisniveau für Waren und Dienstleistungen im Laufe der Zeit steigt und so die Kaufkraft vermindert. Gemessen am Verbraucherpreisindex (VPI).","fr":"Le taux auquel le niveau général des prix des biens et services augmente au fil du temps, réduisant le pouvoir d'achat. Mesuré par l'indice des prix à la consommation (IPC).","tr":"Mal ve hizmetlerin genel fiyat düzeyinin zaman içinde artarak satın alma gücünü düşürdüğü oran. Tüketici Fiyat Endeksi (TÜFE) ile ölçülür.","nl":"Het tempo waarmee het algemene prijsniveau van goederen en diensten in de loop van de tijd stijgt, waardoor de koopkracht afneemt. Gemeten aan de hand van de consumentenprijsindex (CPI).","ru":"Темп роста общего уровня цен на товары и услуги с течением времени, что снижает покупательную способность. Измеряется с помощью индекса потребительских цен (ИПЦ).","zh":"商品和服务的总体价格水平随时间上涨、从而降低购买力的速率。以消费者价格指数（CPI）衡量。","pt_BR":"A taxa na qual o nível geral de preços de bens e serviços sobe ao longo do tempo, reduzindo o poder de compra. Medida pelo Índice de Preços ao Consumidor (IPC).","pt_PT":"A taxa à qual o nível geral de preços de bens e serviços sobe ao longo do tempo, reduzindo o poder de compra. Medida pelo Índice de Preços no Consumidor (IPC)."}},
  { id: 'dc-business-0053', deck_id: 'deck-business', front: 'Consumer Price Index (CPI)', back: 'A measure of the average change over time in prices paid by consumers for a market basket of goods and services; the most commonly used indicator of inflation.', sort_order: 53 , front_translations: {"es":"Índice de Preços al Consumidor (IPC)","de":"Verbraucherpreisindex (VPI)","fr":"Indice des prix à la consommation (IPC)","tr":"Tüketici Fiyat Endeksi (TÜFE)","nl":"Consumentenprijsindex (CPI)","ru":"Индекс потребительских цен (ИПЦ)","zh":"消费者价格指数（CPI）","pt_BR":"Índice de Preços ao Consumidor (IPC)","pt_PT":"Índice de Preços no Consumidor (IPC)"}, back_translations: {"es":"Una medida de la variación média a lo ancho del tiempo en los precios pagos por los consumidores por una cesta de bens y serviços; el indicador de inflación más comúnmente usado.","de":"Ein Maß für die durchschnittliche Veränderung der von Verbrauchern gezahlten Preise für einen Warenkorb von Gütern und Dienstleistungen über die Zeit; der am häufigsten verwendete Inflationsindikator.","fr":"Une mesure de la variation moyenne des prix payés par les consommateurs pour un panier de biens et services au fil du temps ; l'indicateur d'inflation le plus couramment utilisé.","tr":"Tüketicilerin belirli bir mal ve hizmet sepeti için ödediği fiyatlardaki ortalama değişimi zaman içinde ölçen gösterge; en yaygın kullanılan enflasyon göstergesidir.","nl":"Een maatstaf voor de gemiddelde verandering in de loop van de tijd in de prijzen die consumenten betalen voor een mandje goederen en diensten; de meest gebruikte indicator voor inflatie.","ru":"Показатель среднего изменения цен, уплачиваемых потребителями за набор товаров и услуг, с течением времени; наиболее распространённый индикатор инфляции.","zh":"衡量消费者为一篮子商品和服务所支付价格随时间平均变化的指标；是最常用的通货膨胀指标。","pt_BR":"Uma medida da variação média ao longo do tempo nos preços pagos pelos consumidores por uma cesta de bens e serviços; o indicador de inflação mais comumente usado.","pt_PT":"Uma medida da variação média ao longo do tempo nos preços pagos pelos consumidores por um cabaz de bens e serviços; o indicador de inflação mais comummente utilizado."}},
  { id: 'dc-business-0054', deck_id: 'deck-business', front: 'Interest Rate', back: 'The cost of borrowing money, expressed as a percentage of the principal. Central banks set benchmark rates that influence borrowing costs throughout an economy.', sort_order: 54 , front_translations: {"es":"Taxa de Juros","de":"Zinssatz","fr":"Taux d'intérêt","tr":"Faiz Oranı","nl":"Rentevoet","ru":"Процентная ставка","zh":"利率","pt_BR":"Taxa de Juros","pt_PT":"Taxa de Juro"}, back_translations: {"es":"El costo de tomar dinhero emprestado, expresso como percentaje del principal. Los bases centrais definem taxas de referencia que influenciam los costos de crédito en toda a economía.","de":"Die Kosten der Geldleihe, ausgedrückt als Prozentsatz des Kapitals. Zentralbanken legen Leitzinsen fest, die die Kreditkosten in der gesamten Wirtschaft beeinflussen.","fr":"Le coût d'emprunt d'argent, exprimé en pourcentage du capital. Les banques centrales fixent des taux de référence qui influencent les coûts d'emprunt dans toute l'économie.","tr":"Borçlanma maliyetinin anaparaya göre yüzde olarak ifadesi. Merkez bankaları, ekonomi genelindeki borçlanma maliyetlerini etkileyen referans faiz oranlarını belirler.","nl":"De kosten van het lenen van geld, uitgedrukt als een percentage van het hoofdbedrag. Centrale banken stellen benchmarktarieven vast die de leenkosten in de gehele economie beïnvloeden.","ru":"Стоимость заимствования денег, выраженная в процентах от основной суммы. Центральные банки устанавливают базовые ставки, влияющие на стоимость кредитов во всей экономике.","zh":"借款成本，以本金的百分比表示。中央银行设定基准利率，影响整个经济体的借贷成本。","pt_BR":"O custo de tomar dinheiro emprestado, expresso como percentagem do principal. Os bancos centrais definem taxas de referência que influenciam os custos de crédito em toda a economia.","pt_PT":"O custo de contrair empréstimos, expresso em percentagem do capital. Os bancos centrais definem taxas de referência que influenciam os custos de crédito em toda a economia."}},
  { id: 'dc-business-0055', deck_id: 'deck-business', front: 'Supply and Demand', back: 'The fundamental economic model: as price increases, supply rises and demand falls; as price decreases, demand rises and supply falls. The market equilibrium is where both curves meet.', sort_order: 55 , front_translations: {"es":"Oferta y Demanda","de":"Angebot und Nachfrage","fr":"Offre et demande","tr":"Arz ve Talep","nl":"Vraag en aanbod","ru":"Спрос и предложение","zh":"供给与需求","pt_BR":"Oferta e Demanda","pt_PT":"Oferta e Procura"}, back_translations: {"es":"El modelo económico fundamental: a la medida que el precio sobe, a oferta aumenta y a demanda cai; a la medida que el precio cai, a demanda sobe y a oferta cai. El equilíbrio de mercado es donde las de los curvas se encontram.","de":"Das grundlegende wirtschaftliche Modell: Mit steigendem Preis steigt das Angebot und die Nachfrage sinkt; mit fallendem Preis steigt die Nachfrage und das Angebot sinkt. Das Marktgleichgewicht ist der Schnittpunkt beider Kurven.","fr":"Le modèle économique fondamental : lorsque le prix augmente, l'offre augmente et la demande diminue ; lorsque le prix diminue, la demande augmente et l'offre diminue. L'équilibre du marché est là où les deux courbes se croisent.","tr":"Temel ekonomik model: Fiyat arttıkça arz artar ve talep düşer; fiyat düştükçe talep artar ve arz düşer. Piyasa dengesi her iki eğrinin kesiştiği noktadır.","nl":"Het fundamentele economische model: naarmate de prijs stijgt, stijgt het aanbod en daalt de vraag; naarmate de prijs daalt, stijgt de vraag en daalt het aanbod. Het marktevenwicht is waar beide curven elkaar kruisen.","ru":"Фундаментальная экономическая модель: с ростом цены предложение растёт, а спрос падает; с падением цены спрос растёт, а предложение падает. Рыночное равновесие — точка пересечения обеих кривых.","zh":"基本经济模型：价格上涨时，供给增加、需求下降；价格下降时，需求增加、供给下降。市场均衡是两条曲线的交点。","pt_BR":"O modelo econômico fundamental: à medida que o preço sobe, a oferta aumenta e a demanda cai; à medida que o preço cai, a demanda sobe e a oferta cai. O equilíbrio de mercado é onde as duas curvas se encontram.","pt_PT":"O modelo económico fundamental: à medida que o preço sobe, a oferta aumenta e a procura diminui; à medida que o preço desce, a procura aumenta e a oferta diminui. O equilíbrio de mercado é onde as duas curvas se cruzam."}},
  { id: 'dc-business-0056', deck_id: 'deck-business', front: 'Elasticity of Demand', back: 'Measures how much demand for a product changes in response to a price change. Elastic demand is highly sensitive to price changes; inelastic demand is not.', sort_order: 56 , front_translations: {"es":"Elasticidad de la Demanda","de":"Preiselastizität der Nachfrage","fr":"Élasticité-prix de la demande","tr":"Talep Esnekliği","nl":"Prijselasticiteit van de vraag","ru":"Ценовая эластичность спроса","zh":"需求价格弹性","pt_BR":"Elasticidade da Demanda","pt_PT":"Elasticidade da Procura"}, back_translations: {"es":"Mede el quanto a demanda por un producto muda en respuesta a una variación de precio. Demanda elástica es altamente sensible a cambios de precio; demanda inelástica no es.","de":"Misst, wie stark sich die Nachfrage nach einem Produkt als Reaktion auf eine Preisänderung verändert. Elastische Nachfrage reagiert stark auf Preisänderungen; unelastische Nachfrage nicht.","fr":"Mesure dans quelle mesure la demande d'un produit change en réponse à une variation de prix. Une demande élastique est très sensible aux variations de prix ; une demande inélastique ne l'est pas.","tr":"Bir ürüne yönelik talebin fiyat değişikliğine ne ölçüde tepki verdiğini ölçer. Esnek talep fiyat değişikliklerine karşı hassastır; esnek olmayan talep ise değildir.","nl":"Meet hoeveel de vraag naar een product verandert als reactie op een prijswijziging. Elastische vraag is sterk gevoelig voor prijswijzigingen; inelastische vraag is dat niet.","ru":"Измеряет, насколько изменяется спрос на продукт в ответ на изменение цены. Эластичный спрос высоко чувствителен к изменениям цены; неэластичный — нет.","zh":"衡量产品需求量对价格变化的反应程度。弹性需求对价格变化高度敏感；非弹性需求则不敏感。","pt_BR":"Mede o quanto a demanda por um produto muda em resposta a uma variação de preço. Demanda elástica é altamente sensível a mudanças de preço; demanda inelástica não é.","pt_PT":"Mede em que medida a procura de um produto muda em resposta a uma variação de preço. A procura elástica é altamente sensível a variações de preço; a procura inelástica não é."}},
  { id: 'dc-business-0057', deck_id: 'deck-business', front: 'Opportunity Cost', back: 'The value of the next best alternative foregone when making a decision. It is implicit in every economic and business choice, even when no money changes hands.', sort_order: 57 , front_translations: {"es":"Custo de Oportunidad","de":"Opportunitätskosten","fr":"Coût d'opportunité","tr":"Fırsat Maliyeti","nl":"Opportuniteitskosten","ru":"Альтернативные издержки","zh":"机会成本","pt_BR":"Custo de Oportunidade","pt_PT":"Custo de Oportunidade"}, back_translations: {"es":"El valor de la mejor alternativa preterida al se tomar una decisão. Está implícito en toda escolha económica y empresarial, mismo cuando ningún dinhero muda de manos.","de":"Der Wert der nächstbesten Alternative, die bei einer Entscheidung aufgegeben wird. Er steckt in jeder wirtschaftlichen und unternehmerischen Wahl, selbst wenn kein Geld den Besitzer wechselt.","fr":"La valeur de la meilleure alternative abandonnée lors d'une décision. Elle est implicite dans chaque choix économique et commercial, même lorsqu'aucune somme d'argent ne change de mains.","tr":"Bir karar alınırken vazgeçilen en iyi alternatifin değeri. Para el değiştirmese bile her ekonomik ve iş seçiminde örtük olarak yer alır.","nl":"De waarde van het beste alternatief dat wordt opgegeven bij het nemen van een beslissing. Het zit impliciet in elke economische en zakelijke keuze, zelfs wanneer er geen geld van eigenaar wisselt.","ru":"Ценность наилучшей из отвергнутых альтернатив при принятии решения. Она неявно присутствует в каждом экономическом и деловом выборе, даже когда деньги не меняют владельца.","zh":"做决策时放弃的次优选择的价值。它隐含在每一个经济和商业选择中，即使没有金钱的交换。","pt_BR":"O valor da melhor alternativa preterida ao se tomar uma decisão. Está implícito em toda escolha econômica e empresarial, mesmo quando nenhum dinheiro muda de mãos.","pt_PT":"O valor da melhor alternativa preterida ao tomar uma decisão. Está implícito em cada escolha económica e empresarial, mesmo quando não há troca de dinheiro."}},
  { id: 'dc-business-0058', deck_id: 'deck-business', front: 'Economies of Scale', back: 'The cost advantages a business achieves as it increases production; the average cost per unit falls as output rises due to spreading fixed costs and bulk purchasing efficiencies.', sort_order: 58 , front_translations: {"es":"Economias de Escala","de":"Skaleneffekte","fr":"Économies d'échelle","tr":"Ölçek Ekonomileri","nl":"Schaalvoordelen","ru":"Эффект масштаба","zh":"规模经济","pt_BR":"Economias de Escala","pt_PT":"Economias de Escala"}, back_translations: {"es":"As vantajes de costo que una empresa obtiene a la medida que aumenta a producción; el costo médio por unidad cai con el aumento de la producción, debido a la diluición de los costos fixos y a las eficiencias de compra en volumen.","de":"Die Kostenvorteile, die ein Unternehmen mit steigender Produktion erzielt; die durchschnittlichen Stückkosten sinken mit wachsendem Ausstoß durch die Verteilung fixer Kosten und Einkaufsmengenrabatte.","fr":"Les avantages de coût qu'une entreprise obtient en augmentant sa production ; le coût moyen par unité diminue à mesure que la production augmente, grâce à la dilution des coûts fixes et aux efficacités des achats en volume.","tr":"Bir işletmenin üretimini artırdıkça elde ettiği maliyet avantajları; sabit maliyetlerin dağıtılması ve toplu alım verimlilikleri sayesinde birim başına ortalama maliyet üretim arttıkça düşer.","nl":"De kostenvoordelen die een bedrijf behaalt naarmate het de productie verhoogt; de gemiddelde kosten per eenheid dalen naarmate de output stijgt door de spreiding van vaste kosten en inkoopefficiënties bij grotere volumes.","ru":"Ценовые преимущества, которые предприятие получает по мере роста производства; средняя себестоимость единицы продукции снижается с ростом объёма выпуска за счёт распределения постоянных затрат и эффективности оптовых закупок.","zh":"企业随着产量增加而获得的成本优势；由于固定成本被摊薄以及批量采购效率的提升，单位平均成本随产出增加而下降。","pt_BR":"As vantagens de custo que uma empresa obtém à medida que aumenta a produção; o custo médio por unidade cai com o aumento da produção, devido à diluição dos custos fixos e às eficiências de compra em volume.","pt_PT":"As vantagens de custo que uma empresa obtém à medida que aumenta a produção; o custo médio por unidade diminui com o aumento da produção, devido à distribuição dos custos fixos e às eficiências de compra em volume."}},
  { id: 'dc-business-0059', deck_id: 'deck-business', front: 'Monopoly', back: 'A market structure in which a single seller dominates the market with no close substitutes; the monopolist can set prices above competitive levels, reducing consumer welfare.', sort_order: 59 , front_translations: {"es":"Monopólio","de":"Monopol","fr":"Monopole","tr":"Tekel","nl":"Monopolie","ru":"Монополия","zh":"垄断","pt_BR":"Monopólio","pt_PT":"Monopólio"}, back_translations: {"es":"Una estructura de mercado en que un único vendedor domina el mercado sin substitutos próximos; el monopolista puede definir precios encima de los niveles competitivos, reduciendo el bem-estar del consumidor.","de":"Eine Marktstruktur, in der ein einziger Anbieter den Markt ohne enge Substitute dominiert; der Monopolist kann Preise über dem Wettbewerbsniveau festlegen, was das Verbraucherwohlbefinden reduziert.","fr":"Une structure de marché dans laquelle un seul vendeur domine le marché sans substituts proches ; le monopoleur peut fixer des prix au-dessus des niveaux concurrentiels, réduisant le bien-être des consommateurs.","tr":"Tek bir satıcının yakın ikame olmaksızın piyasaya hakim olduğu piyasa yapısı; tekelci, tüketici refahını azaltarak fiyatları rekabetçi seviyenin üzerinde belirleyebilir.","nl":"Een marktstructuur waarbij één verkoper de markt domineert zonder nauwe substituten; de monopolist kan prijzen boven concurrerende niveaus stellen, waardoor het consumentenwelzijn afneemt.","ru":"Рыночная структура, в которой один продавец доминирует на рынке без близких заменителей; монополист может устанавливать цены выше конкурентного уровня, снижая благосостояние потребителей.","zh":"一种由单一卖家主导市场且没有近似替代品的市场结构；垄断者可以将价格定在竞争水平之上，从而损害消费者福利。","pt_BR":"Uma estrutura de mercado em que um único vendedor domina o mercado sem substitutos próximos; o monopolista pode definir preços acima dos níveis competitivos, reduzindo o bem-estar do consumidor.","pt_PT":"Uma estrutura de mercado em que um único vendedor domina o mercado sem substitutos próximos; o monopolista pode fixar preços acima dos níveis competitivos, reduzindo o bem-estar do consumidor."}},
  { id: 'dc-business-0060', deck_id: 'deck-business', front: 'Oligopoly', back: 'A market structure dominated by a small number of large firms whose actions affect each other; it can lead to tacit collusion and prices above competitive levels.', sort_order: 60 , front_translations: {"es":"Oligopólio","de":"Oligopol","fr":"Oligopole","tr":"Oligopol","nl":"Oligopolie","ru":"Олигополия","zh":"寡头垄断","pt_BR":"Oligopólio","pt_PT":"Oligopólio"}, back_translations: {"es":"Una estructura de mercado dominada por un pequeño número de grandes empresas cujas acciones se afectan mutuamente; puede levar a conluio tácito y precios encima de los niveles competitivos.","de":"Eine Marktstruktur, die von einer kleinen Anzahl großer Unternehmen dominiert wird, deren Handlungen sich gegenseitig beeinflussen; sie kann zu stillschweigender Absprache und Preisen über dem Wettbewerbsniveau führen.","fr":"Une structure de marché dominée par un petit nombre de grandes entreprises dont les actions s'influencent mutuellement ; elle peut conduire à une collusion tacite et à des prix supérieurs aux niveaux concurrentiels.","tr":"Birbirlerinin eylemlerini etkileyen az sayıda büyük firmanın hâkim olduğu piyasa yapısı; örtülü anlaşmaya ve rekabetçi seviyelerin üzerinde fiyatlara yol açabilir.","nl":"Een marktstructuur gedomineerd door een klein aantal grote bedrijven wiens acties elkaar beïnvloeden; dit kan leiden tot stilzwijgende samenspanning en prijzen boven concurrerende niveaus.","ru":"Рыночная структура, в которой доминирует небольшое число крупных фирм, действия которых влияют друг на друга; это может привести к молчаливому сговору и ценам выше конкурентного уровня.","zh":"由少数大型企业主导的市场结构，各企业的行为相互影响；可能导致默契串谋以及高于竞争水平的价格。","pt_BR":"Uma estrutura de mercado dominada por um pequeno número de grandes empresas cujas ações se afetam mutuamente; pode levar a conluio tácito e preços acima dos níveis competitivos.","pt_PT":"Uma estrutura de mercado dominada por um pequeno número de grandes empresas cujas ações se influenciam mutuamente; pode levar a conluio tácito e a preços acima dos níveis competitivos."}},
  { id: 'dc-business-0061', deck_id: 'deck-business', front: 'Perfect Competition', back: 'A theoretical market structure with many sellers, identical products, perfect information, and free entry and exit; no single firm has pricing power.', sort_order: 61 , front_translations: {"es":"Concorrencia Perfeita","de":"Vollkommener Wettbewerb","fr":"Concurrence parfaite","tr":"Tam Rekabet","nl":"Volledige mededinging","ru":"Совершенная конкуренция","zh":"完全竞争","pt_BR":"Concorrência Perfeita","pt_PT":"Concorrência Perfeita"}, back_translations: {"es":"Una estructura de mercado teórica con muchos vendedores, productos identicos, información perfeita y livre entrada y saída; ninguna empresa individual tiene poder de precificación.","de":"Eine theoretische Marktstruktur mit vielen Anbietern, identischen Produkten, vollständiger Information und freiem Marktzutritt und -austritt; kein einzelnes Unternehmen hat Preissetzungsmacht.","fr":"Une structure de marché théorique avec de nombreux vendeurs, des produits identiques, une information parfaite et une entrée et sortie libres ; aucune entreprise individuelle n'a de pouvoir de fixation des prix.","tr":"Çok sayıda satıcı, özdeş ürünler, tam bilgi ve serbest giriş-çıkışın mevcut olduğu teorik bir piyasa yapısı; hiçbir firmanın tek başına fiyat belirleme gücü yoktur.","nl":"Een theoretische marktstructuur met veel verkopers, identieke producten, perfecte informatie en vrije toe- en uittreding; geen enkel bedrijf heeft prijszettingsmacht.","ru":"Теоретическая рыночная структура со многими продавцами, идентичными продуктами, совершенной информацией и свободным входом и выходом; ни одна фирма не обладает ценовой властью.","zh":"一种理论上的市场结构，具有众多卖家、同质产品、完全信息以及自由进入和退出的特点；没有单一企业具有定价权。","pt_BR":"Uma estrutura de mercado teórica com muitos vendedores, produtos idênticos, informação perfeita e livre entrada e saída; nenhuma empresa individual tem poder de precificação.","pt_PT":"Uma estrutura de mercado teórica com muitos vendedores, produtos idênticos, informação perfeita e livre entrada e saída; nenhuma empresa individual tem poder de fixação de preços."}},
  { id: 'dc-business-0062', deck_id: 'deck-business', front: 'Competitive Advantage', back: 'A condition that allows a company to outperform competitors; it can stem from cost leadership, differentiation, or focus strategies as described in Porter\'s Generic Strategies.', sort_order: 62 , front_translations: {"es":"Vantaje Competitiva","de":"Wettbewerbsvorteil","fr":"Avantage concurrentiel","tr":"Rekabet Avantajı","nl":"Concurrentievoordeel","ru":"Конкурентное преимущество","zh":"竞争优势","pt_BR":"Vantagem Competitiva","pt_PT":"Vantagem Competitiva"}, back_translations: {"es":"Una condición que permite a una empresa superar sus competidores; puede resultar de estrategias de liderazgo en costo, diferenciación o foco, conforme descrito en las Estratégias Genéricas de Porter.","de":"Eine Bedingung, die es einem Unternehmen ermöglicht, Wettbewerber zu übertreffen; sie kann aus Kostenführerschaft, Differenzierung oder Fokusstrategien stammen, wie in Porters generischen Strategien beschrieben.","fr":"Une condition permettant à une entreprise de surpasser ses concurrents ; elle peut résulter de stratégies de leadership par les coûts, de différenciation ou de focalisation, telles que décrites dans les Stratégies génériques de Porter.","tr":"Bir şirketin rakiplerini geride bırakmasını sağlayan durum; Porter'ın Genel Stratejileri'nde tanımlandığı üzere maliyet liderliği, farklılaştırma veya odaklanma stratejilerinden kaynaklanabilir.","nl":"Een conditie waardoor een bedrijf beter kan presteren dan concurrenten; het kan voortkomen uit kostenleiderschap, differentiatie of focusstrategieën zoals beschreven in Porter's Generieke Strategieën.","ru":"Условие, позволяющее компании превосходить конкурентов; оно может основываться на лидерстве по затратам, дифференциации или стратегии фокусирования, как описано в модели Портера общих стратегий.","zh":"使公司能够超越竞争对手的条件；可来源于成本领先、差异化或专注战略，如波特通用战略中所述。","pt_BR":"Uma condição que permite a uma empresa superar seus concorrentes; pode resultar de estratégias de liderança em custo, diferenciação ou foco, conforme descrito nas Estratégias Genéricas de Porter.","pt_PT":"Uma condição que permite a uma empresa superar os seus concorrentes; pode derivar de estratégias de liderança em custo, diferenciação ou foco, conforme descrito nas Estratégias Genéricas de Porter."}},
  { id: 'dc-business-0063', deck_id: 'deck-business', front: 'Porter\'s Five Forces', back: 'A framework analyzing five competitive forces affecting an industry: threat of new entrants, buyer power, supplier power, threat of substitutes, and rivalry among existing competitors.', sort_order: 63 , front_translations: {"es":"As Cinco Forças de Porter","de":"Porters Fünf-Kräfte-Modell","fr":"Les cinq forces de Porter","tr":"Porter'ın Beş Gücü","nl":"Vijfkrachtenmodel van Porter","ru":"Пять сил Портера","zh":"波特五力模型","pt_BR":"As Cinco Forças de Porter","pt_PT":"As Cinco Forças de Porter"}, back_translations: {"es":"Un framework que analisa cinco fuerzas competitivas que afectan una indústria: ameaça de nuevos entrantes, poder de barganha de los compradores, poder de barganha de los proveedores, ameaça de substitutos y rivalidad entre los competidores existentes.","de":"Ein Rahmenwerk, das fünf Wettbewerbskräfte analysiert, die eine Branche beeinflussen: Bedrohung durch neue Marktteilnehmer, Käufermacht, Lieferantenmacht, Bedrohung durch Substitute und Rivalität unter bestehenden Wettbewerbern.","fr":"Un cadre analysant cinq forces concurrentielles affectant un secteur : la menace de nouveaux entrants, le pouvoir des acheteurs, le pouvoir des fournisseurs, la menace des substituts et la rivalité entre concurrents existants.","tr":"Bir sektörü etkileyen beş rekabet gücünü analiz eden çerçeve: yeni girişimcilerin tehdidi, alıcı gücü, tedarikçi gücü, ikame tehdidi ve mevcut rakipler arasındaki rekabet.","nl":"Een raamwerk dat vijf concurrentiekrachten analyseert die een sector beïnvloeden: dreiging van nieuwe toetreders, kopersmacht, leveranciersmacht, dreiging van substituten en rivaliteit tussen bestaande concurrenten.","ru":"Концепция, анализирующая пять конкурентных сил, влияющих на отрасль: угроза появления новых игроков, переговорная сила покупателей, переговорная сила поставщиков, угроза субститутов и соперничество между существующими конкурентами.","zh":"分析影响行业的五种竞争力量的框架：新进入者的威胁、买方议价能力、供应商议价能力、替代品威胁以及现有竞争者之间的竞争。","pt_BR":"Um framework que analisa cinco forças competitivas que afetam uma indústria: ameaça de novos entrantes, poder de barganha dos compradores, poder de barganha dos fornecedores, ameaça de substitutos e rivalidade entre os concorrentes existentes.","pt_PT":"Um modelo que analisa cinco forças competitivas que afetam uma indústria: ameaça de novos entrantes, poder negocial dos compradores, poder negocial dos fornecedores, ameaça de substitutos e rivalidade entre os concorrentes existentes."}},
  { id: 'dc-business-0064', deck_id: 'deck-business', front: 'Value Chain', back: 'Michael Porter\'s model describing all activities a company performs to deliver a product; analyzing each activity identifies where value is added and costs can be reduced.', sort_order: 64 , front_translations: {"es":"Cadeia de Valor","de":"Wertkette","fr":"Chaîne de valeur","tr":"Değer Zinciri","nl":"Waardeketen","ru":"Цепочка создания стоимости","zh":"价值链","pt_BR":"Cadeia de Valor","pt_PT":"Cadeia de Valor"}, back_translations: {"es":"El modelo de Michael Porter que descreve todas las atividades que una empresa realiza para entregar un producto; analisar cada atividad identifica donde el valor es adicionado y donde los costos pueden ser reduzidos.","de":"Michael Porters Modell, das alle Aktivitäten beschreibt, die ein Unternehmen zur Lieferung eines Produkts ausführt; die Analyse jeder Aktivität zeigt, wo Wert geschaffen und Kosten gesenkt werden können.","fr":"Le modèle de Michael Porter décrivant toutes les activités qu'une entreprise effectue pour livrer un produit ; l'analyse de chaque activité identifie où la valeur est ajoutée et où les coûts peuvent être réduits.","tr":"Michael Porter'ın bir şirketin ürün teslim etmek için gerçekleştirdiği tüm faaliyetleri açıklayan modeli; her faaliyetin analizi değerin nerede eklendiğini ve maliyetlerin nerede azaltılabileceğini ortaya koyar.","nl":"Michael Porter's model dat alle activiteiten beschrijft die een bedrijf uitvoert om een product te leveren; het analyseren van elke activiteit identificeert waar waarde wordt toegevoegd en kosten kunnen worden verlaagd.","ru":"Модель Майкла Портера, описывающая все виды деятельности, которые компания осуществляет для доставки продукта; анализ каждого вида деятельности позволяет определить, где создаётся ценность и можно снизить затраты.","zh":"迈克尔·波特描述公司为交付产品所执行的全部活动的模型；分析每项活动有助于识别价值增加的环节和可降低成本的地方。","pt_BR":"O modelo de Michael Porter que descreve todas as atividades que uma empresa realiza para entregar um produto; analisar cada atividade identifica onde o valor é adicionado e onde os custos podem ser reduzidos.","pt_PT":"O modelo de Michael Porter que descreve todas as atividades que uma empresa realiza para entregar um produto; analisar cada atividade identifica onde o valor é acrescentado e onde os custos podem ser reduzidos."}},
  { id: 'dc-business-0065', deck_id: 'deck-business', front: 'Business Model Canvas', back: 'A strategic management tool by Alexander Osterwalder with nine building blocks: key partners, activities, resources, value propositions, customer relationships, channels, segments, cost structure, and revenue streams.', sort_order: 65 , front_translations: {"es":"Canvas del Modelo de Negócio","de":"Business Model Canvas","fr":"Canevas du modèle d'affaires","tr":"İş Modeli Tuvali","nl":"Business Model Canvas","ru":"Канвас бизнес-модели","zh":"商业模式画布","pt_BR":"Canvas do Modelo de Negócio","pt_PT":"Canvas do Modelo de Negócio"}, back_translations: {"es":"Una herramienta de gestión estratégica de Alexander Osterwalder con nueve blocos: parceros-chave, atividades-chave, recursos-chave, proposta de valor, relacionamento con clientes, canais, segmentos de clientes, estructura de costos y fontes de ingreso.","de":"Ein strategisches Managementwerkzeug von Alexander Osterwalder mit neun Bausteinen: Schlüsselpartner, Schlüsselaktivitäten, Schlüsselressourcen, Wertangebote, Kundenbeziehungen, Kanäle, Kundensegmente, Kostenstruktur und Einnahmequellen.","fr":"Un outil de gestion stratégique d'Alexander Osterwalder comprenant neuf éléments : partenaires clés, activités clés, ressources clés, propositions de valeur, relations clients, canaux, segments de clientèle, structure des coûts et flux de revenus.","tr":"Alexander Osterwalder'ın dokuz yapı taşından oluşan stratejik yönetim aracı: temel ortaklar, faaliyetler, kaynaklar, değer önerileri, müşteri ilişkileri, kanallar, segmentler, maliyet yapısı ve gelir akışları.","nl":"Een strategisch managementtool van Alexander Osterwalder met negen bouwstenen: sleutelpartners, sleutelactiviteiten, sleutelmiddelen, waardepropositie, klantrelaties, kanalen, klantsegmenten, kostenstructuur en inkomstenstromen.","ru":"Инструмент стратегического управления Александра Остервальдера с девятью строительными блоками: ключевые партнёры, виды деятельности, ресурсы, ценностные предложения, отношения с клиентами, каналы, потребительские сегменты, структура затрат и потоки доходов.","zh":"亚历山大·奥斯特瓦德的战略管理工具，包含九个模块：重要伙伴、关键业务、核心资源、价值主张、客户关系、渠道通路、客户细分、成本结构和收入来源。","pt_BR":"Uma ferramenta de gestão estratégica de Alexander Osterwalder com nove blocos: parceiros-chave, atividades-chave, recursos-chave, proposta de valor, relacionamento com clientes, canais, segmentos de clientes, estrutura de custos e fontes de receita.","pt_PT":"Uma ferramenta de gestão estratégica de Alexander Osterwalder com nove blocos: parceiros-chave, atividades-chave, recursos-chave, proposta de valor, relação com clientes, canais, segmentos de clientes, estrutura de custos e fluxos de receita."}},
  { id: 'dc-business-0066', deck_id: 'deck-business', front: 'Product-Market Fit', back: 'The degree to which a product satisfies a strong market demand. Achieving product-market fit is a critical milestone for startups before scaling.', sort_order: 66 , front_translations: {"es":"Adequación Produto-Mercado","de":"Produkt-Markt-Fit","fr":"Adéquation produit-marché","tr":"Ürün-Pazar Uyumu","nl":"Product-marktfit","ru":"Соответствие продукта рынку","zh":"产品与市场契合度","pt_BR":"Adequação Produto-Mercado","pt_PT":"Adequação Produto-Mercado"}, back_translations: {"es":"El grau en que un producto satisfaz una fuerte demanda de mercado. Alcançar a adequación producto-mercado es un marco crítico para startups antes de escalar.","de":"Das Ausmaß, in dem ein Produkt eine starke Marktnachfrage befriedigt. Das Erreichen des Produkt-Markt-Fits ist ein entscheidender Meilenstein für Startups vor der Skalierung.","fr":"Le degré auquel un produit satisfait une forte demande du marché. Atteindre l'adéquation produit-marché est une étape critique pour les startups avant la mise à l'échelle.","tr":"Bir ürünün güçlü bir pazar talebini ne ölçüde karşıladığı. Ürün-pazar uyumuna ulaşmak, büyümeden önce girişimler için kritik bir dönüm noktasıdır.","nl":"De mate waarin een product aan een sterke marktvraag voldoet. Het bereiken van product-marktfit is een kritieke mijlpaal voor startups vóór het opschalen.","ru":"Степень, в которой продукт удовлетворяет устойчивый рыночный спрос. Достижение соответствия продукта рынку является критически важным этапом для стартапов перед масштабированием.","zh":"产品满足强烈市场需求的程度。在扩张之前实现产品与市场契合，是初创企业的关键里程碑。","pt_BR":"O grau em que um produto satisfaz uma forte demanda de mercado. Alcançar a adequação produto-mercado é um marco crítico para startups antes de escalar.","pt_PT":"O grau em que um produto satisfaz uma forte procura de mercado. Alcançar a adequação produto-mercado é um marco crítico para startups antes de escalar."}},
  { id: 'dc-business-0067', deck_id: 'deck-business', front: 'Minimum Viable Product (MVP)', back: 'A version of a product with just enough features to attract early adopters and validate a business concept. It minimizes wasted effort by testing assumptions cheaply.', sort_order: 67 , front_translations: {"es":"Produto Mínimo Viable (MVP)","de":"Minimum Viable Product (MVP)","fr":"Produit minimum viable (PMV)","tr":"Minimum Uygulanabilir Ürün (MVP)","nl":"Minimum Viable Product (MVP)","ru":"Минимально жизнеспособный продукт (MVP)","zh":"最小可行产品（MVP）","pt_BR":"Produto Mínimo Viável (MVP)","pt_PT":"Produto Mínimo Viável (MVP)"}, back_translations: {"es":"Una versão de un producto con solo recursos suficientes para atrair los primeros usuarios y validar un concepto de negocio. Minimiza el esforço desperdiçado testando hipóteses de forma barata.","de":"Eine Produktversion mit gerade genug Funktionen, um frühe Anwender anzuziehen und ein Geschäftskonzept zu validieren. Sie minimiert Verschwendung, indem Annahmen kostengünstig getestet werden.","fr":"Une version d'un produit avec juste assez de fonctionnalités pour attirer les premiers utilisateurs et valider un concept commercial. Elle minimise les efforts inutiles en testant les hypothèses à moindre coût.","tr":"Erken benimseyenleri çekecek ve bir iş konseptini doğrulayacak kadar özelliğe sahip ürün versiyonu. Varsayımları düşük maliyetle test ederek boşa harcanan çabayı en aza indirir.","nl":"Een versie van een product met net genoeg functies om vroege gebruikers aan te trekken en een bedrijfsconcept te valideren. Het minimaliseert verspilde inspanning door aannames goedkoop te testen.","ru":"Версия продукта с минимально необходимым набором функций для привлечения ранних пользователей и проверки бизнес-концепции. Минимизирует напрасные усилия, дёшево тестируя гипотезы.","zh":"一个具备足够功能以吸引早期用户并验证商业概念的产品版本。它通过低成本测试假设来最大程度减少浪费。","pt_BR":"Uma versão de um produto com apenas recursos suficientes para atrair os primeiros usuários e validar um conceito de negócio. Minimiza o esforço desperdiçado testando hipóteses de forma barata.","pt_PT":"Uma versão de um produto com apenas funcionalidades suficientes para atrair os primeiros utilizadores e validar um conceito de negócio. Minimiza o esforço desperdiçado ao testar hipóteses de forma económica."}},
  { id: 'dc-business-0068', deck_id: 'deck-business', front: 'Pivot', back: 'A structured course correction in a startup\'s strategy, business model, or product direction in response to market feedback, while retaining the core mission or vision.', sort_order: 68 , front_translations: {"es":"Pivo","de":"Pivot","fr":"Pivot","tr":"Pivot","nl":"Pivot","ru":"Пивот","zh":"战略转型（Pivot）","pt_BR":"Pivô","pt_PT":"Pivot"}, back_translations: {"es":"Una correción de curso estruturada en la estrategia, modelo de negocio o dirección del producto de una startup en respuesta al feedback del mercado, manteniendo a misión o visão central.","de":"Eine strukturierte Kurskorrektur in der Strategie, dem Geschäftsmodell oder der Produktausrichtung eines Startups als Reaktion auf Marktfeedback, während die Kernmission oder -vision beibehalten wird.","fr":"Une correction de cap structurée dans la stratégie, le modèle d'affaires ou la direction produit d'une startup en réponse aux retours du marché, tout en conservant la mission ou la vision fondamentale.","tr":"Temel misyon veya vizyonu korurken pazar geri bildirimlerine yanıt olarak bir girişimin stratejisinde, iş modelinde veya ürün yönünde yapılan yapısal bir yön değişikliği.","nl":"Een gestructureerde koerscorrectie in de strategie, het bedrijfsmodel of de productrichting van een startup in reactie op marktfeedback, terwijl de kernmissie of -visie behouden blijft.","ru":"Структурированная корректировка стратегии, бизнес-модели или направления продукта стартапа в ответ на обратную связь рынка при сохранении основной миссии или видения.","zh":"初创公司在保留核心使命或愿景的同时，根据市场反馈对战略、商业模式或产品方向进行有结构的调整。","pt_BR":"Uma correção de curso estruturada na estratégia, modelo de negócio ou direção do produto de uma startup em resposta ao feedback do mercado, mantendo a missão ou visão central.","pt_PT":"Uma correção de rumo estruturada na estratégia, modelo de negócio ou direção do produto de uma startup em resposta ao feedback do mercado, mantendo a missão ou visão central."}},
  { id: 'dc-business-0069', deck_id: 'deck-business', front: 'Disruptive Innovation', back: 'A concept by Clayton Christensen describing how a simpler, more affordable product initially targets overlooked segments and eventually displaces established market leaders.', sort_order: 69 , front_translations: {"es":"Inovación Disruptiva","de":"Disruptive Innovation","fr":"Innovation de rupture","tr":"Yıkıcı İnovasyon","nl":"Disruptieve innovatie","ru":"Подрывная инновация","zh":"颠覆性创新","pt_BR":"Inovação Disruptiva","pt_PT":"Inovação Disruptiva"}, back_translations: {"es":"Un concepto de Clayton Christensen que descreve como un producto más simples y acessible inicialmente mira segmentos ignorados y eventualmente desloca líderes de mercado estabelecidos.","de":"Ein Konzept von Clayton Christensen, das beschreibt, wie ein einfacheres, erschwinglicheres Produkt zunächst übersehene Segmente anspricht und schließlich etablierte Marktführer verdrängt.","fr":"Un concept de Clayton Christensen décrivant comment un produit plus simple et plus abordable cible d'abord des segments négligés avant de finalement détrôner les leaders du marché établis.","tr":"Clayton Christensen'ın, daha basit ve uygun fiyatlı bir ürünün başlangıçta göz ardı edilen segmentleri hedefleyerek sonunda yerleşik pazar liderlerini yerinden ettiğini açıklayan kavramı.","nl":"Een concept van Clayton Christensen dat beschrijft hoe een eenvoudiger, betaalbaarder product aanvankelijk over het hoofd geziene segmenten bedient en uiteindelijk gevestigde marktleiders verdringt.","ru":"Концепция Клейтона Кристенсена, описывающая, как более простой и доступный продукт сначала ориентируется на недооценённые сегменты, а затем вытесняет устоявшихся лидеров рынка.","zh":"克莱顿·克里斯坦森提出的概念，描述更简单、更实惠的产品如何最初瞄准被忽视的细分市场，最终取代成熟的市场领导者。","pt_BR":"Um conceito de Clayton Christensen que descreve como um produto mais simples e acessível inicialmente mira segmentos ignorados e eventualmente desloca líderes de mercado estabelecidos.","pt_PT":"Um conceito de Clayton Christensen que descreve como um produto mais simples e acessível inicialmente visa segmentos ignorados e acaba por deslocar líderes de mercado estabelecidos."}},
  { id: 'dc-business-0070', deck_id: 'deck-business', front: 'Network Effects', back: 'The phenomenon where a product or service becomes more valuable as more people use it; a key growth driver for platforms like social networks and marketplaces.', sort_order: 70 , front_translations: {"es":"Efeitos de Rede","de":"Netzwerkeffekte","fr":"Effets de réseau","tr":"Ağ Etkileri","nl":"Netwerkeffecten","ru":"Сетевые эффекты","zh":"网络效应","pt_BR":"Efeitos de Rede","pt_PT":"Efeitos de Rede"}, back_translations: {"es":"El fenómeno por el qual un producto o serviço se torna más valioso a la medida que más personas el utilizan; un motor de crecimiento fundamental para plataformas como redes sociais y marketplaces.","de":"Das Phänomen, bei dem ein Produkt oder eine Dienstleistung wertvoller wird, je mehr Menschen es nutzen; ein wichtiger Wachstumstreiber für Plattformen wie soziale Netzwerke und Marktplätze.","fr":"Le phénomène par lequel un produit ou service devient plus précieux à mesure que davantage de personnes l'utilisent ; un moteur de croissance clé pour les plateformes telles que les réseaux sociaux et les places de marché.","tr":"Daha fazla kişi kullandıkça bir ürün veya hizmetin daha değerli hale geldiği olgu; sosyal ağlar ve pazar yerleri gibi platformlar için temel bir büyüme etkeni.","nl":"Het fenomeen waarbij een product of dienst waardevoller wordt naarmate meer mensen het gebruiken; een belangrijke groeifactor voor platforms zoals sociale netwerken en marktplaatsen.","ru":"Феномен, при котором продукт или услуга становится более ценной по мере того, как её используют всё больше людей; ключевой драйвер роста для платформ, таких как социальные сети и маркетплейсы.","zh":"随着使用人数增多，产品或服务变得更有价值的现象；是社交网络和市场平台等平台的关键增长驱动力。","pt_BR":"O fenômeno pelo qual um produto ou serviço se torna mais valioso à medida que mais pessoas o utilizam; um motor de crescimento fundamental para plataformas como redes sociais e marketplaces.","pt_PT":"O fenómeno pelo qual um produto ou serviço se torna mais valioso à medida que mais pessoas o utilizam; um motor de crescimento fundamental para plataformas como redes sociais e mercados digitais."}},
  { id: 'dc-business-0071', deck_id: 'deck-business', front: 'Freemium Model', back: 'A pricing strategy offering a basic product for free while charging for premium features; it lowers the barrier to adoption while converting a subset of users to paying customers.', sort_order: 71 , front_translations: {"es":"Modelo Freemium","de":"Freemium-Modell","fr":"Modèle freemium","tr":"Freemium Modeli","nl":"Freemiummodel","ru":"Модель freemium","zh":"免费增值模式（Freemium）","pt_BR":"Modelo Freemium","pt_PT":"Modelo Freemium"}, back_translations: {"es":"Una estrategia de precificación que oferece un producto básico gratuitamente mientras cobra por recursos premium; reduce a barrera a la adoción al mismo tiempo que convierte una parcela de usuarios en clientes pagantes.","de":"Eine Preisstrategie, die ein Basisprodukt kostenlos anbietet und für Premium-Funktionen Gebühren erhebt; sie senkt die Adoptionshürde und konvertiert einen Teil der Nutzer in zahlende Kunden.","fr":"Une stratégie de tarification offrant un produit de base gratuitement tout en facturant les fonctionnalités premium ; elle abaisse la barrière à l'adoption tout en convertissant une partie des utilisateurs en clients payants.","tr":"Temel bir ürünü ücretsiz sunarken premium özellikler için ücret alan fiyatlandırma stratejisi; benimseme engelini düşürürken kullanıcıların bir kısmını ödeme yapan müşterilere dönüştürür.","nl":"Een prijsstrategie waarbij een basisproduct gratis wordt aangeboden en voor premiumfuncties wordt betaald; het verlaagt de adoptiedrempel terwijl een deel van de gebruikers wordt omgezet naar betalende klanten.","ru":"Ценовая стратегия, при которой базовый продукт предоставляется бесплатно, а за премиум-функции взимается плата; снижает барьер для принятия, конвертируя часть пользователей в платящих клиентов.","zh":"一种定价策略，提供基础产品免费使用，同时对高级功能收费；降低用户采用门槛，同时将部分用户转化为付费客户。","pt_BR":"Uma estratégia de precificação que oferece um produto básico gratuitamente enquanto cobra por recursos premium; reduz a barreira à adoção ao mesmo tempo que converte uma parcela de usuários em clientes pagantes.","pt_PT":"Uma estratégia de preços que oferece um produto básico gratuitamente enquanto cobra pelas funcionalidades premium; reduz a barreira à adoção ao mesmo tempo que converte uma parte dos utilizadores em clientes pagantes."}},
  { id: 'dc-business-0072', deck_id: 'deck-business', front: 'SaaS (Software as a Service)', back: 'A software delivery model where applications are hosted in the cloud and licensed on a subscription basis; it provides predictable recurring revenue for the vendor.', sort_order: 72 , front_translations: {"es":"SaaS (Software como Serviço)","de":"SaaS (Software as a Service)","fr":"SaaS (logiciel en tant que service)","tr":"SaaS (Hizmet Olarak Yazılım)","nl":"SaaS (Software as a Service)","ru":"SaaS (программное обеспечение как услуга)","zh":"SaaS（软件即服务）","pt_BR":"SaaS (Software como Serviço)","pt_PT":"SaaS (Software como Serviço)"}, back_translations: {"es":"Un modelo de entrega de software donde las aplicaciones son hospedadas en la nuvem y licenciadas por assinatura; proporciona ingreso recorrente y previsible para el proveedor.","de":"Ein Software-Bereitstellungsmodell, bei dem Anwendungen in der Cloud gehostet und auf Abonnementbasis lizenziert werden; es bietet dem Anbieter vorhersehbare, wiederkehrende Einnahmen.","fr":"Un modèle de distribution de logiciels où les applications sont hébergées dans le cloud et concédées sous licence par abonnement ; il procure des revenus récurrents prévisibles au fournisseur.","tr":"Uygulamaların bulutta barındırıldığı ve abonelik esasına göre lisanslandığı yazılım dağıtım modeli; sağlayıcıya öngörülebilir ve tekrar eden gelir sağlar.","nl":"Een software-leveringsmodel waarbij applicaties in de cloud worden gehost en op abonnementsbasis worden gelicentieerd; het biedt de leverancier voorspelbare terugkerende inkomsten.","ru":"Модель распространения программного обеспечения, при которой приложения размещаются в облаке и лицензируются на основе подписки; обеспечивает поставщику предсказуемый регулярный доход.","zh":"一种软件交付模式，应用程序托管在云端并按订阅方式授权；为供应商提供可预测的经常性收入。","pt_BR":"Um modelo de entrega de software onde as aplicações são hospedadas na nuvem e licenciadas por assinatura; proporciona receita recorrente e previsível para o fornecedor.","pt_PT":"Um modelo de entrega de software onde as aplicações são alojadas na nuvem e licenciadas por subscrição; proporciona receitas recorrentes e previsíveis ao fornecedor."}},
  { id: 'dc-business-0073', deck_id: 'deck-business', front: 'B2B vs. B2C', back: 'B2B (Business-to-Business) involves transactions between companies, with longer sales cycles and higher contract values. B2C (Business-to-Consumer) targets individual consumers with often shorter sales cycles.', sort_order: 73 , front_translations: {"es":"B2B vs. B2C","de":"B2B vs. B2C","fr":"B2B vs. B2C","tr":"B2B ve B2C","nl":"B2B vs. B2C","ru":"B2B и B2C","zh":"B2B 与 B2C","pt_BR":"B2B vs. B2C","pt_PT":"B2B vs. B2C"}, back_translations: {"es":"B2B (Business-to-Business) involucra transaciones entre empresas, con ciclos de venta más largos y valores de contrato más altos. B2C (Business-to-Consumer) tiene como alvo consumidores individuais con ciclos de venta frecuentemente más curtos.","de":"B2B (Business-to-Business) umfasst Transaktionen zwischen Unternehmen mit längeren Verkaufszyklen und höheren Vertragswerten. B2C (Business-to-Consumer) richtet sich an Einzelverbraucher mit oft kürzeren Verkaufszyklen.","fr":"Le B2B (Business-to-Business) implique des transactions entre entreprises, avec des cycles de vente plus longs et des valeurs de contrat plus élevées. Le B2C (Business-to-Consumer) cible les consommateurs individuels avec des cycles de vente souvent plus courts.","tr":"B2B (İşletmeden İşletmeye), daha uzun satış döngüleri ve daha yüksek sözleşme değerleriyle şirketler arası işlemleri kapsar. B2C (İşletmeden Tüketiciye), genellikle daha kısa satış döngüleriyle bireysel tüketicileri hedefler.","nl":"B2B (Business-to-Business) omvat transacties tussen bedrijven, met langere verkoopcycli en hogere contractwaarden. B2C (Business-to-Consumer) richt zich op individuele consumenten met vaak kortere verkoopcycli.","ru":"B2B (бизнес для бизнеса) подразумевает транзакции между компаниями с более длинными циклами продаж и более высокой стоимостью контрактов. B2C (бизнес для потребителя) ориентирован на частных лиц с, как правило, более короткими циклами продаж.","zh":"B2B（企业对企业）涉及公司间交易，销售周期较长、合同价值较高。B2C（企业对消费者）面向个人消费者，销售周期通常较短。","pt_BR":"B2B (Business-to-Business) envolve transações entre empresas, com ciclos de venda mais longos e valores de contrato mais altos. B2C (Business-to-Consumer) tem como alvo consumidores individuais com ciclos de venda frequentemente mais curtos.","pt_PT":"B2B (Business-to-Business) envolve transações entre empresas, com ciclos de venda mais longos e valores de contrato mais elevados. B2C (Business-to-Consumer) tem como alvo consumidores individuais com ciclos de venda frequentemente mais curtos."}},
  { id: 'dc-business-0074', deck_id: 'deck-business', front: 'Marketing Mix (4 Ps)', back: 'Product, Price, Place, and Promotion — the four key elements a company controls to market its offerings effectively to target customers.', sort_order: 74 , front_translations: {"es":"Mix de Marketing (4 Ps)","de":"Marketing-Mix (4 Ps)","fr":"Mix marketing (4 P)","tr":"Pazarlama Karması (4P)","nl":"Marketingmix (4 P's)","ru":"Маркетинг-микс (4P)","zh":"营销组合（4P）","pt_BR":"Mix de Marketing (4 Ps)","pt_PT":"Mix de Marketing (4 Ps)"}, back_translations: {"es":"Produto, Preço, Praça y Promoción — los cuatro elementos-chave que una empresa controla para comercializar sus ofertas de forma eficaz para los clientes-alvo.","de":"Produkt, Preis, Platz und Promotion — die vier Schlüsselelemente, die ein Unternehmen kontrolliert, um seine Angebote effektiv an Zielkunden zu vermarkten.","fr":"Produit, Prix, Place et Promotion — les quatre éléments clés qu'une entreprise contrôle pour commercialiser efficacement ses offres auprès des clients cibles.","tr":"Ürün, Fiyat, Yer ve Tanıtım — bir şirketin tekliflerini hedef müşterilere etkin biçimde pazarlamak için kontrol ettiği dört temel unsur.","nl":"Product, Prijs, Plaats en Promotie — de vier sleutelelementen die een bedrijf beheert om zijn aanbod effectief te vermarkten aan doelklanten.","ru":"Продукт, Цена, Место и Продвижение — четыре ключевых элемента, которыми управляет компания для эффективного маркетинга своих предложений целевым клиентам.","zh":"产品、价格、渠道和促销——企业掌控的四个关键要素，用于有效地向目标客户营销其产品。","pt_BR":"Produto, Preço, Praça e Promoção — os quatro elementos-chave que uma empresa controla para comercializar suas ofertas de forma eficaz para os clientes-alvo.","pt_PT":"Produto, Preço, Distribuição e Promoção — os quatro elementos-chave que uma empresa controla para comercializar as suas ofertas de forma eficaz junto dos clientes-alvo."}},
  { id: 'dc-business-0075', deck_id: 'deck-business', front: 'Brand Equity', back: 'The commercial value that derives from consumer perception of the brand name rather than the product itself. Strong brand equity enables premium pricing and customer loyalty.', sort_order: 75 , front_translations: {"es":"Brand Equity","de":"Markenwert","fr":"Capital de marque","tr":"Marka Değeri","nl":"Merkwaarde","ru":"Капитал бренда","zh":"品牌资产","pt_BR":"Brand Equity","pt_PT":"Brand Equity"}, back_translations: {"es":"El valor comercial derivado de la percepción del consumidor sobre el nombre de la marca, y no sobre el producto en si. Un fuerte brand equity possibilita precios premium y fidelización de clientes.","de":"Der kommerzielle Wert, der aus der Wahrnehmung des Markennamens durch die Verbraucher entsteht, nicht aus dem Produkt selbst. Starker Markenwert ermöglicht Premiumpreise und Kundentreue.","fr":"La valeur commerciale découlant de la perception de la marque par les consommateurs plutôt que du produit lui-même. Un capital de marque solide permet une tarification premium et la fidélisation des clients.","tr":"Ürünün kendisinden değil, tüketicilerin marka adına ilişkin algısından kaynaklanan ticari değer. Güçlü marka değeri, prim fiyatlandırmasına ve müşteri sadakatine olanak tanır.","nl":"De commerciële waarde die voortkomt uit de perceptie van de merknaam door consumenten, in plaats van het product zelf. Sterke merkwaarde maakt premiumprijsstelling en klantloyaliteit mogelijk.","ru":"Коммерческая ценность, возникающая из восприятия потребителями торговой марки, а не самого продукта. Сильный капитал бренда позволяет устанавливать премиальные цены и формирует лояльность клиентов.","zh":"源于消费者对品牌名称而非产品本身的认知所产生的商业价值。强大的品牌资产能够实现溢价定价并培养客户忠诚度。","pt_BR":"O valor comercial derivado da percepção do consumidor sobre o nome da marca, e não sobre o produto em si. Um forte brand equity possibilita preços premium e fidelização de clientes.","pt_PT":"O valor comercial que deriva da perceção do consumidor sobre o nome da marca, e não sobre o produto em si. Um forte brand equity permite preços premium e fidelização de clientes."}},
  { id: 'dc-business-0076', deck_id: 'deck-business', front: 'Net Promoter Score (NPS)', back: 'A customer loyalty metric calculated by subtracting the percentage of detractors from promoters. Scores above 50 are generally considered excellent.', sort_order: 76 , front_translations: {"es":"Net Promoter Score (NPS)","de":"Net Promoter Score (NPS)","fr":"Net Promoter Score (NPS)","tr":"Net Tavsiye Skoru (NPS)","nl":"Net Promoter Score (NPS)","ru":"Индекс потребительской лояльности (NPS)","zh":"净推荐值（NPS）","pt_BR":"Net Promoter Score (NPS)","pt_PT":"Net Promoter Score (NPS)"}, back_translations: {"es":"Una métrica de fidelidad del cliente calculada subtraindo a porcentaje de detratores de la porcentaje de promotores. Pontuaciones por encima de 50 son generalmente consideradas excelentes.","de":"Eine Kundentreue-Kennzahl, die berechnet wird, indem der Prozentsatz der Kritiker vom Prozentsatz der Befürworter abgezogen wird. Werte über 50 gelten allgemein als ausgezeichnet.","fr":"Une mesure de fidélité client calculée en soustrayant le pourcentage de détracteurs du pourcentage de promoteurs. Un score supérieur à 50 est généralement considéré comme excellent.","tr":"Destekçilerin yüzdesinden eleştirmenlerin yüzdesini çıkararak hesaplanan bir müşteri sadakati ölçütüdür. 50'nin üzerindeki puanlar genellikle mükemmel kabul edilir.","nl":"Een klantloyaliteitsmaatstaf berekend door het percentage criticasters af te trekken van het percentage promotors. Scores boven de 50 worden over het algemeen als uitstekend beschouwd.","ru":"Метрика лояльности клиентов, рассчитываемая путём вычитания доли критиков из доли сторонников. Значения выше 50 обычно считаются отличными.","zh":"一种客户忠诚度指标，通过从推荐者百分比中减去贬损者百分比来计算。得分高于50通常被认为是优秀的。","pt_BR":"Uma métrica de fidelidade do cliente calculada subtraindo a porcentagem de detratores da porcentagem de promotores. Pontuações acima de 50 são geralmente consideradas excelentes.","pt_PT":"Uma métrica de fidelização de clientes calculada subtraindo a percentagem de detratores à percentagem de promotores. Pontuações acima de 50 são geralmente consideradas excelentes."}},
  { id: 'dc-business-0077', deck_id: 'deck-business', front: 'Conversion Rate', back: 'The percentage of users who complete a desired action (e.g., purchase, sign-up) out of the total number who were presented with the opportunity.', sort_order: 77 , front_translations: {"es":"Taxa de conversão","de":"Konversionsrate","fr":"Taux de conversion","tr":"Dönüşüm Oranı","nl":"Conversieratio","ru":"Коэффициент конверсии","zh":"转化率","pt_BR":"Taxa de conversão","pt_PT":"Taxa de conversão"}, back_translations: {"es":"La porcentaje de usuarios que concluem una acción desejada (p. ex., compra, cadastro) del total de usuarios que tiveram a oportunidad.","de":"Der Prozentsatz der Nutzer, die eine gewünschte Aktion abschließen (z. B. Kauf, Anmeldung), bezogen auf die Gesamtzahl derer, denen die Möglichkeit präsentiert wurde.","fr":"Le pourcentage d'utilisateurs qui effectuent une action souhaitée (par ex. achat, inscription) sur le nombre total de personnes à qui l'opportunité a été présentée.","tr":"Fırsatla karşılaşan toplam kullanıcı sayısından istenen bir eylemi (örn. satın alma, kayıt) tamamlayanların yüzdesi.","nl":"Het percentage gebruikers dat een gewenste actie voltooit (bijv. aankoop, aanmelding) van het totale aantal gebruikers dat de kans heeft gekregen.","ru":"Процент пользователей, выполнивших желаемое действие (например, покупку, регистрацию), от общего числа тех, кому была представлена такая возможность.","zh":"在所有被给予机会的用户中，完成期望行为（如购买、注册）的用户百分比。","pt_BR":"A porcentagem de usuários que concluem uma ação desejada (p. ex., compra, cadastro) do total de usuários que tiveram a oportunidade.","pt_PT":"A percentagem de utilizadores que completam uma ação desejada (p. ex., compra, registo) do total de utilizadores que tiveram a oportunidade."}},
  { id: 'dc-business-0078', deck_id: 'deck-business', front: 'Cost of Goods Sold (COGS)', back: 'The direct costs attributable to the production of goods sold, including raw materials and direct labor. Revenue minus COGS equals gross profit.', sort_order: 78 , front_translations: {"es":"Custo de los productos vendidos (CPV / COGS)","de":"Umsatzkosten (COGS)","fr":"Coût des marchandises vendues (COGS)","tr":"Satılan Malın Maliyeti (SMM / COGS)","nl":"Kostprijs van verkochte goederen (COGS)","ru":"Себестоимость проданных товаров (COGS)","zh":"销售成本（COGS）","pt_BR":"Custo dos produtos vendidos (CPV / COGS)","pt_PT":"Custo dos produtos vendidos (CPV / COGS)"}, back_translations: {"es":"Los costos diretos atribuibles a la producción de los bens vendidos, incluyendo materias primas y mano de obra direta. Receita menos CPV es igual al ganancia bruto.","de":"Die direkt der Produktion der verkauften Waren zuzurechnenden Kosten, einschließlich Rohmaterialien und direkter Arbeit. Umsatz minus COGS ergibt den Bruttogewinn.","fr":"Les coûts directs attribuables à la production des marchandises vendues, incluant les matières premières et la main-d'œuvre directe. Le chiffre d'affaires moins le COGS est égal au bénéfice brut.","tr":"Ham maddeler ve doğrudan işçilik dahil olmak üzere satılan malların üretimine doğrudan atfedilebilen maliyetler. Gelirden COGS çıkarıldığında brüt kâr elde edilir.","nl":"De directe kosten toe te schrijven aan de productie van verkochte goederen, inclusief grondstoffen en directe arbeid. Omzet minus COGS is gelijk aan de brutowinst.","ru":"Прямые затраты, связанные с производством проданных товаров, включая сырьё и прямые трудозатраты. Выручка минус COGS равна валовой прибыли.","zh":"直接归属于已售商品生产的成本，包括原材料和直接人工。收入减去销售成本等于毛利润。","pt_BR":"Os custos diretos atribuíveis à produção dos bens vendidos, incluindo matérias-primas e mão de obra direta. Receita menos CPV é igual ao lucro bruto.","pt_PT":"Os custos diretos atribuíveis à produção dos bens vendidos, incluindo matérias-primas e mão de obra direta. Receita menos CPV é igual ao lucro bruto."}},
  { id: 'dc-business-0079', deck_id: 'deck-business', front: 'Operating Expenses (OpEx)', back: 'Ongoing costs for running a business that are not directly tied to production, such as marketing, rent, utilities, and salaries. Distinct from capital expenditures (CapEx).', sort_order: 79 , front_translations: {"es":"Despesas operacionais (OpEx)","de":"Betriebsausgaben (OpEx)","fr":"Charges d'exploitation (OpEx)","tr":"İşletme Giderleri (OpEx)","nl":"Operationele uitgaven (OpEx)","ru":"Операционные расходы (OpEx)","zh":"运营支出（OpEx）","pt_BR":"Despesas operacionais (OpEx)","pt_PT":"Despesas operacionais (OpEx)"}, back_translations: {"es":"Custos contínuos para operar un negocio que no están directamente ligados a la producción, como marketing, aluguel, serviços públicos y salários. Distintos de las gastos de capital (CapEx).","de":"Laufende Kosten für den Betrieb eines Unternehmens, die nicht direkt mit der Produktion verbunden sind, wie Marketing, Miete, Nebenkosten und Gehälter. Unterscheiden sich von Investitionsausgaben (CapEx).","fr":"Coûts permanents liés à l'exploitation d'une entreprise non directement liés à la production, tels que le marketing, le loyer, les services publics et les salaires. Distincts des dépenses d'investissement (CapEx).","tr":"Pazarlama, kira, faturalar ve maaşlar gibi doğrudan üretime bağlı olmayan işletme yürütme maliyetleri. Sermaye harcamalarından (CapEx) farklıdır.","nl":"Doorlopende kosten voor het runnen van een bedrijf die niet direct verband houden met productie, zoals marketing, huur, nutsvoorzieningen en salarissen. Verschilt van kapitaaluitgaven (CapEx).","ru":"Текущие затраты на ведение бизнеса, не связанные напрямую с производством: маркетинг, аренда, коммунальные услуги, зарплаты. Отличаются от капитальных затрат (CapEx).","zh":"企业日常运营中不直接与生产挂钩的持续性成本，如市场营销、租金、水电费和薪资，与资本支出（CapEx）不同。","pt_BR":"Custos contínuos para operar um negócio que não estão diretamente ligados à produção, como marketing, aluguel, serviços públicos e salários. Distintos das despesas de capital (CapEx).","pt_PT":"Custos contínuos para gerir um negócio que não estão diretamente ligados à produção, como marketing, renda, serviços públicos e salários. Distintos das despesas de capital (CapEx)."}},
  { id: 'dc-business-0080', deck_id: 'deck-business', front: 'Capital Expenditure (CapEx)', back: 'Funds used by a company to acquire, upgrade, or maintain physical assets such as machinery and buildings; unlike OpEx, CapEx is capitalized on the balance sheet and depreciated.', sort_order: 80 , front_translations: {"es":"Despesas de capital (CapEx)","de":"Investitionsausgaben (CapEx)","fr":"Dépenses d'investissement (CapEx)","tr":"Sermaye Harcamaları (CapEx)","nl":"Kapitaaluitgaven (CapEx)","ru":"Капитальные затраты (CapEx)","zh":"资本支出（CapEx）","pt_BR":"Despesas de capital (CapEx)","pt_PT":"Despesas de capital (CapEx)"}, back_translations: {"es":"Recursos usados por una empresa para adquirir, melhorar o mantener ativos físicos, como máquinas y edifícios; al contrário del OpEx, el CapEx es capitalizado en el balanço y depreciado.","de":"Mittel, die ein Unternehmen für den Erwerb, die Verbesserung oder Instandhaltung physischer Anlagen wie Maschinen und Gebäude verwendet; im Gegensatz zu OpEx wird CapEx in der Bilanz aktiviert und abgeschrieben.","fr":"Fonds utilisés par une entreprise pour acquérir, améliorer ou entretenir des actifs physiques tels que les machines et les bâtiments ; contrairement aux OpEx, les CapEx sont capitalisées au bilan et amorties.","tr":"Bir şirketin makine ve binalar gibi fiziksel varlıkları edinmek, yükseltmek veya korumak için kullandığı fonlar; OpEx'ten farklı olarak CapEx bilançoda aktifleştirilir ve amortismana tabi tutulur.","nl":"Middelen die een bedrijf gebruikt om fysieke activa zoals machines en gebouwen te verwerven, te upgraden of te onderhouden; in tegenstelling tot OpEx worden CapEx geactiveerd op de balans en afgeschreven.","ru":"Средства, используемые компанией для приобретения, модернизации или обслуживания физических активов — машин, оборудования, зданий; в отличие от OpEx, CapEx капитализируются в балансе и амортизируются.","zh":"公司用于购置、升级或维护机械、建筑等实物资产的资金；与运营支出不同，资本支出在资产负债表上资本化并计提折旧。","pt_BR":"Recursos usados por uma empresa para adquirir, melhorar ou manter ativos físicos, como máquinas e edifícios; ao contrário do OpEx, o CapEx é capitalizado no balanço e depreciado.","pt_PT":"Recursos utilizados por uma empresa para adquirir, melhorar ou manter ativos físicos, como máquinas e edifícios; ao contrário do OpEx, o CapEx é capitalizado no balanço e depreciado."}},
  { id: 'dc-business-0081', deck_id: 'deck-business', front: 'Free Cash Flow (FCF)', back: 'Operating cash flow minus capital expenditures. It represents the cash a company generates after investing in its business, available for dividends, debt repayment, or reinvestment.', sort_order: 81 , front_translations: {"es":"Flujo de caja livre (FCF)","de":"Freier Cashflow (FCF)","fr":"Flux de trésorerie disponible (FCF)","tr":"Serbest Nakit Akışı (FCF)","nl":"Vrije kasstroom (FCF)","ru":"Свободный денежный поток (FCF)","zh":"自由现金流（FCF）","pt_BR":"Fluxo de caixa livre (FCF)","pt_PT":"Fluxo de caixa livre (FCF)"}, back_translations: {"es":"Flujo de caja operacional menos gastos de capital. Representa el caixa gerado por una empresa após investir en sus negocios, disponible para dividendos, pagamento de dívidas o reinvestimento.","de":"Operativer Cashflow minus Investitionsausgaben. Er stellt den Zahlungsmittelüberschuss dar, den ein Unternehmen nach Investitionen in sein Geschäft generiert, der für Dividenden, Schuldenabbau oder Reinvestitionen verfügbar ist.","fr":"Flux de trésorerie d'exploitation moins les dépenses d'investissement. Il représente les liquidités générées par une entreprise après avoir investi dans son activité, disponibles pour les dividendes, le remboursement de dettes ou le réinvestissement.","tr":"Faaliyetlerden elde edilen nakit akışından sermaye harcamalarının çıkarılmasıyla hesaplanır. Bir şirketin işine yatırım yaptıktan sonra temettü, borç ödeme veya yeniden yatırım için kullanılabilecek nakdi temsil eder.","nl":"Operationele kasstroom minus kapitaaluitgaven. Het vertegenwoordigt het geld dat een bedrijf genereert na investeringen in zijn activiteiten, beschikbaar voor dividenden, schuldaflossing of herinvestering.","ru":"Операционный денежный поток за вычетом капитальных затрат. Представляет средства, генерируемые компанией после инвестиций в бизнес, доступные для выплаты дивидендов, погашения долга или реинвестирования.","zh":"经营活动现金流减去资本支出。代表企业在对业务进行投资后产生的现金，可用于派发股息、偿还债务或再投资。","pt_BR":"Fluxo de caixa operacional menos despesas de capital. Representa o caixa gerado por uma empresa após investir em seus negócios, disponível para dividendos, pagamento de dívidas ou reinvestimento.","pt_PT":"Fluxo de caixa operacional menos despesas de capital. Representa o caixa gerado por uma empresa após investir no seu negócio, disponível para dividendos, reembolso de dívidas ou reinvestimento."}},
  { id: 'dc-business-0082', deck_id: 'deck-business', front: 'Discounted Cash Flow (DCF)', back: 'A valuation method that estimates the value of an investment based on its expected future cash flows, discounted back to the present using the cost of capital.', sort_order: 82 , front_translations: {"es":"Flujo de caja descontado (DCF)","de":"Discounted Cashflow (DCF)","fr":"Flux de trésorerie actualisés (DCF)","tr":"İndirgenmiş Nakit Akışı (DCF)","nl":"Verdisconteerde kasstroom (DCF)","ru":"Дисконтированный денежный поток (DCF)","zh":"折现现金流（DCF）","pt_BR":"Fluxo de caixa descontado (DCF)","pt_PT":"Fluxo de caixa descontado (DCF)"}, back_translations: {"es":"Un método de avaliación que estima el valor de un inversión con base en los fluxos de caixa futuros esperados, descontados al costo de capital.","de":"Eine Bewertungsmethode, die den Wert einer Investition auf Basis ihrer erwarteten künftigen Zahlungsströme schätzt, die mit den Kapitalkosten auf den Gegenwartswert abgezinst werden.","fr":"Une méthode d'évaluation qui estime la valeur d'un investissement en fonction de ses flux de trésorerie futurs attendus, actualisés au coût du capital.","tr":"Bir yatırımın değerini, sermaye maliyeti kullanılarak bugüne iskonto edilen beklenen gelecekteki nakit akışlarına dayanarak tahmin eden bir değerleme yöntemi.","nl":"Een waarderingsmethode die de waarde van een investering schat op basis van de verwachte toekomstige kasstromen, verdisconteerd tegen de kapitaalkosten.","ru":"Метод оценки стоимости инвестиции на основе ожидаемых будущих денежных потоков, дисконтированных до текущей стоимости с использованием стоимости капитала.","zh":"一种估值方法，通过将预期未来现金流以资本成本折现回当前来估算投资价值。","pt_BR":"Um método de avaliação que estima o valor de um investimento com base nos fluxos de caixa futuros esperados, descontados ao custo de capital.","pt_PT":"Um método de avaliação que estima o valor de um investimento com base nos fluxos de caixa futuros esperados, descontados ao custo de capital."}},
  { id: 'dc-business-0083', deck_id: 'deck-business', front: 'Weighted Average Cost of Capital (WACC)', back: 'The average rate a company is expected to pay to finance its assets, weighted by the proportion of equity and debt; used as the discount rate in DCF analysis.', sort_order: 83 , front_translations: {"es":"Custo médio ponderado de capital (WACC)","de":"Gewichteter durchschnittlicher Kapitalkostensatz (WACC)","fr":"Coût moyen pondéré du capital (WACC)","tr":"Ağırlıklı Ortalama Sermaye Maliyeti (WACC)","nl":"Gewogen gemiddelde kapitaalkosten (WACC)","ru":"Средневзвешенная стоимость капитала (WACC)","zh":"加权平均资本成本（WACC）","pt_BR":"Custo médio ponderado de capital (WACC)","pt_PT":"Custo médio ponderado de capital (WACC)"}, back_translations: {"es":"La taxa média que una empresa espera pagar para financiar sus ativos, ponderada por la proporción de capital propio y dívida; usada como taxa de desconto en la análise DCF.","de":"Der durchschnittliche Zinssatz, den ein Unternehmen voraussichtlich zur Finanzierung seiner Vermögenswerte zahlt, gewichtet nach dem Anteil von Eigenkapital und Fremdkapital; wird als Diskontierungssatz in der DCF-Analyse verwendet.","fr":"Le taux moyen qu'une entreprise devrait payer pour financer ses actifs, pondéré par la proportion de capitaux propres et de dettes ; utilisé comme taux d'actualisation dans l'analyse DCF.","tr":"Bir şirketin varlıklarını finanse etmek için ödemeyi beklediği ortalama oran; öz sermaye ve borç oranlarına göre ağırlıklandırılır ve DCF analizinde iskonto oranı olarak kullanılır.","nl":"Het gemiddelde tarief dat een bedrijf naar verwachting betaalt om zijn activa te financieren, gewogen naar de verhouding eigen vermogen en schuld; gebruikt als discontovoet in DCF-analyse.","ru":"Средняя ставка, которую компания ожидает платить за финансирование своих активов, взвешенная по доле собственного капитала и долга; используется как ставка дисконтирования в DCF-анализе.","zh":"公司预期用于融资其资产所支付的平均利率，按股权和债务比例加权；用作DCF分析中的折现率。","pt_BR":"A taxa média que uma empresa espera pagar para financiar seus ativos, ponderada pela proporção de capital próprio e dívida; usada como taxa de desconto na análise DCF.","pt_PT":"A taxa média que uma empresa espera pagar para financiar os seus ativos, ponderada pela proporção de capital próprio e dívida; utilizada como taxa de desconto na análise DCF."}},
  { id: 'dc-business-0084', deck_id: 'deck-business', front: 'Merger & Acquisition (M&A)', back: 'Mergers combine two companies into one; acquisitions involve one company purchasing another. Both are strategies for growth, diversification, or gaining competitive advantages.', sort_order: 84 , front_translations: {"es":"Fusões y aquisiciones (M&A)","de":"Fusion & Übernahme (M&A)","fr":"Fusions et acquisitions (M&A)","tr":"Birleşme ve Satın Alma (M&A)","nl":"Fusies en overnames (M&A)","ru":"Слияния и поглощения (M&A)","zh":"并购（M&A）","pt_BR":"Fusões e aquisições (M&A)","pt_PT":"Fusões e aquisições (M&A)"}, back_translations: {"es":"As fusões combinam de los empresas en una; las aquisiciones involucran una empresa comprando outra. Ambas son estrategias de crecimiento, diversificación o obtención de vantajes competitivas.","de":"Bei Fusionen werden zwei Unternehmen zu einem zusammengeschlossen; bei Übernahmen kauft ein Unternehmen ein anderes. Beides sind Strategien für Wachstum, Diversifikation oder die Erlangung von Wettbewerbsvorteilen.","fr":"Les fusions combinent deux entreprises en une ; les acquisitions consistent à acheter une autre entreprise. Ces deux stratégies visent la croissance, la diversification ou l'obtention d'avantages concurrentiels.","tr":"Birleşmelerde iki şirket tek bir yapıda birleşir; satın almalarda bir şirket başka bir şirketi satın alır. Her ikisi de büyüme, çeşitlendirme veya rekabet avantajı elde etme stratejileridir.","nl":"Bij fusies worden twee bedrijven samengevoegd tot één; bij overnames koopt een bedrijf een ander. Beide zijn strategieën voor groei, diversificatie of het behalen van concurrentievoordelen.","ru":"При слиянии два предприятия объединяются в одно; при поглощении одна компания приобретает другую. Обе стратегии направлены на рост, диверсификацию или получение конкурентных преимуществ.","zh":"合并是将两家公司合并为一家；收购是一家公司购买另一家公司。两者都是实现增长、多元化或获取竞争优势的策略。","pt_BR":"As fusões combinam duas empresas em uma; as aquisições envolvem uma empresa comprando outra. Ambas são estratégias de crescimento, diversificação ou obtenção de vantagens competitivas.","pt_PT":"As fusões combinam duas empresas numa só; as aquisições envolvem uma empresa a comprar outra. Ambas são estratégias de crescimento, diversificação ou obtenção de vantagens competitivas."}},
  { id: 'dc-business-0085', deck_id: 'deck-business', front: 'Due Diligence', back: 'The comprehensive appraisal of a business undertaken before a merger, acquisition, or investment. It assesses financial, legal, operational, and strategic risks.', sort_order: 85 , front_translations: {"es":"Diligencia prévia (Due Diligence)","de":"Due Diligence","fr":"Diligence raisonnable (Due Diligence)","tr":"Durum Tespiti (Due Diligence)","nl":"Due diligence","ru":"Должная осмотрительность (Due Diligence)","zh":"尽职调查（Due Diligence）","pt_BR":"Diligência prévia (Due Diligence)","pt_PT":"Diligência prévia (Due Diligence)"}, back_translations: {"es":"La análise abrangente de una empresa realizada antes de una fusión, adquisición o inversión. Avalia riesgos financeros, legais, operacionais y estratégicos.","de":"Die umfassende Prüfung eines Unternehmens vor einer Fusion, Übernahme oder Investition. Sie bewertet finanzielle, rechtliche, operative und strategische Risiken.","fr":"L'évaluation approfondie d'une entreprise réalisée avant une fusion, acquisition ou investissement. Elle examine les risques financiers, juridiques, opérationnels et stratégiques.","tr":"Bir birleşme, satın alma veya yatırım öncesinde bir işletmenin kapsamlı biçimde incelenmesidir. Finansal, hukuki, operasyonel ve stratejik riskler değerlendirilir.","nl":"Het uitgebreide onderzoek naar een bedrijf vóór een fusie, overname of investering. Het beoordeelt financiële, juridische, operationele en strategische risico's.","ru":"Всестороннее изучение компании перед слиянием, поглощением или инвестированием. Охватывает финансовые, правовые, операционные и стратегические риски.","zh":"在并购或投资前对企业进行的全面审查，评估财务、法律、运营和战略风险。","pt_BR":"A análise abrangente de uma empresa realizada antes de uma fusão, aquisição ou investimento. Avalia riscos financeiros, legais, operacionais e estratégicos.","pt_PT":"A avaliação abrangente de uma empresa realizada antes de uma fusão, aquisição ou investimento. Avalia riscos financeiros, jurídicos, operacionais e estratégicos."}},
  { id: 'dc-business-0086', deck_id: 'deck-business', front: 'Hostile Takeover', back: 'An acquisition of a company against the wishes of its board and management, typically by purchasing shares directly from shareholders or through a tender offer.', sort_order: 86 , front_translations: {"es":"Aquisición hostil","de":"Feindliche Übernahme","fr":"OPA hostile","tr":"Düşmanca Ele Geçirme","nl":"Vijandige overname","ru":"Враждебное поглощение","zh":"恶意收购","pt_BR":"Aquisição hostil","pt_PT":"Aquisição hostil"}, back_translations: {"es":"La adquisición de una empresa contra a vontade de su conselho y gestión, generalmente comprando acciones directamente de los accionistas o por medio de una oferta pública de adquisición.","de":"Der Erwerb eines Unternehmens gegen den Willen seines Vorstands und seiner Geschäftsführung, typischerweise durch den direkten Kauf von Aktien bei Aktionären oder durch ein öffentliches Übernahmeangebot.","fr":"L'acquisition d'une entreprise contre la volonté de son conseil d'administration et de sa direction, généralement en achetant des actions directement auprès des actionnaires ou via une offre publique d'achat.","tr":"Bir şirketin yönetim kurulu ve yönetiminin isteğine karşın, genellikle doğrudan hissedarlardan hisse satın alarak veya bir hisse teklifi aracılığıyla gerçekleştirilen satın alma işlemi.","nl":"De overname van een bedrijf tegen de wil van zijn bestuur en management, doorgaans door aandelen rechtstreeks van aandeelhouders te kopen of via een openbaar overnamebod.","ru":"Приобретение компании вопреки воле её совета директоров и менеджмента, как правило, путём скупки акций напрямую у акционеров или через тендерное предложение.","zh":"在目标公司董事会和管理层意愿相反的情况下进行的收购，通常通过直接从股东购买股票或发出要约收购来实现。","pt_BR":"A aquisição de uma empresa contra a vontade de seu conselho e gestão, geralmente comprando ações diretamente dos acionistas ou por meio de uma oferta pública de aquisição.","pt_PT":"A aquisição de uma empresa contra a vontade do seu conselho de administração e gestão, geralmente através da compra de ações diretamente aos acionistas ou por meio de uma oferta pública de aquisição."}},
  { id: 'dc-business-0087', deck_id: 'deck-business', front: 'Private Equity (PE)', back: 'Investment funds that buy and restructure private companies or take public companies private; they typically use leveraged buyouts and aim to sell for a profit after several years.', sort_order: 87 , front_translations: {"es":"Private equity (PE)","de":"Private Equity (PE)","fr":"Capital-investissement (Private Equity)","tr":"Özel Sermaye (Private Equity)","nl":"Private equity (PE)","ru":"Прямые инвестиции (Private Equity)","zh":"私募股权（PE）","pt_BR":"Private equity (PE)","pt_PT":"Capital de risco privado (Private Equity)"}, back_translations: {"es":"Fundos de inversión que compram y reestruturem empresas privadas o retiram empresas públicas de la bolsa; generalmente usam aquisiciones alavancadas y buscam vender con ganancia após algunos anos.","de":"Investmentfonds, die private Unternehmen kaufen und restrukturieren oder börsennotierte Unternehmen von der Börse nehmen; sie nutzen typischerweise fremdfinanzierte Übernahmen und zielen darauf ab, nach einigen Jahren mit Gewinn zu verkaufen.","fr":"Fonds d'investissement qui achètent et restructurent des entreprises privées ou retirent des sociétés cotées de la bourse ; ils ont généralement recours aux rachats par effet de levier et visent à revendre avec profit après plusieurs années.","tr":"Özel şirketleri satın alıp yeniden yapılandıran veya halka açık şirketleri piyasadan çeken yatırım fonları; genellikle kaldıraçlı satın almalar kullanır ve birkaç yıl içinde kârlı şekilde satmayı hedefler.","nl":"Investeringsfondsen die private bedrijven kopen en herstructureren of beursgenoteerde bedrijven van de beurs halen; ze maken doorgaans gebruik van leveraged buyouts en willen na enkele jaren met winst verkopen.","ru":"Инвестиционные фонды, которые приобретают и реструктурируют частные компании или делают публичные компании непубличными; как правило, используют выкупы с долговым финансированием и стремятся продать с прибылью через несколько лет.","zh":"通过收购并重组私营公司或将上市公司私有化的投资基金，通常采用杠杆收购策略，目标是在数年后盈利退出。","pt_BR":"Fundos de investimento que compram e reestruturem empresas privadas ou retiram empresas públicas da bolsa; geralmente usam aquisições alavancadas e buscam vender com lucro após alguns anos.","pt_PT":"Fundos de investimento que compram e reestruturem empresas privadas ou retiram empresas cotadas da bolsa; geralmente recorrem a aquisições alavancadas e pretendem vender com lucro ao fim de alguns anos."}},
  { id: 'dc-business-0088', deck_id: 'deck-business', front: 'Leveraged Buyout (LBO)', back: 'The acquisition of a company using a significant amount of borrowed money, with the acquired company\'s assets often used as collateral; a key strategy of private equity firms.', sort_order: 88 , front_translations: {"es":"Aquisición alavancada (LBO)","de":"Leveraged Buyout (LBO)","fr":"Rachat par effet de levier (LBO)","tr":"Kaldıraçlı Satın Alma (LBO)","nl":"Leveraged buyout (LBO)","ru":"Выкуп с привлечением заёмных средств (LBO)","zh":"杠杆收购（LBO）","pt_BR":"Aquisição alavancada (LBO)","pt_PT":"Aquisição alavancada (LBO)"}, back_translations: {"es":"La adquisición de una empresa usando una cantidad significativa de dinhero emprestado, con los ativos de la empresa adquirida frecuentemente usados como garantia; una estrategia fundamental de las firmas de private equity.","de":"Die Übernahme eines Unternehmens unter Einsatz eines erheblichen Anteils geliehener Mittel, wobei die Vermögenswerte des erworbenen Unternehmens oft als Sicherheit dienen; eine Kernstrategie von Private-Equity-Unternehmen.","fr":"L'acquisition d'une entreprise en utilisant une part importante de capitaux empruntés, les actifs de la société acquise servant souvent de garantie ; une stratégie clé des fonds de capital-investissement.","tr":"Önemli miktarda borç para kullanılarak gerçekleştirilen şirket satın alımı; satın alınan şirketin varlıkları genellikle teminat olarak kullanılır. Özel sermaye firmalarının temel bir stratejisidir.","nl":"De overname van een bedrijf met behulp van een aanzienlijk bedrag aan geleend geld, waarbij de activa van het overgenomen bedrijf vaak als onderpand dienen; een kernstrategie van private-equityfirma's.","ru":"Приобретение компании с использованием значительного объёма заёмного капитала, при этом активы приобретаемой компании нередко служат залогом; ключевая стратегия фондов прямых инвестиций.","zh":"以大量借贷资金收购公司，被收购公司的资产通常作为抵押品；这是私募股权公司的核心策略。","pt_BR":"A aquisição de uma empresa usando uma quantidade significativa de dinheiro emprestado, com os ativos da empresa adquirida frequentemente usados como garantia; uma estratégia fundamental das firmas de private equity.","pt_PT":"A aquisição de uma empresa utilizando uma quantidade significativa de capital emprestado, sendo os ativos da empresa adquirida frequentemente usados como garantia; uma estratégia fundamental das firmas de private equity."}},
  { id: 'dc-business-0089', deck_id: 'deck-business', front: 'Hedge Fund', back: 'A pooled investment fund using diverse strategies — including leverage, short-selling, and derivatives — to generate returns regardless of market direction.', sort_order: 89 , front_translations: {"es":"Fundo de hedge (Hedge Fund)","de":"Hedgefonds","fr":"Fonds spéculatif (Hedge Fund)","tr":"Hedge Fonu","nl":"Hedgefonds","ru":"Хедж-фонд","zh":"对冲基金","pt_BR":"Fundo de hedge (Hedge Fund)","pt_PT":"Fundo de cobertura (Hedge Fund)"}, back_translations: {"es":"Un fundo de inversión coletivo que utiliza estrategias diversas — incluyendo alavancaje, venta a descoberto y derivativos — para gerar retornos independentemente de la dirección del mercado.","de":"Ein gepoolter Investmentfonds, der verschiedene Strategien einsetzt – darunter Hebelwirkung, Leerverkäufe und Derivate –, um unabhängig von der Marktrichtung Renditen zu erzielen.","fr":"Un fonds d'investissement collectif utilisant des stratégies diverses — dont l'effet de levier, la vente à découvert et les produits dérivés — pour générer des rendements quelle que soit la direction du marché.","tr":"Piyasa yönünden bağımsız getiri elde etmek amacıyla kaldıraç, açığa satış ve türev ürünler dahil çeşitli stratejiler kullanan havuzlanmış bir yatırım fonudur.","nl":"Een collectief beleggingsfonds dat diverse strategieën gebruikt — waaronder hefboom, short selling en derivaten — om rendementen te genereren ongeacht de marktrichting.","ru":"Объединённый инвестиционный фонд, использующий разнообразные стратегии — в том числе кредитное плечо, короткие продажи и деривативы — для получения дохода независимо от направления рынка.","zh":"一种集合投资基金，采用多种策略——包括杠杆、卖空和衍生品——无论市场走势如何都力求获得回报。","pt_BR":"Um fundo de investimento coletivo que utiliza estratégias diversas — incluindo alavancagem, venda a descoberto e derivativos — para gerar retornos independentemente da direção do mercado.","pt_PT":"Um fundo de investimento coletivo que utiliza estratégias diversas — incluindo alavancagem, venda a descoberto e derivados — para gerar retornos independentemente da direção do mercado."}},
  { id: 'dc-business-0090', deck_id: 'deck-business', front: 'Derivatives', back: 'Financial contracts whose value is derived from an underlying asset (stock, bond, commodity, currency). Common types include options, futures, and swaps.', sort_order: 90 , front_translations: {"es":"Derivativos","de":"Derivate","fr":"Produits dérivés","tr":"Türev Ürünler","nl":"Derivaten","ru":"Производные финансовые инструменты (деривативы)","zh":"衍生品","pt_BR":"Derivativos","pt_PT":"Derivados"}, back_translations: {"es":"Contratos financeros cujo valor es derivado de un ativo subjacente (acción, título, commodity, moeda). Los tipos más comuns incluyen opciones, futuros y swaps.","de":"Finanzkontrakte, deren Wert von einem Basiswert (Aktie, Anleihe, Rohstoff, Währung) abgeleitet wird. Zu den gängigen Typen gehören Optionen, Futures und Swaps.","fr":"Contrats financiers dont la valeur est dérivée d'un actif sous-jacent (action, obligation, matière première, devise). Les types courants comprennent les options, les contrats à terme et les swaps.","tr":"Değeri bir dayanak varlıktan (hisse senedi, tahvil, emtia, döviz) türetilen finansal sözleşmeler. Yaygın türleri arasında opsiyonlar, vadeli işlem sözleşmeleri ve swap'lar yer alır.","nl":"Financiële contracten waarvan de waarde is afgeleid van een onderliggend actief (aandeel, obligatie, grondstof, valuta). Veelvoorkomende typen zijn opties, futures en swaps.","ru":"Финансовые контракты, стоимость которых определяется базовым активом (акцией, облигацией, сырьевым товаром, валютой). К распространённым видам относятся опционы, фьючерсы и свопы.","zh":"价值来源于基础资产（股票、债券、大宗商品、货币）的金融合约。常见类型包括期权、期货和互换。","pt_BR":"Contratos financeiros cujo valor é derivado de um ativo subjacente (ação, título, commodity, moeda). Os tipos mais comuns incluem opções, futuros e swaps.","pt_PT":"Contratos financeiros cujo valor é derivado de um ativo subjacente (ação, obrigação, matéria-prima, moeda). Os tipos mais comuns incluem opções, futuros e swaps."}},
  { id: 'dc-business-0091', deck_id: 'deck-business', front: 'Options Contract', back: 'A derivative giving the buyer the right, but not the obligation, to buy (call) or sell (put) an asset at a specified price before or at a specified expiration date.', sort_order: 91 , front_translations: {"es":"Contrato de opción","de":"Optionskontrakt","fr":"Contrat d'option","tr":"Opsiyon Sözleşmesi","nl":"Optiecontract","ru":"Опционный контракт","zh":"期权合约","pt_BR":"Contrato de opção","pt_PT":"Contrato de opção"}, back_translations: {"es":"Un derivativo que dá al comprador el derecho, pero no a obrigación, de comprar (call) o vender (put) un ativo a un precio especificado antes o en la data de vencimento.","de":"Ein Derivat, das dem Käufer das Recht, aber nicht die Pflicht einräumt, einen Vermögenswert zu einem festgelegten Preis vor oder am Verfallsdatum zu kaufen (Call) oder zu verkaufen (Put).","fr":"Un produit dérivé donnant à l'acheteur le droit, mais non l'obligation, d'acheter (call) ou de vendre (put) un actif à un prix défini avant ou à une date d'échéance précisée.","tr":"Alıcıya belirli bir varlığı, belirli bir fiyattan, belirli bir vadeye kadar veya vadede satın alma (alım opsiyonu) ya da satma (satım opsiyonu) hakkını veren, ancak zorunluluk getirmeyen bir türev araç.","nl":"Een derivaat dat de koper het recht, maar niet de verplichting geeft, om een actief te kopen (call) of te verkopen (put) tegen een bepaalde prijs vóór of op een bepaalde vervaldatum.","ru":"Производный инструмент, дающий покупателю право, но не обязательство, купить (колл) или продать (пут) актив по установленной цене до или на дату истечения срока.","zh":"一种衍生品，赋予买方在特定到期日前或到期日以规定价格购买（看涨期权）或出售（看跌期权）资产的权利，但无义务。","pt_BR":"Um derivativo que dá ao comprador o direito, mas não a obrigação, de comprar (call) ou vender (put) um ativo a um preço especificado antes ou na data de vencimento.","pt_PT":"Um derivado que dá ao comprador o direito, mas não a obrigação, de comprar (call) ou vender (put) um ativo a um preço especificado antes ou na data de vencimento."}},
  { id: 'dc-business-0092', deck_id: 'deck-business', front: 'Futures Contract', back: 'An agreement to buy or sell an asset at a predetermined price at a specified future date; unlike options, both parties are obligated to complete the transaction.', sort_order: 92 , front_translations: {"es":"Contrato futuro (Futures)","de":"Terminkontrakt (Futures)","fr":"Contrat à terme (Futures)","tr":"Vadeli İşlem Sözleşmesi (Futures)","nl":"Termijncontract (Futures)","ru":"Фьючерсный контракт","zh":"期货合约","pt_BR":"Contrato futuro (Futures)","pt_PT":"Contrato de futuros"}, back_translations: {"es":"Un acuerdo para comprar o vender un ativo a un precio predeterminado en una data futura especificada; al contrário de las opciones, ambas las partes son obrigadas a concluir a transación.","de":"Eine Vereinbarung, einen Vermögenswert zu einem vorher festgelegten Preis zu einem zukünftigen Datum zu kaufen oder zu verkaufen; im Gegensatz zu Optionen sind beide Parteien zur Erfüllung des Geschäfts verpflichtet.","fr":"Un accord d'achat ou de vente d'un actif à un prix prédéterminé à une date future spécifiée ; contrairement aux options, les deux parties sont obligées de réaliser la transaction.","tr":"Belirli bir varlığı, belirli bir gelecek tarihte, önceden belirlenmiş bir fiyattan alıp satmayı taahhüt eden anlaşma; opsiyonların aksine her iki taraf da işlemi tamamlamakla yükümlüdür.","nl":"Een overeenkomst om een actief te kopen of verkopen tegen een vooraf bepaalde prijs op een specifieke toekomstige datum; in tegenstelling tot opties zijn beide partijen verplicht de transactie te voltooien.","ru":"Соглашение о покупке или продаже актива по заранее определённой цене в указанную будущую дату; в отличие от опционов, обе стороны обязаны исполнить сделку.","zh":"一种在指定未来日期以预定价格买卖资产的协议；与期权不同，双方均有义务完成交易。","pt_BR":"Um acordo para comprar ou vender um ativo a um preço predeterminado em uma data futura especificada; ao contrário das opções, ambas as partes são obrigadas a concluir a transação.","pt_PT":"Um acordo para comprar ou vender um ativo a um preço predeterminado numa data futura especificada; ao contrário das opções, ambas as partes são obrigadas a concluir a transação."}},
  { id: 'dc-business-0093', deck_id: 'deck-business', front: 'Short Selling', back: 'Borrowing and selling a security with the expectation its price will fall, then buying it back at a lower price to return it and profit from the difference.', sort_order: 93 , front_translations: {"es":"Venda a descoberto (Short Selling)","de":"Leerverkauf (Short Selling)","fr":"Vente à découvert (Short Selling)","tr":"Açığa Satış (Short Selling)","nl":"Short selling","ru":"Короткая продажа (Short Selling)","zh":"卖空（Short Selling）","pt_BR":"Venda a descoberto (Short Selling)","pt_PT":"Venda a descoberto (Short Selling)"}, back_translations: {"es":"Tomar emprestado y vender un título en la expectativa de que su precio caia, después comprá-lo de volta a un precio menor para devolve-lo y lucrar con a diferencia.","de":"Das Ausleihen und Verkaufen eines Wertpapiers in der Erwartung, dass sein Kurs fällt, um es anschließend zu einem niedrigeren Preis zurückzukaufen und die Differenz als Gewinn einzustreichen.","fr":"Emprunter et vendre un titre en anticipant une baisse de son cours, puis le racheter à un prix inférieur pour le rendre et encaisser la différence comme profit.","tr":"Fiyatının düşeceği beklentisiyle bir menkul kıymeti ödünç alıp satmak, ardından daha düşük bir fiyattan geri satın alarak iade etmek ve farkı kâr olarak elde etmek.","nl":"Het lenen en verkopen van een effect in de verwachting dat de prijs zal dalen, om het vervolgens tegen een lagere prijs terug te kopen, terug te geven en het verschil als winst te boeken.","ru":"Заимствование и продажа ценной бумаги в расчёте на падение её цены, с последующим выкупом по более низкой цене для возврата и получения прибыли от разницы.","zh":"借入并卖出某证券，预期其价格将下跌，随后以更低价格买回归还，从差价中获利。","pt_BR":"Tomar emprestado e vender um título na expectativa de que seu preço caia, depois comprá-lo de volta a um preço menor para devolvê-lo e lucrar com a diferença.","pt_PT":"Pedir emprestado e vender um título na expectativa de que o seu preço caia, comprá-lo de volta a um preço mais baixo para o devolver e lucrar com a diferença."}},
  { id: 'dc-business-0094', deck_id: 'deck-business', front: 'Diversification', back: 'A risk management strategy that mixes a variety of investments in a portfolio to reduce exposure to any single asset or risk; "don\'t put all your eggs in one basket."', sort_order: 94 , front_translations: {"es":"Diversificación","de":"Diversifikation","fr":"Diversification","tr":"Çeşitlendirme (Diversifikasyon)","nl":"Diversificatie","ru":"Диверсификация","zh":"多元化","pt_BR":"Diversificação","pt_PT":"Diversificação"}, back_translations: {"es":"Una estrategia de gestión de riesgo que combina una variedad de inversiones en un portfólio para reduzir a exposición a cualquier ativo o riesgo único; \"no coloque todos los ovos en la misma cesta.\"","de":"Eine Risikomanagementstrategie, die eine Vielzahl von Anlagen in einem Portfolio mischt, um die Exposition gegenüber einem einzelnen Vermögenswert oder Risiko zu reduzieren; \"Lege nicht alle Eier in einen Korb.\"","fr":"Une stratégie de gestion des risques qui mélange divers investissements dans un portefeuille pour réduire l'exposition à un seul actif ou risque ; \"ne pas mettre tous ses œufs dans le même panier.\"","tr":"Tek bir varlık veya riske maruziyeti azaltmak amacıyla portföye çeşitli yatırımları dahil eden bir risk yönetimi stratejisi; \"tüm yumurtaları aynı sepete koymamak.\"","nl":"Een risicobeheersstrategie die een variëteit aan beleggingen in een portefeuille combineert om de blootstelling aan een enkel actief of risico te verminderen; \"leg niet alle eieren in één mand.\"","ru":"Стратегия управления рисками, предполагающая включение в портфель различных активов для снижения зависимости от одного актива или риска; \"не кладите все яйца в одну корзину.\"","zh":"一种风险管理策略，通过在投资组合中混合多种投资来降低对任何单一资产或风险的敞口；即\"不要把所有鸡蛋放在一个篮子里\"。","pt_BR":"Uma estratégia de gestão de risco que combina uma variedade de investimentos em um portfólio para reduzir a exposição a qualquer ativo ou risco único; \"não coloque todos os ovos na mesma cesta.\"","pt_PT":"Uma estratégia de gestão de risco que combina uma variedade de investimentos numa carteira para reduzir a exposição a qualquer ativo ou risco único; \"não coloque todos os ovos no mesmo cesto.\""}},
  { id: 'dc-business-0095', deck_id: 'deck-business', front: 'Asset Allocation', back: 'The process of distributing investments among different asset categories (stocks, bonds, real estate, cash) according to an investor\'s goals, risk tolerance, and time horizon.', sort_order: 95 , front_translations: {"es":"Alocación de ativos","de":"Asset Allocation","fr":"Allocation d'actifs","tr":"Varlık Dağılımı (Asset Allocation)","nl":"Activaspreiding (Asset Allocation)","ru":"Распределение активов (Asset Allocation)","zh":"资产配置","pt_BR":"Alocação de ativos","pt_PT":"Alocação de ativos"}, back_translations: {"es":"El proceso de distribuir inversiones entre diferentes categorias de ativos (acciones, títulos, imóveis, dinhero) de acuerdo con los objetivos, tolerancia al riesgo y horizonte de tiempo del investidor.","de":"Der Prozess der Verteilung von Anlagen auf verschiedene Anlagekategorien (Aktien, Anleihen, Immobilien, Bargeld) entsprechend den Zielen, der Risikobereitschaft und dem Zeithorizont eines Investors.","fr":"Le processus de répartition des investissements entre différentes catégories d'actifs (actions, obligations, immobilier, liquidités) en fonction des objectifs, de la tolérance au risque et de l'horizon temporel d'un investisseur.","tr":"Yatırımcının hedeflerine, risk toleransına ve zaman ufkuna göre yatırımları farklı varlık kategorileri (hisse senetleri, tahviller, gayrimenkul, nakit) arasında dağıtma süreci.","nl":"Het proces van het verdelen van beleggingen over verschillende activacategorieën (aandelen, obligaties, onroerend goed, contanten) op basis van de doelen, risicobereidheid en tijdshorizon van een belegger.","ru":"Процесс размещения инвестиций по различным классам активов (акции, облигации, недвижимость, денежные средства) в соответствии с целями, склонностью к риску и временным горизонтом инвестора.","zh":"根据投资者的目标、风险承受能力和时间跨度，将投资分配到不同资产类别（股票、债券、房地产、现金）的过程。","pt_BR":"O processo de distribuir investimentos entre diferentes categorias de ativos (ações, títulos, imóveis, dinheiro) de acordo com os objetivos, tolerância ao risco e horizonte de tempo do investidor.","pt_PT":"O processo de distribuir investimentos entre diferentes categorias de ativos (ações, obrigações, imóveis, dinheiro) de acordo com os objetivos, tolerância ao risco e horizonte temporal do investidor."}},
  { id: 'dc-business-0096', deck_id: 'deck-business', front: 'Bull Market', back: 'A financial market characterized by rising asset prices, typically defined as a 20% or more rise from recent lows; associated with investor confidence and economic expansion.', sort_order: 96 , front_translations: {"es":"Mercado en alta (Bull Market)","de":"Bullenmarkt","fr":"Marché haussier (Bull Market)","tr":"Boğa Piyasası","nl":"Bullmarkt","ru":"Бычий рынок","zh":"牛市","pt_BR":"Mercado em alta (Bull Market)","pt_PT":"Mercado em alta (Bull Market)"}, back_translations: {"es":"Un mercado financiero caracterizado por la alta de los precios de los ativos, generalmente definido como una alta de 20% o más en relación a las mínimas recentes; associado a la confiança de los investidores y a la expansão económica.","de":"Ein Finanzmarkt, der durch steigende Vermögenspreise gekennzeichnet ist, typischerweise definiert als ein Anstieg von 20 % oder mehr gegenüber einem jüngsten Tiefstand; verbunden mit Anlegervertrauen und wirtschaftlicher Expansion.","fr":"Un marché financier caractérisé par la hausse des prix des actifs, généralement défini comme une hausse de 20 % ou plus par rapport aux récents points bas ; associé à la confiance des investisseurs et à l'expansion économique.","tr":"Varlık fiyatlarının yükselişiyle karakterize edilen bir finans piyasası; genellikle son düşük noktalardan %20 veya daha fazla artış olarak tanımlanır. Yatırımcı güveni ve ekonomik genişlemeyle ilişkilidir.","nl":"Een financiële markt gekenmerkt door stijgende activaprijzen, doorgaans gedefinieerd als een stijging van 20% of meer ten opzichte van recente dieptepunten; geassocieerd met beleggersvertrouwen en economische expansie.","ru":"Финансовый рынок, характеризующийся ростом цен на активы, как правило, на 20% и более от недавних минимумов; ассоциируется с уверенностью инвесторов и экономическим ростом.","zh":"以资产价格上涨为特征的金融市场，通常定义为从近期低点上涨20%或以上；与投资者信心增强和经济扩张相关。","pt_BR":"Um mercado financeiro caracterizado pela alta dos preços dos ativos, geralmente definido como uma alta de 20% ou mais em relação às mínimas recentes; associado à confiança dos investidores e à expansão econômica.","pt_PT":"Um mercado financeiro caracterizado pela subida dos preços dos ativos, geralmente definido como uma subida de 20% ou mais em relação às mínimas recentes; associado à confiança dos investidores e à expansão económica."}},
  { id: 'dc-business-0097', deck_id: 'deck-business', front: 'Bear Market', back: 'A financial market experiencing prolonged price declines, typically defined as a 20% or more drop from recent highs; associated with pessimism and economic contraction.', sort_order: 97 , front_translations: {"es":"Mercado en baja (Bear Market)","de":"Bärenmarkt","fr":"Marché baissier (Bear Market)","tr":"Ayı Piyasası","nl":"Bearmarkt","ru":"Медвежий рынок","zh":"熊市","pt_BR":"Mercado em baixa (Bear Market)","pt_PT":"Mercado em baixa (Bear Market)"}, back_translations: {"es":"Un mercado financiero con caídas prolongadas de precios, generalmente definido como una caída de 20% o más en relación a las máximas recentes; associado al pessimismo y a la contración económica.","de":"Ein Finanzmarkt mit anhaltenden Kursrückgängen, typischerweise definiert als ein Rückgang von 20 % oder mehr gegenüber einem jüngsten Hochstand; verbunden mit Pessimismus und wirtschaftlicher Kontraktion.","fr":"Un marché financier connaissant une baisse prolongée des prix, généralement défini comme une chute de 20 % ou plus par rapport aux récents sommets ; associé au pessimisme et à la contraction économique.","tr":"Uzun süreli fiyat düşüşleri yaşayan bir finans piyasası; genellikle son yüksek noktalardan %20 veya daha fazla düşüş olarak tanımlanır. Kötümserlik ve ekonomik daralmayla ilişkilidir.","nl":"Een financiële markt die aanhoudende prijsdalingen ervaart, doorgaans gedefinieerd als een daling van 20% of meer ten opzichte van recente hoogtepunten; geassocieerd met pessimisme en economische krimp.","ru":"Финансовый рынок с устойчивым снижением цен, как правило, на 20% и более от недавних максимумов; ассоциируется с пессимизмом и экономическим спадом.","zh":"经历持续价格下跌的金融市场，通常定义为从近期高点下跌20%或以上；与悲观情绪和经济收缩相关。","pt_BR":"Um mercado financeiro com quedas prolongadas de preços, geralmente definido como uma queda de 20% ou mais em relação às máximas recentes; associado ao pessimismo e à contração econômica.","pt_PT":"Um mercado financeiro com quedas prolongadas de preços, geralmente definido como uma queda de 20% ou mais em relação às máximas recentes; associado ao pessimismo e à contração económica."}},
  { id: 'dc-business-0098', deck_id: 'deck-business', front: 'Recession', back: 'A significant decline in economic activity lasting more than a few months, visible in GDP, employment, and production; technically defined as two consecutive quarters of negative GDP growth.', sort_order: 98 , front_translations: {"es":"Recesión","de":"Rezession","fr":"Récession","tr":"Resesyon","nl":"Recessie","ru":"Рецессия","zh":"经济衰退","pt_BR":"Recessão","pt_PT":"Recessão"}, back_translations: {"es":"Un declínio significativo en la atividad económica con duración superior a algunos meses, visible en el PIB, emprego y producción; tecnicamente definida como de los trimestres consecutivos de crecimiento negativo del PIB.","de":"Ein erheblicher Rückgang der Wirtschaftstätigkeit, der mehr als wenige Monate anhält und in BIP, Beschäftigung und Produktion sichtbar ist; technisch definiert als zwei aufeinanderfolgende Quartale mit negativem BIP-Wachstum.","fr":"Un recul significatif de l'activité économique durant plus de quelques mois, visible dans le PIB, l'emploi et la production ; techniquement définie comme deux trimestres consécutifs de croissance négative du PIB.","tr":"GSYİH, istihdam ve üretimde görülen, birkaç aydan uzun süren önemli ekonomik daralma; teknik olarak ardı ardına iki çeyrek dönem negatif GSYİH büyümesi olarak tanımlanır.","nl":"Een aanzienlijke daling van economische activiteit die meer dan een paar maanden aanhoudt en zichtbaar is in bbp, werkgelegenheid en productie; technisch gedefinieerd als twee opeenvolgende kwartalen van negatieve bbp-groei.","ru":"Значительный спад экономической активности, продолжающийся более нескольких месяцев и проявляющийся в ВВП, занятости и производстве; технически определяется как два последовательных квартала отрицательного роста ВВП.","zh":"经济活动的显著下滑，持续超过数月，体现在GDP、就业和生产方面；技术上定义为连续两个季度GDP负增长。","pt_BR":"Um declínio significativo na atividade econômica com duração superior a alguns meses, visível no PIB, emprego e produção; tecnicamente definida como dois trimestres consecutivos de crescimento negativo do PIB.","pt_PT":"Um declínio significativo na atividade económica com duração superior a alguns meses, visível no PIB, emprego e produção; tecnicamente definida como dois trimestres consecutivos de crescimento negativo do PIB."}},
  { id: 'dc-business-0099', deck_id: 'deck-business', front: 'Fiscal Policy', back: 'Government use of taxation and spending to influence the economy. Expansionary fiscal policy (lower taxes, more spending) stimulates growth; contractionary policy slows inflation.', sort_order: 99 , front_translations: {"es":"Política fiscal","de":"Fiskalpolitik","fr":"Politique budgétaire","tr":"Mali Politika (Fiskal Politika)","nl":"Begrotingsbeleid (Fiscaal beleid)","ru":"Фискальная политика","zh":"财政政策","pt_BR":"Política fiscal","pt_PT":"Política fiscal"}, back_translations: {"es":"El uso del gobierno de tributación y gastos para influenciar a economía. La política fiscal expansionista (impuestos más baixos, más gastos) estimula el crecimiento; a política contracionista desacelera a inflación.","de":"Der staatliche Einsatz von Steuern und Ausgaben zur Beeinflussung der Wirtschaft. Eine expansive Fiskalpolitik (niedrigere Steuern, höhere Ausgaben) regt das Wachstum an; eine kontraktive Politik verlangsamt die Inflation.","fr":"L'utilisation par l'État de la fiscalité et des dépenses pour influencer l'économie. Une politique budgétaire expansionniste (réduction d'impôts, augmentation des dépenses) stimule la croissance ; une politique restrictive ralentit l'inflation.","tr":"Hükümetin ekonomiyi etkilemek için vergilendirme ve harcama araçlarını kullanması. Genişletici mali politika (düşük vergiler, artan harcamalar) büyümeyi canlandırır; daraltıcı politika enflasyonu yavaşlatır.","nl":"Overheidsgebruik van belastingen en uitgaven om de economie te beïnvloeden. Expansief fiscaal beleid (lagere belastingen, meer uitgaven) stimuleert groei; restrictief beleid remt inflatie.","ru":"Использование правительством налогообложения и расходов для воздействия на экономику. Мягкая фискальная политика (снижение налогов, рост расходов) стимулирует рост; жёсткая — сдерживает инфляцию.","zh":"政府通过税收和支出来影响经济的手段。扩张性财政政策（降税、增加支出）刺激增长；紧缩性政策抑制通胀。","pt_BR":"O uso do governo de tributação e gastos para influenciar a economia. A política fiscal expansionista (impostos mais baixos, mais gastos) estimula o crescimento; a política contracionista desacelera a inflação.","pt_PT":"A utilização pelo governo de tributação e despesa para influenciar a economia. A política fiscal expansionista (impostos mais baixos, mais despesa) estimula o crescimento; a política contracionista abranda a inflação."}},
  { id: 'dc-business-0100', deck_id: 'deck-business', front: 'Monetary Policy', back: 'Central bank actions managing money supply and interest rates to achieve economic goals. Expansionary policy (low rates) boosts growth; contractionary policy (high rates) fights inflation.', sort_order: 100 , front_translations: {"es":"Política monetária","de":"Geldpolitik","fr":"Politique monétaire","tr":"Para Politikası","nl":"Monetair beleid","ru":"Денежно-кредитная политика","zh":"货币政策","pt_BR":"Política monetária","pt_PT":"Política monetária"}, back_translations: {"es":"Aciones del base central para gerenciar a oferta de moeda y las taxas de juros con el fin de atingir metas económicas. La política expansionista (taxas baixas) impulsiona el crecimiento; a política contracionista (taxas altas) combate a inflación.","de":"Maßnahmen der Zentralbank zur Steuerung von Geldmenge und Zinssätzen zur Erreichung wirtschaftlicher Ziele. Eine expansive Politik (niedrige Zinsen) fördert Wachstum; eine kontraktive Politik (hohe Zinsen) bekämpft Inflation.","fr":"Actions de la banque centrale gérant la masse monétaire et les taux d'intérêt pour atteindre des objectifs économiques. Une politique expansionniste (taux bas) stimule la croissance ; une politique restrictive (taux élevés) lutte contre l'inflation.","tr":"Ekonomik hedeflere ulaşmak için merkez bankasının para arzını ve faiz oranlarını yönettiği eylemler. Genişletici politika (düşük faiz) büyümeyi artırır; daraltıcı politika (yüksek faiz) enflasyonla mücadele eder.","nl":"Centrale bankacties voor het beheer van de geldvoorraad en rentetarieven om economische doelen te bereiken. Expansief beleid (lage rente) stimuleert groei; restrictief beleid (hoge rente) bestrijdt inflatie.","ru":"Действия центрального банка по управлению денежной массой и процентными ставками для достижения экономических целей. Мягкая политика (низкие ставки) стимулирует рост; жёсткая (высокие ставки) борется с инфляцией.","zh":"中央银行通过管理货币供应和利率来实现经济目标的行动。宽松政策（低利率）促进增长；紧缩政策（高利率）抑制通胀。","pt_BR":"Ações do banco central para gerenciar a oferta de moeda e as taxas de juros a fim de atingir metas econômicas. A política expansionista (taxas baixas) impulsiona o crescimento; a política contracionista (taxas altas) combate a inflação.","pt_PT":"Ações do banco central para gerir a oferta de moeda e as taxas de juro para atingir objetivos económicos. A política expansionista (taxas baixas) impulsiona o crescimento; a política contracionista (taxas altas) combate a inflação."}},
  { id: 'dc-business-0101', deck_id: 'deck-business', front: 'Quantitative Easing (QE)', back: 'A monetary policy where a central bank buys government bonds or other securities to inject money into the economy and lower long-term interest rates.', sort_order: 101 , front_translations: {"es":"Flexibilización Quantitativa (QE)","de":"Quantitative Lockerung (QE)","fr":"Assouplissement quantitatif (QE)","tr":"Niceliksel Genişleme (QE)","nl":"Kwantitatieve versoepeling (QE)","ru":"Количественное смягчение (QE)","zh":"量化宽松（QE）","pt_BR":"Flexibilização Quantitativa (QE)","pt_PT":"Flexibilização Quantitativa (QE)"}, back_translations: {"es":"Una política monetária en la qual un base central compra títulos del gobierno o outros ativos para injetar dinhero en la economía y reduzir las taxas de juros de ancho prazo.","de":"Eine Geldpolitik, bei der eine Zentralbank Staatsanleihen oder andere Wertpapiere kauft, um Geld in die Wirtschaft zu pumpen und die langfristigen Zinsen zu senken.","fr":"Une politique monétaire par laquelle une banque centrale achète des obligations d'État ou d'autres titres pour injecter de l'argent dans l'économie et abaisser les taux d'intérêt à long terme.","tr":"Bir merkez bankasının ekonomiye para enjekte etmek ve uzun vadeli faiz oranlarını düşürmek amacıyla devlet tahvilleri veya diğer menkul kıymetleri satın aldığı bir para politikası.","nl":"Een monetair beleid waarbij een centrale bank staatsobligaties of andere effecten koopt om geld in de economie te injecteren en de langetermijnrente te verlagen.","ru":"Монетарная политика, при которой центральный банк покупает государственные облигации или другие ценные бумаги, чтобы вливать деньги в экономику и снижать долгосрочные процентные ставки.","zh":"一种货币政策，中央银行通过购买政府债券或其他证券向经济注入资金，从而降低长期利率。","pt_BR":"Uma política monetária na qual um banco central compra títulos do governo ou outros ativos para injetar dinheiro na economia e reduzir as taxas de juros de longo prazo.","pt_PT":"Uma política monetária em que um banco central compra obrigações do Estado ou outros títulos para injetar dinheiro na economia e baixar as taxas de juro de longo prazo."}},
  { id: 'dc-business-0102', deck_id: 'deck-business', front: 'Trade Balance', back: 'The difference between a country\'s exports and imports. A trade surplus means exports exceed imports; a trade deficit means imports exceed exports.', sort_order: 102 , front_translations: {"es":"Balança Comercial","de":"Handelsbilanz","fr":"Balance commerciale","tr":"Ticaret Dengesi","nl":"Handelsbalans","ru":"Торговый баланс","zh":"贸易差额","pt_BR":"Balança Comercial","pt_PT":"Balança Comercial"}, back_translations: {"es":"La diferencia entre las exportaciones y importaciones de un país. Un superávit comercial significa que las exportaciones superam las importaciones; un déficit comercial significa que las importaciones superam las exportaciones.","de":"Die Differenz zwischen den Exporten und Importen eines Landes. Ein Handelsüberschuss bedeutet, dass die Exporte die Importe übersteigen; ein Handelsdefizit bedeutet, dass die Importe die Exporte übersteigen.","fr":"La différence entre les exportations et les importations d'un pays. Un excédent commercial signifie que les exportations dépassent les importations ; un déficit commercial signifie que les importations dépassent les exportations.","tr":"Bir ülkenin ihracatı ile ithalatı arasındaki fark. Ticaret fazlası, ihracatın ithalatı aştığı anlamına gelir; ticaret açığı ise ithalatın ihracatı aştığı anlamına gelir.","nl":"Het verschil tussen de export en import van een land. Een handelsoverschot betekent dat de export de import overstijgt; een handelstekort betekent dat de import de export overstijgt.","ru":"Разница между экспортом и импортом страны. Торговый профицит означает, что экспорт превышает импорт; торговый дефицит означает, что импорт превышает экспорт.","zh":"一个国家出口与进口之间的差额。贸易顺差意味着出口超过进口；贸易逆差意味着进口超过出口。","pt_BR":"A diferença entre as exportações e importações de um país. Um superávit comercial significa que as exportações superam as importações; um déficit comercial significa que as importações superam as exportações.","pt_PT":"A diferença entre as exportações e importações de um país. Um superávite comercial significa que as exportações superam as importações; um défice comercial significa que as importações superam as exportações."}},
  { id: 'dc-business-0103', deck_id: 'deck-business', front: 'Exchange Rate', back: 'The rate at which one currency can be exchanged for another. Fluctuating exchange rates affect trade competitiveness, import costs, and the value of foreign investments.', sort_order: 103 , front_translations: {"es":"Taxa de Cambio","de":"Wechselkurs","fr":"Taux de change","tr":"Döviz Kuru","nl":"Wisselkoers","ru":"Обменный курс","zh":"汇率","pt_BR":"Taxa de Câmbio","pt_PT":"Taxa de Câmbio"}, back_translations: {"es":"La taxa por la qual una moeda puede ser trocada por outra. As flutuaciones en las taxas de cambio afectan a competitividad comercial, los costos de importación y el valor de los inversiones estrangeros.","de":"Der Kurs, zu dem eine Währung gegen eine andere getauscht werden kann. Schwankende Wechselkurse beeinflussen die Wettbewerbsfähigkeit im Handel, die Importkosten und den Wert ausländischer Investitionen.","fr":"Le taux auquel une devise peut être échangée contre une autre. Les fluctuations des taux de change affectent la compétitivité commerciale, les coûts d'importation et la valeur des investissements étrangers.","tr":"Bir para biriminin başka bir para birimiyle değiştirilebileceği oran. Dalgalanan döviz kurları, ticaret rekabetçiliğini, ithalat maliyetlerini ve yabancı yatırımların değerini etkiler.","nl":"De koers waartegen één valuta kan worden omgewisseld voor een andere. Fluctuerende wisselkoersen beïnvloeden de handelscompetitiviteit, importkosten en de waarde van buitenlandse investeringen.","ru":"Курс, по которому одна валюта может быть обменяна на другую. Колебания обменных курсов влияют на конкурентоспособность торговли, затраты на импорт и стоимость иностранных инвестиций.","zh":"一种货币兑换另一种货币的比率。汇率波动影响贸易竞争力、进口成本以及境外投资的价值。","pt_BR":"A taxa pela qual uma moeda pode ser trocada por outra. As flutuações nas taxas de câmbio afetam a competitividade comercial, os custos de importação e o valor dos investimentos estrangeiros.","pt_PT":"A taxa à qual uma moeda pode ser trocada por outra. As flutuações nas taxas de câmbio afetam a competitividade comercial, os custos de importação e o valor dos investimentos estrangeiros."}},
  { id: 'dc-business-0104', deck_id: 'deck-business', front: 'Comparative Advantage', back: 'A country\'s ability to produce a good at a lower opportunity cost than another; the basis for international trade theory suggesting countries should specialize in what they do best.', sort_order: 104 , front_translations: {"es":"Vantaje Comparativa","de":"Komparativer Vorteil","fr":"Avantage comparatif","tr":"Karşılaştırmalı Üstünlük","nl":"Comparatief voordeel","ru":"Сравнительное преимущество","zh":"比较优势","pt_BR":"Vantagem Comparativa","pt_PT":"Vantagem Comparativa"}, back_translations: {"es":"La capacidad de un país de produzir un bem con un costo de oportunidad menor del que outro; a base de la teoría del comercio internacional que sugere que los países devem se especializar naquilo que hacen mejor.","de":"Die Fähigkeit eines Landes, ein Gut zu geringeren Opportunitätskosten als ein anderes herzustellen; die Grundlage der internationalen Handelstheorie, die besagt, dass Länder sich auf das spezialisieren sollten, was sie am besten können.","fr":"La capacité d'un pays à produire un bien à un coût d'opportunité inférieur à celui d'un autre ; fondement de la théorie du commerce international selon laquelle les pays devraient se spécialiser dans ce qu'ils font le mieux.","tr":"Bir ülkenin bir malı diğerine göre daha düşük fırsat maliyetiyle üretme yeteneği; ülkelerin en iyi yaptıkları şeylerde uzmanlaşması gerektiğini öne süren uluslararası ticaret teorisinin temeli.","nl":"Het vermogen van een land om een goed te produceren tegen lagere opportuniteitskosten dan een ander land; de basis van de internationale handelstheorie die stelt dat landen zich moeten specialiseren in wat ze het beste doen.","ru":"Способность страны производить товар с меньшими альтернативными издержками, чем другая страна; основа теории международной торговли, согласно которой страны должны специализироваться на том, что они делают лучше всего.","zh":"一个国家以比另一个国家更低的机会成本生产某种商品的能力；这是国际贸易理论的基础，认为各国应专注于自身最擅长的领域。","pt_BR":"A capacidade de um país de produzir um bem com um custo de oportunidade menor do que outro; a base da teoria do comércio internacional que sugere que os países devem se especializar naquilo que fazem melhor.","pt_PT":"A capacidade de um país produzir um bem a um custo de oportunidade menor do que outro; a base da teoria do comércio internacional que sugere que os países devem especializar-se no que fazem melhor."}},
  { id: 'dc-business-0105', deck_id: 'deck-business', front: 'Supply Chain', back: 'The network of all individuals, organizations, resources, activities, and technologies involved in creating and selling a product from raw materials to the end consumer.', sort_order: 105 , front_translations: {"es":"Cadeia de Suprimentos","de":"Lieferkette","fr":"Chaîne d'approvisionnement","tr":"Tedarik Zinciri","nl":"Toeleveringsketen","ru":"Цепочка поставок","zh":"供应链","pt_BR":"Cadeia de Suprimentos","pt_PT":"Cadeia de Abastecimento"}, back_translations: {"es":"La red de todos los indivíduos, organizaciones, recursos, atividades y tecnologias involucrados en la criación y venta de un producto, desde las materias primas hasta el consumidor final.","de":"Das Netzwerk aller Personen, Organisationen, Ressourcen, Aktivitäten und Technologien, die an der Erstellung und dem Verkauf eines Produkts vom Rohmaterial bis zum Endverbraucher beteiligt sind.","fr":"Le réseau de toutes les personnes, organisations, ressources, activités et technologies impliquées dans la création et la vente d'un produit, des matières premières au consommateur final.","tr":"Ham maddeden nihai tüketiciye kadar bir ürünün oluşturulması ve satışında yer alan tüm bireylerin, kuruluşların, kaynakların, faaliyetlerin ve teknolojilerin ağı.","nl":"Het netwerk van alle individuen, organisaties, middelen, activiteiten en technologieën die betrokken zijn bij het maken en verkopen van een product, van grondstoffen tot de eindconsument.","ru":"Сеть всех людей, организаций, ресурсов, деятельности и технологий, участвующих в создании и продаже продукта от сырья до конечного потребителя.","zh":"涉及从原材料到终端消费者的产品创建与销售过程中，所有个人、组织、资源、活动和技术构成的网络。","pt_BR":"A rede de todos os indivíduos, organizações, recursos, atividades e tecnologias envolvidos na criação e venda de um produto, desde as matérias-primas até o consumidor final.","pt_PT":"A rede de todos os indivíduos, organizações, recursos, atividades e tecnologias envolvidos na criação e venda de um produto, desde as matérias-primas até ao consumidor final."}},
  { id: 'dc-business-0106', deck_id: 'deck-business', front: 'Just-in-Time (JIT) Inventory', back: 'A production strategy that reduces inventory by receiving goods only as needed in the production process, minimizing storage costs but increasing supply chain risk.', sort_order: 106 , front_translations: {"es":"Estoque Just-in-Time (JIT)","de":"Just-in-Time (JIT) Lagerhaltung","fr":"Gestion des stocks en flux tendu (JIT)","tr":"Tam Zamanında (JIT) Envanter","nl":"Just-in-Time (JIT) voorraadbeheer","ru":"Производство «точно в срок» (JIT)","zh":"准时制（JIT）库存","pt_BR":"Estoque Just-in-Time (JIT)","pt_PT":"Gestão de Stocks Just-in-Time (JIT)"}, back_translations: {"es":"Una estrategia de producción que reduce el estoque al recibir mercadorias solo cuando necesarias en el proceso produtivo, minimizando costos de armazenaje, pero aumentando el riesgo en la cadena de suministro.","de":"Eine Produktionsstrategie, die den Lagerbestand reduziert, indem Waren nur dann geliefert werden, wenn sie im Produktionsprozess benötigt werden. Dies minimiert Lagerkosten, erhöht aber das Lieferkettenrisiko.","fr":"Une stratégie de production qui réduit les stocks en ne recevant les marchandises qu'au moment où elles sont nécessaires dans le processus de production, minimisant les coûts de stockage mais augmentant le risque de la chaîne d'approvisionnement.","tr":"Depolamayı azaltmak için ürünlerin yalnızca üretim sürecinde ihtiyaç duyulduğunda teslim alındığı bir üretim stratejisi; depolama maliyetlerini en aza indirir ancak tedarik zinciri riskini artırır.","nl":"Een productiestrategie die de voorraad vermindert door goederen alleen te ontvangen wanneer ze nodig zijn in het productieproces, waardoor opslagkosten worden geminimaliseerd maar het toeleveringsrisico toeneemt.","ru":"Производственная стратегия, сокращающая запасы путём получения товаров только тогда, когда они нужны в производственном процессе; минимизирует складские расходы, но увеличивает риск сбоев в цепочке поставок.","zh":"一种生产策略，通过仅在生产过程需要时才接收货物来减少库存，从而降低仓储成本，但会增加供应链风险。","pt_BR":"Uma estratégia de produção que reduz o estoque ao receber mercadorias apenas quando necessárias no processo produtivo, minimizando custos de armazenagem, mas aumentando o risco na cadeia de suprimentos.","pt_PT":"Uma estratégia de produção que reduz o stock ao receber mercadorias apenas quando são necessárias no processo produtivo, minimizando custos de armazenamento, mas aumentando o risco na cadeia de abastecimento."}},
  { id: 'dc-business-0107', deck_id: 'deck-business', front: 'Intellectual Property (IP)', back: 'Creations of the mind (inventions, designs, brand names, creative works) protected by patents, trademarks, and copyrights, granting exclusive rights to the creator.', sort_order: 107 , front_translations: {"es":"Propriedad Intelectual (PI)","de":"Geistiges Eigentum (IP)","fr":"Propriété intellectuelle (PI)","tr":"Fikri Mülkiyet (IP)","nl":"Intellectueel eigendom (IE)","ru":"Интеллектуальная собственность (ИС)","zh":"知识产权（IP）","pt_BR":"Propriedade Intelectual (PI)","pt_PT":"Propriedade Intelectual (PI)"}, back_translations: {"es":"Criaciones de la mente (invenciones, designs, nombres de marcas, obras criativas) protegidas por patentes, marcas registradas y derechos autorais, concedendo derechos exclusivos al criador.","de":"Geistige Schöpfungen (Erfindungen, Designs, Markennamen, kreative Werke), die durch Patente, Marken und Urheberrechte geschützt sind und dem Schöpfer ausschließliche Rechte gewähren.","fr":"Des créations de l'esprit (inventions, dessins, noms de marque, œuvres créatives) protégées par des brevets, marques et droits d'auteur, accordant des droits exclusifs au créateur.","tr":"Patent, ticari marka ve telif hakkıyla korunan, yaratıcıya münhasır haklar tanıyan zihinsel yaratımlar (icatlar, tasarımlar, marka isimleri, yaratıcı eserler).","nl":"Creaties van de geest (uitvindingen, ontwerpen, merknamen, creatieve werken) die worden beschermd door octrooien, handelsmerken en auteursrechten, waardoor de maker exclusieve rechten krijgt.","ru":"Творения разума (изобретения, дизайны, названия брендов, творческие произведения), защищённые патентами, товарными знаками и авторским правом, предоставляющие создателю исключительные права.","zh":"通过专利、商标和版权受到保护的智力创造成果（发明、设计、品牌名称、创意作品），赋予创造者专有权利。","pt_BR":"Criações da mente (invenções, designs, nomes de marcas, obras criativas) protegidas por patentes, marcas registradas e direitos autorais, concedendo direitos exclusivos ao criador.","pt_PT":"Criações da mente (invenções, designs, nomes de marcas, obras criativas) protegidas por patentes, marcas e direitos de autor, concedendo direitos exclusivos ao criador."}},
  { id: 'dc-business-0108', deck_id: 'deck-business', front: 'Patent', back: 'An exclusive right granted by the government for an invention, preventing others from making, using, or selling it for typically 20 years in exchange for public disclosure.', sort_order: 108 , front_translations: {"es":"Patente","de":"Patent","fr":"Brevet","tr":"Patent","nl":"Octrooi","ru":"Патент","zh":"专利","pt_BR":"Patente","pt_PT":"Patente"}, back_translations: {"es":"Un derecho exclusivo concedido por el gobierno para una invención, impidiendo que outros a fabriquem, usem o vendam por generalmente 20 anos en troca de la divulgación pública.","de":"Ein ausschließliches Recht, das vom Staat für eine Erfindung gewährt wird und anderen für in der Regel 20 Jahre verbietet, diese herzustellen, zu verwenden oder zu verkaufen, im Austausch für die öffentliche Offenlegung.","fr":"Un droit exclusif accordé par le gouvernement pour une invention, empêchant d'autres de la fabriquer, utiliser ou vendre pendant généralement 20 ans en échange d'une divulgation publique.","tr":"Bir buluş için hükümet tarafından verilen ve başkalarının genellikle 20 yıl boyunca onu üretmesini, kullanmasını veya satmasını engelleyen ve kamuya açıklama karşılığında tanınan münhasır bir hak.","nl":"Een exclusief recht verleend door de overheid voor een uitvinding, waardoor anderen het gedurende doorgaans 20 jaar niet mogen maken, gebruiken of verkopen, in ruil voor publieke openbaarmaking.","ru":"Исключительное право, предоставляемое государством на изобретение, запрещающее другим производить, использовать или продавать его в течение, как правило, 20 лет в обмен на публичное раскрытие информации.","zh":"政府授予发明人的一种专有权利，禁止他人在通常20年内制造、使用或销售该发明，以换取公开披露。","pt_BR":"Um direito exclusivo concedido pelo governo para uma invenção, impedindo que outros a fabriquem, usem ou vendam por geralmente 20 anos em troca da divulgação pública.","pt_PT":"Um direito exclusivo concedido pelo Estado para uma invenção, impedindo terceiros de a fabricar, usar ou vender durante geralmente 20 anos em troca da divulgação pública."}},
  { id: 'dc-business-0109', deck_id: 'deck-business', front: 'Trademark', back: 'A legally registered symbol, word, or phrase that identifies and distinguishes a company\'s products or services from those of competitors.', sort_order: 109 , front_translations: {"es":"Marca Registrada (Trademark)","de":"Marke (Trademark)","fr":"Marque déposée (Trademark)","tr":"Ticari Marka (Trademark)","nl":"Handelsmerk (Trademark)","ru":"Товарный знак (Trademark)","zh":"商标（Trademark）","pt_BR":"Marca Registrada (Trademark)","pt_PT":"Marca Registada (Trademark)"}, back_translations: {"es":"Un símbolo, palavra o frase legalmente registrado que identifica y distingue los productos o serviços de una empresa de los de sus competidores.","de":"Ein rechtlich eingetragenes Symbol, Wort oder eine Phrase, das die Produkte oder Dienstleistungen eines Unternehmens von denen der Wettbewerber identifiziert und unterscheidet.","fr":"Un symbole, un mot ou une phrase légalement enregistré qui identifie et distingue les produits ou services d'une entreprise de ceux de ses concurrents.","tr":"Bir şirketin ürün veya hizmetlerini rakiplerinkinden tanımlayan ve ayırt eden yasal olarak tescil edilmiş sembol, kelime veya ifade.","nl":"Een wettelijk geregistreerd symbool, woord of zin dat de producten of diensten van een bedrijf identificeert en onderscheidt van die van concurrenten.","ru":"Юридически зарегистрированный символ, слово или фраза, идентифицирующие и отличающие товары или услуги компании от товаров и услуг конкурентов.","zh":"经法律注册的符号、词语或短语，用于识别并区分一家公司的产品或服务与竞争对手的产品或服务。","pt_BR":"Um símbolo, palavra ou frase legalmente registrado que identifica e distingue os produtos ou serviços de uma empresa dos de seus concorrentes.","pt_PT":"Um símbolo, palavra ou frase legalmente registado que identifica e distingue os produtos ou serviços de uma empresa dos dos seus concorrentes."}},
  { id: 'dc-business-0110', deck_id: 'deck-business', front: 'Copyright', back: 'Legal protection for original creative works (books, music, software) granting the creator exclusive rights to reproduce, distribute, and display the work for a limited period.', sort_order: 110 , front_translations: {"es":"Direitos Autorais (Copyright)","de":"Urheberrecht (Copyright)","fr":"Droit d'auteur (Copyright)","tr":"Telif Hakkı (Copyright)","nl":"Auteursrecht (Copyright)","ru":"Авторское право (Copyright)","zh":"版权（Copyright）","pt_BR":"Direitos Autorais (Copyright)","pt_PT":"Direitos de Autor (Copyright)"}, back_translations: {"es":"Proteción legal para obras criativas originais (livros, música, software) que concede al criador derechos exclusivos de reproduzir, distribuir y exibir a obra por un período limitado.","de":"Rechtlicher Schutz für originale kreative Werke (Bücher, Musik, Software), der dem Schöpfer ausschließliche Rechte zur Vervielfältigung, Verbreitung und Darstellung des Werks für einen begrenzten Zeitraum gewährt.","fr":"La protection légale pour les œuvres créatives originales (livres, musique, logiciels) accordant au créateur des droits exclusifs de reproduction, distribution et présentation de l'œuvre pour une durée limitée.","tr":"Orijinal yaratıcı eserler (kitaplar, müzik, yazılım) için yasal koruma; yaratıcıya eseri sınırlı bir süre için çoğaltma, dağıtma ve sergileme konusunda münhasır haklar tanır.","nl":"Wettelijke bescherming voor originele creatieve werken (boeken, muziek, software) die de maker exclusieve rechten verleent om het werk voor een beperkte periode te reproduceren, distribueren en tonen.","ru":"Правовая защита оригинальных творческих произведений (книг, музыки, программного обеспечения), предоставляющая создателю исключительные права на воспроизведение, распространение и демонстрацию произведения в течение ограниченного срока.","zh":"对原创作品（书籍、音乐、软件）的法律保护，赋予创作者在有限期内复制、发行和展示作品的专有权利。","pt_BR":"Proteção legal para obras criativas originais (livros, música, software) que concede ao criador direitos exclusivos de reproduzir, distribuir e exibir a obra por um período limitado.","pt_PT":"Proteção legal para obras criativas originais (livros, música, software) que concede ao criador direitos exclusivos de reproduzir, distribuir e exibir a obra por um período limitado."}},
  { id: 'dc-business-0111', deck_id: 'deck-business', front: 'Goodwill', back: 'An intangible asset representing the premium paid over a company\'s book value in an acquisition, attributable to brand reputation, customer relationships, and other intangibles.', sort_order: 111 , front_translations: {"es":"Ágio por Expectativa de Rentabilidad Futura (Goodwill)","de":"Firmenwert (Goodwill)","fr":"Goodwill (Écart d'acquisition)","tr":"Şerefiye (Goodwill)","nl":"Goodwill","ru":"Гудвилл (деловая репутация)","zh":"商誉（Goodwill）","pt_BR":"Ágio por Expectativa de Rentabilidade Futura (Goodwill)","pt_PT":"Trespasse (Goodwill)"}, back_translations: {"es":"Un ativo intangible que representa el premio pago encima del valor contábil de una empresa en una adquisición, atribuible a la reputación de la marca, relacionamentos con clientes y outros intangibles.","de":"Ein immaterieller Vermögenswert, der die bei einer Übernahme über den Buchwert des Unternehmens hinaus gezahlte Prämie darstellt, zurückzuführen auf Markenreputation, Kundenbeziehungen und andere immaterielle Werte.","fr":"Un actif incorporel représentant la prime payée au-delà de la valeur comptable d'une entreprise lors d'une acquisition, attribuable à la réputation de la marque, aux relations clients et à d'autres incorporels.","tr":"Bir satın almada şirketin defter değerinin üzerinde ödenen primi temsil eden, marka itibarı, müşteri ilişkileri ve diğer maddi olmayan değerlere atfedilen bir maddi olmayan varlık.","nl":"Een immaterieel actief dat de premie vertegenwoordigt die bij een overname boven de boekwaarde van een bedrijf is betaald, toe te schrijven aan merkbekendheid, klantrelaties en andere immateriële activa.","ru":"Нематериальный актив, представляющий надбавку к балансовой стоимости компании при её приобретении, обусловленную репутацией бренда, отношениями с клиентами и другими нематериальными факторами.","zh":"一种无形资产，代表收购中支付的超过公司账面价值的溢价，归因于品牌声誉、客户关系及其他无形因素。","pt_BR":"Um ativo intangível que representa o prêmio pago acima do valor contábil de uma empresa em uma aquisição, atribuível à reputação da marca, relacionamentos com clientes e outros intangíveis.","pt_PT":"Um ativo intangível que representa o prémio pago acima do valor contabilístico de uma empresa numa aquisição, atribuível à reputação da marca, às relações com clientes e a outros intangíveis."}},
  { id: 'dc-business-0112', deck_id: 'deck-business', front: 'Accounts Receivable Turnover', back: 'Revenue divided by average accounts receivable; measures how efficiently a company collects money owed by customers. A higher ratio indicates more efficient collection.', sort_order: 112 , front_translations: {"es":"Giro de Contas a Receber","de":"Forderungsumschlag","fr":"Rotation des créances clients","tr":"Alacak Devir Hızı","nl":"Omzet debiteuren","ru":"Оборачиваемость дебиторской задолженности","zh":"应收账款周转率","pt_BR":"Giro de Contas a Receber","pt_PT":"Rotação de Contas a Receber"}, back_translations: {"es":"Receita dividida por las contas a recibir médias; mide a eficiencia con que una empresa cobra valores devidos por clientes. Un índice más alto indica cobrança más eficiente.","de":"Umsatz geteilt durch durchschnittliche Forderungen; misst, wie effizient ein Unternehmen von Kunden geschuldetes Geld einzieht. Ein höherer Wert deutet auf ein effizienteres Inkasso hin.","fr":"Le chiffre d'affaires divisé par les créances clients moyennes ; mesure l'efficacité avec laquelle une entreprise recouvre les sommes dues par ses clients. Un ratio plus élevé indique un recouvrement plus efficace.","tr":"Gelirin ortalama alacaklara bölümü; bir şirketin müşterilerden borçlu olunan parayı ne kadar verimli topladığını ölçer. Daha yüksek bir oran, daha verimli tahsilatı gösterir.","nl":"Omzet gedeeld door gemiddelde debiteuren; meet hoe efficiënt een bedrijf geld int dat klanten verschuldigd zijn. Een hogere ratio duidt op efficiënter innen.","ru":"Выручка, делённая на среднюю дебиторскую задолженность; измеряет, насколько эффективно компания взыскивает деньги, причитающиеся от клиентов. Более высокий коэффициент означает более эффективное взыскание.","zh":"收入除以平均应收账款；衡量公司收回客户欠款的效率。比率越高，表明收款效率越高。","pt_BR":"Receita dividida pelas contas a receber médias; mede a eficiência com que uma empresa cobra valores devidos por clientes. Um índice mais alto indica cobrança mais eficiente.","pt_PT":"Receita dividida pelas contas a receber médias; mede a eficiência com que uma empresa cobra valores devidos por clientes. Um rácio mais elevado indica uma cobrança mais eficiente."}},
  { id: 'dc-business-0113', deck_id: 'deck-business', front: 'Inventory Turnover', back: 'COGS divided by average inventory; measures how many times a company sells and replaces its inventory in a period. Higher turnover indicates efficient inventory management.', sort_order: 113 , front_translations: {"es":"Giro de Estoque","de":"Lagerumschlag","fr":"Rotation des stocks","tr":"Stok Devir Hızı","nl":"Voorraadrotatie","ru":"Оборачиваемость запасов","zh":"存货周转率","pt_BR":"Giro de Estoque","pt_PT":"Rotação de Inventário"}, back_translations: {"es":"CMV dividido por el estoque médio; mide quantas veces una empresa vende y repõe su estoque en un período. Un giro más alto indica gestión eficiente de estoque.","de":"Umsatzkosten geteilt durch durchschnittlichen Lagerbestand; misst, wie oft ein Unternehmen seinen Lagerbestand in einem Zeitraum verkauft und erneuert. Ein höherer Umschlag zeigt eine effiziente Lagerverwaltung an.","fr":"Le coût des marchandises vendues divisé par le stock moyen ; mesure combien de fois une entreprise vend et reconstitue son stock sur une période. Un taux de rotation élevé indique une gestion efficace des stocks.","tr":"SMM'nin ortalama stoğa bölümü; bir şirketin belirli bir dönemde stoğunu kaç kez satıp yenilediğini ölçer. Daha yüksek devir hızı, verimli stok yönetimini gösterir.","nl":"COGS gedeeld door de gemiddelde voorraad; meet hoe vaak een bedrijf zijn voorraad verkoopt en vervangt in een periode. Een hogere omloopsnelheid duidt op efficiënt voorraadbeheer.","ru":"Себестоимость реализованной продукции, делённая на средние запасы; измеряет, сколько раз компания продаёт и пополняет запасы за период. Более высокая оборачиваемость свидетельствует об эффективном управлении запасами.","zh":"销售成本除以平均存货；衡量公司在一段时间内销售并补充存货的次数。周转率越高，表明存货管理越高效。","pt_BR":"CMV dividido pelo estoque médio; mede quantas vezes uma empresa vende e repõe seu estoque em um período. Um giro mais alto indica gestão eficiente de estoque.","pt_PT":"CMV dividido pelo inventário médio; mede quantas vezes uma empresa vende e repõe o seu inventário num período. Uma rotação mais elevada indica uma gestão eficiente do inventário."}},
  { id: 'dc-business-0114', deck_id: 'deck-business', front: 'Return on Equity (ROE)', back: 'Net Income divided by Shareholders\' Equity. It measures how effectively management uses equity to generate profit; a key indicator of profitability for investors.', sort_order: 114 , front_translations: {"es":"Retorno sobre el Patrimonio Líquido (ROE)","de":"Eigenkapitalrendite (ROE)","fr":"Rendement des capitaux propres (ROE)","tr":"Öz Sermaye Karlılığı (ROE)","nl":"Rendement op eigen vermogen (ROE)","ru":"Рентабельность собственного капитала (ROE)","zh":"净资产收益率（ROE）","pt_BR":"Retorno sobre o Patrimônio Líquido (ROE)","pt_PT":"Retorno sobre o Capital Próprio (ROE)"}, back_translations: {"es":"Lucro Líquido dividido por el Patrimonio Líquido de los Acionistas. Mede a eficácia con que a gestión usa el patrimonio para gerar ganancia; un indicador-chave de rentabilidad para investidores.","de":"Nettogewinn geteilt durch das Eigenkapital der Aktionäre. Es misst, wie effektiv das Management Eigenkapital einsetzt, um Gewinn zu erwirtschaften; ein wichtiger Rentabilitätsindikator für Investoren.","fr":"Le bénéfice net divisé par les capitaux propres. Il mesure l'efficacité avec laquelle la direction utilise les capitaux propres pour générer des bénéfices ; un indicateur clé de rentabilité pour les investisseurs.","tr":"Net Gelirin Hissedar Öz Sermayesine bölümü. Yönetimin kâr üretmek için öz sermayeyi ne kadar etkin kullandığını ölçer; yatırımcılar için önemli bir kârlılık göstergesidir.","nl":"Nettoresultaat gedeeld door het eigen vermogen van aandeelhouders. Het meet hoe effectief het management eigen vermogen gebruikt om winst te genereren; een belangrijke winstgevendheidsindicator voor beleggers.","ru":"Чистая прибыль, делённая на собственный капитал акционеров. Измеряет, насколько эффективно менеджмент использует собственный капитал для получения прибыли; ключевой показатель доходности для инвесторов.","zh":"净利润除以股东权益。衡量管理层利用股权创造利润的效率；是投资者评估盈利能力的关键指标。","pt_BR":"Lucro Líquido dividido pelo Patrimônio Líquido dos Acionistas. Mede a eficácia com que a gestão usa o patrimônio para gerar lucro; um indicador-chave de rentabilidade para investidores.","pt_PT":"Resultado Líquido dividido pelo Capital Próprio dos Acionistas. Mede a eficácia com que a gestão utiliza o capital próprio para gerar lucro; um indicador-chave de rentabilidade para investidores."}},
  { id: 'dc-business-0115', deck_id: 'deck-business', front: 'Return on Assets (ROA)', back: 'Net Income divided by Total Assets. It measures how efficiently a company uses its assets to generate profit; useful for comparing companies within the same industry.', sort_order: 115 , front_translations: {"es":"Retorno sobre los Ativos (ROA)","de":"Gesamtkapitalrendite (ROA)","fr":"Rendement des actifs (ROA)","tr":"Aktif Karlılığı (ROA)","nl":"Rendement op activa (ROA)","ru":"Рентабельность активов (ROA)","zh":"资产收益率（ROA）","pt_BR":"Retorno sobre os Ativos (ROA)","pt_PT":"Retorno sobre os Ativos (ROA)"}, back_translations: {"es":"Lucro Líquido dividido por el Total de Ativos. Mede a eficiencia con que una empresa usa sus ativos para gerar ganancia; útil para comparar empresas dentro del mismo setor.","de":"Nettogewinn geteilt durch Gesamtvermögen. Es misst, wie effizient ein Unternehmen seine Vermögenswerte einsetzt, um Gewinn zu erzielen; nützlich für den Vergleich von Unternehmen innerhalb derselben Branche.","fr":"Le bénéfice net divisé par l'actif total. Il mesure l'efficacité avec laquelle une entreprise utilise ses actifs pour générer des bénéfices ; utile pour comparer des entreprises au sein d'un même secteur.","tr":"Net Gelirin Toplam Varlıklara bölümü. Bir şirketin kâr elde etmek için varlıklarını ne kadar verimli kullandığını ölçer; aynı sektördeki şirketleri karşılaştırmak için kullanışlıdır.","nl":"Nettoresultaat gedeeld door totale activa. Het meet hoe efficiënt een bedrijf zijn activa gebruikt om winst te genereren; nuttig voor het vergelijken van bedrijven binnen dezelfde sector.","ru":"Чистая прибыль, делённая на общие активы. Измеряет, насколько эффективно компания использует свои активы для получения прибыли; полезна для сравнения компаний внутри одной отрасли.","zh":"净利润除以总资产。衡量公司利用资产创造利润的效率；适用于同行业内公司的比较。","pt_BR":"Lucro Líquido dividido pelo Total de Ativos. Mede a eficiência com que uma empresa usa seus ativos para gerar lucro; útil para comparar empresas dentro do mesmo setor.","pt_PT":"Resultado Líquido dividido pelo Total de Ativos. Mede a eficiência com que uma empresa usa os seus ativos para gerar lucro; útil para comparar empresas dentro do mesmo setor."}},
  { id: 'dc-business-0116', deck_id: 'deck-business', front: 'Retained Earnings', back: 'The cumulative portion of net income kept in the business rather than paid out as dividends; it is reinvested to fund growth and appears on the balance sheet under equity.', sort_order: 116 , front_translations: {"es":"Lucros Retidos","de":"Gewinnrücklagen","fr":"Bénéfices non distribués","tr":"Dağıtılmamış Karlar","nl":"Ingehouden winsten","ru":"Нераспределённая прибыль","zh":"留存收益","pt_BR":"Lucros Retidos","pt_PT":"Resultados Retidos"}, back_translations: {"es":"La parte acumulada del ganancia líquido mantida en la empresa en vez de distribuída como dividendos; es reinvestida para financiar el crecimiento y aparece en el balanço patrimonial sob el patrimonio líquido.","de":"Der kumulierte Anteil des Nettogewinns, der im Unternehmen verbleibt, anstatt als Dividende ausgeschüttet zu werden; er wird reinvestiert, um das Wachstum zu finanzieren, und erscheint in der Bilanz unter dem Eigenkapital.","fr":"La part cumulée du bénéfice net conservée dans l'entreprise plutôt que versée en dividendes ; elle est réinvestêe pour financer la croissance et apparaît au bilan sous les capitaux propres.","tr":"Temettü olarak ödenmek yerine işletmede tutulan birikimli net gelir kısmı; büyümeyi finanse etmek için yeniden yatırılır ve bilançoda öz sermaye altında görünür.","nl":"Het cumulatieve deel van de nettowinst dat in het bedrijf wordt gehouden in plaats van als dividend te worden uitgekeerd; het wordt herbelegd om groei te financieren en verschijnt op de balans onder het eigen vermogen.","ru":"Накопленная часть чистой прибыли, оставшаяся в бизнесе, а не выплаченная в качестве дивидендов; реинвестируется для финансирования роста и отражается в балансе в составе собственного капитала.","zh":"公司净利润中未作为股息分配而留存在企业中的累积部分；再投资用于支持增长，在资产负债表中列于所有者权益项下。","pt_BR":"A parte acumulada do lucro líquido mantida na empresa em vez de distribuída como dividendos; é reinvestida para financiar o crescimento e aparece no balanço patrimonial sob o patrimônio líquido.","pt_PT":"A parte acumulada do resultado líquido mantida na empresa em vez de distribuída como dividendos; é reinvestida para financiar o crescimento e aparece no balanço patrimonial sob o capital próprio."}},
  { id: 'dc-business-0117', deck_id: 'deck-business', front: 'Stock Buyback (Share Repurchase)', back: 'When a company purchases its own shares from the open market, reducing the number of outstanding shares; it can increase earnings per share and signal management confidence.', sort_order: 117 , front_translations: {"es":"Recompra de Aciones","de":"Aktienrückkauf","fr":"Rachat d'actions","tr":"Hisse Geri Alımı","nl":"Inkoop eigen aandelen","ru":"Выкуп акций","zh":"股票回购","pt_BR":"Recompra de Ações","pt_PT":"Recompra de Ações"}, back_translations: {"es":"Cuando una empresa compra sus propias acciones en el mercado aberto, reduciendo el número de acciones en circulación; puede aumentar el ganancia por acción y sinalizar a confiança de la administración.","de":"Wenn ein Unternehmen seine eigenen Aktien vom freien Markt kauft und dadurch die Anzahl der ausstehenden Aktien verringert; dies kann den Gewinn je Aktie steigern und Managementvertrauen signalisieren.","fr":"Lorsqu'une entreprise achète ses propres actions sur le marché libre, réduisant ainsi le nombre d'actions en circulation ; cela peut augmenter le bénéfice par action et signaler la confiance de la direction.","tr":"Bir şirketin açık piyasadan kendi hisselerini satın alması, dolaşımdaki hisse sayısını azaltması; hisse başına kazancı artırabilir ve yönetimin güvenini gösterebilir.","nl":"Wanneer een bedrijf zijn eigen aandelen van de open markt koopt, waardoor het aantal uitstaande aandelen daalt; dit kan de winst per aandeel verhogen en het vertrouwen van het management signaleren.","ru":"Когда компания приобретает собственные акции на открытом рынке, сокращая количество акций в обращении; это может увеличить прибыль на акцию и свидетельствовать об уверенности руководства.","zh":"公司从公开市场买回自身股票，减少流通股数量；这可以提高每股收益，并传递管理层信心的信号。","pt_BR":"Quando uma empresa compra suas próprias ações no mercado aberto, reduzindo o número de ações em circulação; pode aumentar o lucro por ação e sinalizar a confiança da administração.","pt_PT":"Quando uma empresa compra as suas próprias ações no mercado aberto, reduzindo o número de ações em circulação; pode aumentar o resultado por ação e sinalizar a confiança da gestão."}},
  { id: 'dc-business-0118', deck_id: 'deck-business', front: 'Dilution', back: 'A reduction in existing shareholders\' ownership percentage resulting from the issuance of new shares (e.g., in a funding round or stock option exercise).', sort_order: 118 , front_translations: {"es":"Diluición","de":"Verwässerung (Dilution)","fr":"Dilution","tr":"Seyreltme (Dilution)","nl":"Verwatering (Dilution)","ru":"Размывание (дилюция)","zh":"稀释（Dilution）","pt_BR":"Diluição","pt_PT":"Diluição"}, back_translations: {"es":"Una reducción en el percentual de propiedad de los accionistas existentes resultante de la emisión de nuevas acciones (por ejemplo, en una rodada de financiamento o en el ejercicio de opciones de acciones).","de":"Eine Verringerung des Eigentumsanteils bestehender Aktionäre infolge der Ausgabe neuer Aktien (z. B. in einer Finanzierungsrunde oder bei der Ausübung von Aktienoptionen).","fr":"Une réduction du pourcentage de propriété des actionnaires existants résultant de l'émission de nouvelles actions (par exemple lors d'un tour de financement ou d'un exercice d'options sur actions).","tr":"Yeni hisse senedi ihracından (örneğin bir finansman turunda veya hisse senedi opsiyonu kullanımında) kaynaklanan, mevcut hissedarların sahiplik yüzdesindeki azalma.","nl":"Een vermindering van het eigendomspercentage van bestaande aandeelhouders als gevolg van de uitgifte van nieuwe aandelen (bijv. in een financieringsronde of bij de uitoefening van aandelenopties).","ru":"Уменьшение доли владения существующих акционеров в результате выпуска новых акций (например, в ходе раунда финансирования или исполнения опционов на акции).","zh":"因发行新股（如在融资轮次或行使股票期权时）导致现有股东持股比例降低的现象。","pt_BR":"Uma redução no percentual de propriedade dos acionistas existentes resultante da emissão de novas ações (por exemplo, em uma rodada de financiamento ou no exercício de opções de ações).","pt_PT":"Uma redução na percentagem de propriedade dos acionistas existentes resultante da emissão de novas ações (por exemplo, numa ronda de financiamento ou no exercício de opções sobre ações)."}},
  { id: 'dc-business-0119', deck_id: 'deck-business', front: 'Convertible Note', back: 'A short-term debt instrument used in startup financing that converts into equity at a future funding round, typically with a discount or valuation cap.', sort_order: 119 , front_translations: {"es":"Nota Conversible (Convertible Note)","de":"Wandelanleihe (Convertible Note)","fr":"Obligation convertible (Convertible Note)","tr":"Dönüştürülebilir Senet (Convertible Note)","nl":"Converteerbare obligatie (Convertible Note)","ru":"Конвертируемая нота (Convertible Note)","zh":"可转换票据（Convertible Note）","pt_BR":"Nota Conversível (Convertible Note)","pt_PT":"Nota Convertível (Convertible Note)"}, back_translations: {"es":"Un instrumento de dívida de corto prazo usado en el financiamento de startups que se convierte en participación acionária en una rodada futura de financiamento, generalmente con desconto o teto de valuation.","de":"Ein kurzfristiges Schuldinstrument in der Startup-Finanzierung, das sich bei einer zukünftigen Finanzierungsrunde in Eigenkapital umwandelt, typischerweise mit einem Abschlag oder einer Bewertungsobergrenze.","fr":"Un instrument de dette à court terme utilisé dans le financement de startups qui se convertit en capital lors d'un futur tour de financement, généralement avec une décote ou un plafond de valorisation.","tr":"Gelecekteki bir finansman turunda genellikle bir iskonto veya değerleme tavanıyla öz sermayeye dönüşen, girişim finansmanında kullanılan kısa vadeli bir borç aracı.","nl":"Een kortlopend schuldinstrument gebruikt bij startup-financiering dat bij een toekomstige financieringsronde omgezet wordt in eigen vermogen, doorgaans met een korting of waarderingsplafond.","ru":"Краткосрочный долговой инструмент, используемый при финансировании стартапов, который конвертируется в акционерный капитал при следующем раунде финансирования, как правило, с дисконтом или ограничением оценки.","zh":"初创企业融资中使用的短期债务工具，在未来融资轮次中转换为股权，通常附带折扣或估值上限。","pt_BR":"Um instrumento de dívida de curto prazo usado no financiamento de startups que se converte em participação acionária em uma rodada futura de financiamento, geralmente com desconto ou teto de valuation.","pt_PT":"Um instrumento de dívida de curto prazo utilizado no financiamento de startups que se converte em capital numa futura ronda de financiamento, geralmente com desconto ou limite de avaliação."}},
  { id: 'dc-business-0120', deck_id: 'deck-business', front: 'SAFE (Simple Agreement for Future Equity)', back: 'An investment instrument created by Y Combinator that gives investors the right to future equity without interest accruing; simpler than convertible notes for early-stage fundraising.', sort_order: 120 , front_translations: {"es":"SAFE (Simple Agreement for Future Equity)","de":"SAFE (Simple Agreement for Future Equity)","fr":"SAFE (Simple Agreement for Future Equity)","tr":"SAFE (Simple Agreement for Future Equity)","nl":"SAFE (Simple Agreement for Future Equity)","ru":"SAFE (Simple Agreement for Future Equity)","zh":"SAFE（未来股权简单协议）","pt_BR":"SAFE (Simple Agreement for Future Equity)","pt_PT":"SAFE (Simple Agreement for Future Equity)"}, back_translations: {"es":"Un instrumento de inversión creado por la Y Combinator que dá a los investidores el derecho a participación futura sin acumulación de juros; más simples que notas conversibles para captación en etapa inicial.","de":"Ein von Y Combinator entwickeltes Investitionsinstrument, das Investoren das Recht auf zukünftiges Eigenkapital einräumt, ohne Zinsaufläufe; einfacher als Wandelanleihen für die Frühphasenfinanzierung.","fr":"Un instrument d'investissement créé par Y Combinator qui donne aux investisseurs le droit à des actions futures sans accumulation d'intérêts ; plus simple que les obligations convertibles pour les levées de fonds en phase précoce.","tr":"Y Combinator tarafından oluşturulan ve yatırımcılara faiz tahakkuku olmaksızın gelecekteki öz sermayeye hak tanıyan bir yatırım aracı; erken aşama fon toplamaları için dönüştürülebilir senetlerden daha basittir.","nl":"Een investeringsinstrument gecreëerd door Y Combinator dat investeerders het recht geeft op toekomstig eigen vermogen zonder renteopbouw; eenvoudiger dan converteerbare obligaties voor vroegstadium fondsenwerving.","ru":"Инвестиционный инструмент, созданный Y Combinator, предоставляющий инвесторам право на будущий акционерный капитал без начисления процентов; проще конвертируемых нот для привлечения финансирования на ранних стадиях.","zh":"由Y Combinator创建的投资工具，赋予投资者未来股权权利，无需计息；比可转换票据更简单，适用于早期融资。","pt_BR":"Um instrumento de investimento criado pela Y Combinator que dá aos investidores o direito a participação futura sem acumulação de juros; mais simples que notas conversíveis para captação em estágio inicial.","pt_PT":"Um instrumento de investimento criado pela Y Combinator que confere aos investidores o direito a capital futuro sem acumulação de juros; mais simples do que notas convertíveis para angariação de fundos em fase inicial."}},
  { id: 'dc-business-0121', deck_id: 'deck-business', front: 'Term Sheet', back: 'A non-binding document summarizing the key terms and conditions of a proposed investment deal; it forms the basis for detailed legal agreements.', sort_order: 121 , front_translations: {"es":"Term Sheet (Carta de Intenciones)","de":"Term Sheet","fr":"Term Sheet (Lettre d'intention)","tr":"Term Sheet (Ön Mutabakat Mektubu)","nl":"Term sheet (intentieverklaring)","ru":"Term Sheet (Предварительное соглашение)","zh":"投资条款清单（Term Sheet）","pt_BR":"Term Sheet (Carta de Intenções)","pt_PT":"Term Sheet (Carta de Intenções)"}, back_translations: {"es":"Un documento no vinculante que resume los principales termos y condiciones de un acuerdo de inversión proposto; serve de base para los acuerdos jurídicos detalhados.","de":"Ein unverbindliches Dokument, das die wesentlichen Bedingungen eines geplanten Investitionsgeschäfts zusammenfasst; es bildet die Grundlage für detaillierte Rechtsvereinbarungen.","fr":"Un document non contraignant résumant les termes et conditions clés d'un accord d'investissement proposé ; il sert de base aux accords juridiques détaillés.","tr":"Önerilen bir yatırım anlaşmasının temel hüküm ve koşullarını özetleyen bağlayıcı olmayan bir belge; ayrıntılı yasal anlaşmaların temelini oluşturur.","nl":"Een niet-bindend document dat de belangrijkste voorwaarden van een voorgestelde investeringsdeal samenvat; het vormt de basis voor gedetailleerde juridische overeenkomsten.","ru":"Необязывающий документ, обобщающий ключевые условия предлагаемой инвестиционной сделки; служит основой для подготовки детальных юридических соглашений.","zh":"概述拟议投资交易主要条款和条件的非约束性文件；是详细法律协议的基础。","pt_BR":"Um documento não vinculante que resume os principais termos e condições de um acordo de investimento proposto; serve de base para os acordos jurídicos detalhados.","pt_PT":"Um documento não vinculativo que resume os principais termos e condições de um acordo de investimento proposto; serve de base para os acordos jurídicos detalhados."}},
  { id: 'dc-business-0122', deck_id: 'deck-business', front: 'Vesting Schedule', back: 'A timeline over which an employee or founder earns the right to their equity; a typical schedule is a 4-year vest with a 1-year cliff, aligning incentives with long-term commitment.', sort_order: 122 , front_translations: {"es":"Cronograma de Vesting","de":"Vesting-Plan","fr":"Calendrier d'acquisition (Vesting Schedule)","tr":"Hak Kazanma Takvimi (Vesting Schedule)","nl":"Vestigingsschema (Vesting Schedule)","ru":"График вестинга (Vesting Schedule)","zh":"归属计划（Vesting Schedule）","pt_BR":"Cronograma de Vesting","pt_PT":"Calendário de Vesting"}, back_translations: {"es":"Un cronograma a lo ancho del qual un funcionário o fundador ganha el derecho al su capital; un cronograma típico es un vesting de 4 anos con un cliff de 1 ano, alinhando incentivos con el comprometimento de ancho prazo.","de":"Ein Zeitplan, nach dem ein Mitarbeiter oder Gründer das Recht auf sein Eigenkapital erwirbt; ein typischer Plan sieht eine vierjährige Zuteilung mit einer einjährigen Cliff-Periode vor, um Anreize mit langfristigem Engagement zu verknüpfen.","fr":"Un calendrier selon lequel un employé ou fondateur acquiert progressivement le droit à ses actions ; un calendrier typique est un vest sur 4 ans avec une falaise (cliff) d'un an, alignant les incitations avec l'engagement à long terme.","tr":"Bir çalışanın veya kurucunun öz sermayesini kazanma hakkını elde ettiği zaman çizelgesi; tipik bir takvim, uzun vadeli bağlılıkla teşvikleri uyumlu hale getirmek için 1 yıllık uçurum ile 4 yıllık hakediştir.","nl":"Een tijdlijn waarover een werknemer of oprichter het recht op zijn aandelen verdient; een typisch schema is een vest van 4 jaar met een cliff van 1 jaar, waarmee prikkels worden afgestemd op langdurige betrokkenheid.","ru":"Временной план, по которому сотрудник или основатель приобретает права на свой акционерный капитал; типичный план — четырёхлетний вестинг с однолетним клиффом, выравнивающий стимулы с долгосрочными обязательствами.","zh":"员工或创始人获得其股权权利的时间表；典型方案为4年归属期、1年悬崖期，以将激励与长期承诺挂钩。","pt_BR":"Um cronograma ao longo do qual um funcionário ou fundador ganha o direito ao seu capital; um cronograma típico é um vesting de 4 anos com um cliff de 1 ano, alinhando incentivos com o comprometimento de longo prazo.","pt_PT":"Um calendário ao longo do qual um colaborador ou fundador adquire o direito ao seu capital; um calendário típico é um vesting de 4 anos com um cliff de 1 ano, alinhando incentivos com o compromisso a longo prazo."}},
  { id: 'dc-business-0123', deck_id: 'deck-business', front: 'Cliff (Vesting)', back: 'The minimum time period an employee must work before any equity vests; typically one year. No equity is earned before the cliff and a lump sum vests on the cliff date.', sort_order: 123 , front_translations: {"es":"Cliff (Vesting)","de":"Cliff (Vesting)","fr":"Cliff (Acquisition)","tr":"Uçurum Süresi (Vesting Cliff)","nl":"Cliff (vesting)","ru":"Клифф (вестинг)","zh":"悬崖期（归属Cliff）","pt_BR":"Cliff (Vesting)","pt_PT":"Cliff (Vesting)"}, back_translations: {"es":"El período mínimo que un funcionário deve trabalhar antes de cualquier capital ser adquirido; generalmente un ano. Nenhum capital es adquirido antes del cliff, y una quantia en bloco es adquirida en la data del cliff.","de":"Der Mindestzeitraum, den ein Mitarbeiter arbeiten muss, bevor irgendetwas vom Eigenkapital zugeteilt wird; in der Regel ein Jahr. Vor dem Cliff wird kein Eigenkapital verdient, und am Cliff-Datum wird eine Pauschalsumme zugeteilt.","fr":"La période minimale pendant laquelle un employé doit travailler avant qu'aucune action ne soit acquise ; généralement un an. Aucune action n'est acquise avant la falaise et un montant forfaitaire est acquis à la date de la falaise.","tr":"Herhangi bir öz sermayenin hak kazanılmadan önce bir çalışanın çalışması gereken minimum süre; genellikle bir yıl. Uçurumdan önce hiçbir öz sermaye kazanılmaz ve uçurum tarihinde toplu bir miktar hak kazanılır.","nl":"De minimale periode die een werknemer moet werken voordat er enig eigen vermogen verworven wordt; doorgaans één jaar. Er wordt geen eigen vermogen verworven voor de cliff en op de cliff-datum verwerft men een forfaitair bedrag.","ru":"Минимальный период работы сотрудника, по истечении которого начинается вестинг; как правило, один год. До клиффа акции не вестируются, а в дату клиффа единовременно вестируется определённый пакет.","zh":"员工在任何股权归属前必须工作的最短期限；通常为一年。悬崖期前无股权归属，悬崖期届满当日一次性归属一笔股权。","pt_BR":"O período mínimo que um funcionário deve trabalhar antes de qualquer capital ser adquirido; geralmente um ano. Nenhum capital é adquirido antes do cliff, e uma quantia em bloco é adquirida na data do cliff.","pt_PT":"O período mínimo que um colaborador deve trabalhar antes de qualquer capital ser adquirido; geralmente um ano. Nenhum capital é adquirido antes do cliff, e uma quantia em bloco é adquirida na data do cliff."}},
  { id: 'dc-business-0124', deck_id: 'deck-business', front: 'Corporate Governance', back: 'The system of rules and practices by which a company is directed and controlled, balancing interests of shareholders, management, customers, and regulators.', sort_order: 124 , front_translations: {"es":"Governança Corporativa","de":"Corporate Governance","fr":"Gouvernance d'entreprise","tr":"Kurumsal Yönetim","nl":"Corporate governance","ru":"Корпоративное управление","zh":"公司治理","pt_BR":"Governança Corporativa","pt_PT":"Governação Corporativa"}, back_translations: {"es":"El sistema de regras y práticas por el qual una empresa es dirigida y controlada, equilibrando los interesses de accionistas, gestión, clientes y reguladores.","de":"Das System von Regeln und Praktiken, durch das ein Unternehmen geleitet und kontrolliert wird, das die Interessen von Aktionären, Management, Kunden und Regulierungsbehörden ausbalanciert.","fr":"Le système de règles et de pratiques par lequel une entreprise est dirigée et contrôlée, en équilibrant les intérêts des actionnaires, de la direction, des clients et des régulateurs.","tr":"Bir şirketin yönlendirildiği ve denetlendiği, hissedarlar, yönetim, müşteriler ve düzenleyicilerin çıkarlarını dengeleyen kural ve uygulamalar sistemi.","nl":"Het systeem van regels en praktijken waarmee een bedrijf wordt geleid en gecontroleerd, waarbij de belangen van aandeelhouders, management, klanten en toezichthouders in balans worden gebracht.","ru":"Система правил и практик, в соответствии с которой компания направляется и контролируется, обеспечивая баланс интересов акционеров, менеджмента, клиентов и регуляторов.","zh":"公司受到指导和控制的规则与实践体系，兼顾股东、管理层、客户和监管机构的利益。","pt_BR":"O sistema de regras e práticas pelo qual uma empresa é dirigida e controlada, equilibrando os interesses de acionistas, gestão, clientes e reguladores.","pt_PT":"O sistema de regras e práticas pelo qual uma empresa é dirigida e controlada, equilibrando os interesses dos acionistas, gestão, clientes e reguladores."}},
  { id: 'dc-business-0125', deck_id: 'deck-business', front: 'Board of Directors', back: 'A group of individuals elected by shareholders to oversee management\'s execution of corporate strategy; it has fiduciary duty to act in shareholders\' best interests.', sort_order: 125 , front_translations: {"es":"Conselho de Administración (Board of Directors)","de":"Vorstand (Board of Directors)","fr":"Conseil d'administration (Board of Directors)","tr":"Yönetim Kurulu (Board of Directors)","nl":"Raad van bestuur (Board of Directors)","ru":"Совет директоров (Board of Directors)","zh":"董事会（Board of Directors）","pt_BR":"Conselho de Administração (Board of Directors)","pt_PT":"Conselho de Administração (Board of Directors)"}, back_translations: {"es":"Un grupo de indivíduos eleitos por los accionistas para supervisionar a execución de la estrategia corporativa por la gestión; tiene dever fiduciário de agir en el mejor interesse de los accionistas.","de":"Eine Gruppe von Einzelpersonen, die von den Aktionären gewählt wird, um die Umsetzung der Unternehmensstrategie durch das Management zu überwachen; er hat eine Treuepflicht, im besten Interesse der Aktionäre zu handeln.","fr":"Un groupe d'individus élus par les actionnaires pour superviser l'exécution de la stratégie d'entreprise par la direction ; il a une obligation fiduciaire d'agir dans le meilleur intérêt des actionnaires.","tr":"Yönetimin kurumsal stratejiyi yürütmesini denetlemek amacıyla hissedarlar tarafından seçilen bireyler grubu; hissedarların çıkarları doğrultusunda hareket etme görevi (fiduciary duty) taşır.","nl":"Een groep individuen gekozen door aandeelhouders om toezicht te houden op de uitvoering van de bedrijfsstrategie door het management; het heeft een fiduciaire plicht om te handelen in het belang van aandeelhouders.","ru":"Группа лиц, избранных акционерами для надзора за реализацией корпоративной стратегии менеджментом; несёт фидуциарную обязанность действовать в интересах акционеров.","zh":"由股东选举产生、负责监督管理层执行公司战略的一组人员；对股东负有受托责任，须以股东最佳利益行事。","pt_BR":"Um grupo de indivíduos eleitos pelos acionistas para supervisionar a execução da estratégia corporativa pela gestão; tem dever fiduciário de agir no melhor interesse dos acionistas.","pt_PT":"Um grupo de indivíduos eleitos pelos acionistas para supervisionar a execução da estratégia corporativa pela gestão; tem dever fiduciário de agir no melhor interesse dos acionistas."}},
  { id: 'dc-business-0126', deck_id: 'deck-business', front: 'Fiduciary Duty', back: 'The legal obligation to act in another party\'s best interests; directors, officers, and trustees owe fiduciary duties of care and loyalty to shareholders and beneficiaries.', sort_order: 126 , front_translations: {"es":"Dever Fiduciário","de":"Treuhänderische Pflicht","fr":"Devoir fiduciaire","tr":"Güven Yükümlülüğü","nl":"Fiduciaire Plicht","ru":"Фидуциарная обязанность","zh":"信托责任","pt_BR":"Dever Fiduciário","pt_PT":"Dever Fiduciário"}, back_translations: {"es":"La obrigación legal de agir en el mejor interesse de outra parte; diretores, executivos y fiduciários tienen deveres fiduciários de cuidado y lealdad para con accionistas y beneficiários.","de":"Die gesetzliche Verpflichtung, im besten Interesse einer anderen Partei zu handeln; Direktoren, leitende Angestellte und Treuhänder schulden Aktionären und Begünstigten Sorgfalts- und Loyalitätspflichten.","fr":"L'obligation légale d'agir dans le meilleur intérêt d'une autre partie; les administrateurs, dirigeants et fiduciaires ont des devoirs fiduciaires de diligence et de loyauté envers les actionnaires et les bénéficiaires.","tr":"Başka bir tarafın çıkarları doğrultusunda hareket etme yasal yükümlülüğü; yöneticiler, yetkililer ve mütevelliler, hissedarlar ve lehdarlara karşı özen ve sadakat fiduciary yükümlülükleri taşır.","nl":"De wettelijke verplichting om te handelen in het beste belang van een andere partij; bestuurders, functionarissen en trustees hebben fiduciaire verplichtingen van zorg en loyaliteit jegens aandeelhouders en begunstigden.","ru":"Законное обязательство действовать в интересах другой стороны; директора, должностные лица и доверительные управляющие несут фидуциарные обязанности заботы и лояльности перед акционерами и бенефициарами.","zh":"以他人最大利益行事的法律义务；董事、高管和受托人对股东和受益人负有审慎和忠诚的信托责任。","pt_BR":"A obrigação legal de agir no melhor interesse de outra parte; diretores, executivos e fiduciários têm deveres fiduciários de cuidado e lealdade para com acionistas e beneficiários.","pt_PT":"A obrigação legal de agir no melhor interesse de outra parte; administradores, dirigentes e fiduciários têm deveres fiduciários de cuidado e lealdade para com os acionistas e beneficiários."}},
  { id: 'dc-business-0127', deck_id: 'deck-business', front: 'ESG (Environmental, Social, Governance)', back: 'A set of criteria used by investors to evaluate a company\'s ethical impact and sustainability practices; increasingly important in investment decision-making.', sort_order: 127 , front_translations: {"es":"ESG (Ambiental, Social, Governança)","de":"ESG (Umwelt, Soziales, Unternehmensführung)","fr":"ESG (Environnement, Social, Gouvernance)","tr":"ESG (Çevre, Sosyal, Yönetişim)","nl":"ESG (Milieu, Sociaal, Bestuur)","ru":"ESG (Экология, Социальная сфера, Управление)","zh":"ESG（环境、社会、治理）","pt_BR":"ESG (Ambiental, Social, Governança)","pt_PT":"ESG (Ambiental, Social, Governação)"}, back_translations: {"es":"Un conjunto de critérios usado por investidores para avaliar el impacto ético y las práticas de sostenibilidad de una empresa; cada vez más importante en la tomada de decisões de inversión.","de":"Eine Reihe von Kriterien, die von Investoren verwendet werden, um die ethischen Auswirkungen und Nachhaltigkeitspraktiken eines Unternehmens zu bewerten; zunehmend wichtig bei Investitionsentscheidungen.","fr":"Un ensemble de critères utilisés par les investisseurs pour évaluer l'impact éthique et les pratiques de durabilité d'une entreprise; de plus en plus important dans la prise de décision d'investissement.","tr":"Yatırımcıların bir şirketin etik etkisini ve sürdürülebilirlik uygulamalarını değerlendirmek için kullandıkları bir dizi kriter; yatırım kararlarında giderek daha önemli hale gelmektedir.","nl":"Een reeks criteria die door beleggers worden gebruikt om de ethische impact en duurzaamheidspraktijken van een bedrijf te beoordelen; steeds belangrijker bij investeringsbeslissingen.","ru":"Набор критериев, используемых инвесторами для оценки этического воздействия и практик устойчивого развития компании; всё более важен при принятии инвестиционных решений.","zh":"投资者用于评估公司道德影响和可持续发展实践的一套标准；在投资决策中日益重要。","pt_BR":"Um conjunto de critérios usado por investidores para avaliar o impacto ético e as práticas de sustentabilidade de uma empresa; cada vez mais importante na tomada de decisões de investimento.","pt_PT":"Um conjunto de critérios utilizados por investidores para avaliar o impacto ético e as práticas de sustentabilidade de uma empresa; cada vez mais importante na tomada de decisões de investimento."}},
  { id: 'dc-business-0128', deck_id: 'deck-business', front: 'Gross Merchandise Value (GMV)', back: 'The total value of merchandise sold through a marketplace platform over a given period; a key metric for e-commerce platforms, though it differs from actual revenue.', sort_order: 128 , front_translations: {"es":"Valor Bruto de Mercadorias (GMV)","de":"Brutto-Warenwert (GMV)","fr":"Valeur brute des marchandises (GMV)","tr":"Brüt Ticaret Hacmi (GMV)","nl":"Bruto Merchandise Waarde (GMV)","ru":"Валовая стоимость товаров (GMV)","zh":"商品交易总额（GMV）","pt_BR":"Valor Bruto de Mercadorias (GMV)","pt_PT":"Valor Bruto de Mercadoria (GMV)"}, back_translations: {"es":"El valor total de mercadorias vendidas por medio de una plataforma de marketplace en un determinado período; una métrica esencial para plataformas de y-commerce, aunque difira de la ingreso real.","de":"Der Gesamtwert der über eine Marktplattform in einem bestimmten Zeitraum verkauften Waren; eine Schlüsselkennzahl für E-Commerce-Plattformen, die sich jedoch vom tatsächlichen Umsatz unterscheidet.","fr":"La valeur totale des marchandises vendues via une plateforme de marché sur une période donnée; une métrique clé pour les plateformes e-commerce, bien qu'elle diffère du chiffre d'affaires réel.","tr":"Belirli bir dönemde bir pazar platformu aracılığıyla satılan toplam mal değeri; e-ticaret platformları için önemli bir metrik olmakla birlikte gerçek gelirden farklıdır.","nl":"De totale waarde van via een marktplaatsplatform verkochte goederen over een bepaalde periode; een belangrijke maatstaf voor e-commerceplatforms, hoewel het verschilt van de werkelijke omzet.","ru":"Общая стоимость товаров, проданных через торговую платформу за определённый период; ключевой показатель для платформ электронной коммерции, хотя он отличается от фактической выручки.","zh":"在特定时期内通过市场平台售出的商品总价值；是电商平台的关键指标，但与实际收入有所不同。","pt_BR":"O valor total de mercadorias vendidas por meio de uma plataforma de marketplace em um determinado período; uma métrica essencial para plataformas de e-commerce, embora difira da receita real.","pt_PT":"O valor total das mercadorias vendidas através de uma plataforma de mercado num determinado período; uma métrica essencial para plataformas de comércio eletrónico, embora difira da receita real."}},
  { id: 'dc-business-0129', deck_id: 'deck-business', front: 'Take Rate', back: 'The percentage of GMV that a marketplace platform keeps as revenue; a critical indicator of platform monetization and health.', sort_order: 129 , front_translations: {"es":"Taxa de Participación (Take Rate)","de":"Take Rate (Plattformprovision)","fr":"Taux de commission (Take Rate)","tr":"Komisyon Oranı (Take Rate)","nl":"Take Rate (Platformcommissie)","ru":"Доля комиссии (Take Rate)","zh":"抽佣比例（Take Rate）","pt_BR":"Taxa de Participação (Take Rate)","pt_PT":"Taxa de Participação (Take Rate)"}, back_translations: {"es":"El percentual del GMV que una plataforma de marketplace retém como ingreso; un indicador crítico de la monetización y salud de la plataforma.","de":"Der Prozentsatz des GMV, den eine Marktplattform als Umsatz einbehält; ein entscheidender Indikator für die Monetarisierung und Gesundheit der Plattform.","fr":"Le pourcentage du GMV qu'une plateforme de marché conserve comme chiffre d'affaires; un indicateur essentiel de la monétisation et de la santé de la plateforme.","tr":"Bir pazar platformunun gelir olarak elinde tuttuğu GMV yüzdesi; platform monetizasyonunun ve sağlığının kritik bir göstergesi.","nl":"Het percentage van de GMV dat een marktplaatsplatform als omzet behoudt; een cruciale indicator voor platformmonetisatie en -gezondheid.","ru":"Процент от GMV, который торговая платформа удерживает в качестве выручки; ключевой показатель монетизации и состояния платформы.","zh":"市场平台作为收入保留的GMV百分比；衡量平台变现能力和健康状况的关键指标。","pt_BR":"O percentual do GMV que uma plataforma de marketplace retém como receita; um indicador crítico da monetização e saúde da plataforma.","pt_PT":"A percentagem do GMV que uma plataforma de mercado retém como receita; um indicador crítico da monetização e saúde da plataforma."}},
  { id: 'dc-business-0130', deck_id: 'deck-business', front: 'Unit Economics', back: 'Analysis of revenues and costs on a per-unit basis; for SaaS businesses this typically means LTV:CAC ratio, showing whether customer value justifies acquisition cost.', sort_order: 130 , front_translations: {"es":"Economia Unitária (Unit Economics)","de":"Stückökonomie (Unit Economics)","fr":"Économie unitaire (Unit Economics)","tr":"Birim Ekonomisi (Unit Economics)","nl":"Eenheidseconomie (Unit Economics)","ru":"Экономика единицы (Unit Economics)","zh":"单位经济效益","pt_BR":"Economia Unitária (Unit Economics)","pt_PT":"Economia Unitária (Unit Economics)"}, back_translations: {"es":"Análise de ingresos y costos por unidad; para empresas SaaS, eso generalmente significa a proporción LTV:CAC, mostrando se el valor del cliente justifica el costo de adquisición.","de":"Analyse von Einnahmen und Kosten auf Einzelbasis; für SaaS-Unternehmen bedeutet dies typischerweise das LTV:CAC-Verhältnis, das zeigt, ob der Kundenwert die Akquisitionskosten rechtfertigt.","fr":"Analyse des revenus et des coûts sur une base unitaire; pour les entreprises SaaS, cela signifie généralement le ratio LTV:CAC, montrant si la valeur client justifie le coût d'acquisition.","tr":"Gelirlerin ve maliyetlerin birim bazında analizi; SaaS işletmeleri için bu genellikle LTV:CAC oranı anlamına gelir ve müşteri değerinin edinme maliyetini haklı kılıp kılmadığını gösterir.","nl":"Analyse van inkomsten en kosten op eenheidsbasis; voor SaaS-bedrijven betekent dit doorgaans de LTV:CAC-verhouding, die aantoont of de klantwaarde de acquisitiekosten rechtvaardigt.","ru":"Анализ доходов и затрат на единицу; для SaaS-компаний это обычно соотношение LTV:CAC, показывающее, оправдывает ли ценность клиента затраты на привлечение.","zh":"以单位为基础分析收入和成本；对于SaaS企业，通常指LTV:CAC比率，显示客户价值是否能证明获客成本的合理性。","pt_BR":"Análise de receitas e custos por unidade; para empresas SaaS, isso geralmente significa a proporção LTV:CAC, mostrando se o valor do cliente justifica o custo de aquisição.","pt_PT":"Análise de receitas e custos numa base unitária; para empresas SaaS, isso significa tipicamente o rácio LTV:CAC, mostrando se o valor do cliente justifica o custo de aquisição."}},
  { id: 'dc-business-0131', deck_id: 'deck-business', front: 'Aggregate Demand', back: 'The total demand for all goods and services in an economy at a given price level; it is the sum of consumption, investment, government spending, and net exports.', sort_order: 131 , front_translations: {"es":"Demanda Agregada","de":"Gesamtnachfrage (Aggregate Demand)","fr":"Demande agrégée","tr":"Toplam Talep","nl":"Totale vraag (Aggregate Demand)","ru":"Совокупный спрос","zh":"总需求","pt_BR":"Demanda Agregada","pt_PT":"Procura Agregada"}, back_translations: {"es":"La demanda total por todos los bens y serviços en una economía en determinado nivel de precios; es a suma del consumo, inversión, gastos del gobierno y exportaciones líquidas.","de":"Die Gesamtnachfrage nach allen Gütern und Dienstleistungen in einer Volkswirtschaft bei einem bestimmten Preisniveau; sie setzt sich zusammen aus Konsum, Investitionen, Staatsausgaben und Nettoexporten.","fr":"La demande totale pour tous les biens et services dans une économie à un niveau de prix donné; c'est la somme de la consommation, de l'investissement, des dépenses publiques et des exportations nettes.","tr":"Belirli bir fiyat düzeyinde bir ekonomideki tüm mal ve hizmetlere yönelik toplam talep; tüketim, yatırım, hükümet harcamaları ve net ihracatın toplamıdır.","nl":"De totale vraag naar alle goederen en diensten in een economie bij een bepaald prijsniveau; het is de som van consumptie, investeringen, overheidsuitgaven en netto-export.","ru":"Общий спрос на все товары и услуги в экономике при данном уровне цен; представляет собой сумму потребления, инвестиций, государственных расходов и чистого экспорта.","zh":"在特定价格水平下，经济体中对所有商品和服务的总需求；是消费、投资、政府支出和净出口的总和。","pt_BR":"A demanda total por todos os bens e serviços em uma economia em determinado nível de preços; é a soma do consumo, investimento, gastos do governo e exportações líquidas.","pt_PT":"A procura total de todos os bens e serviços numa economia a um determinado nível de preços; é a soma do consumo, investimento, despesas do governo e exportações líquidas."}},
  { id: 'dc-business-0132', deck_id: 'deck-business', front: 'Stagflation', back: 'A rare economic condition combining stagnant growth, high unemployment, and high inflation simultaneously; famously occurred in the 1970s during the oil crisis.', sort_order: 132 , front_translations: {"es":"Estagflación","de":"Stagflation","fr":"Stagflation","tr":"Stagflasyon","nl":"Stagflatie","ru":"Стагфляция","zh":"滞胀","pt_BR":"Estagflação","pt_PT":"Estagflação"}, back_translations: {"es":"Una rara condición económica que combina crecimiento estagnado, alto desemprego y alta inflación simultáneamente; ocorreu notavelmente en los anos 1970 durante a crise del petróleo.","de":"Ein seltener wirtschaftlicher Zustand, bei dem stagnierendes Wachstum, hohe Arbeitslosigkeit und hohe Inflation gleichzeitig auftreten; berühmt aufgetreten in den 1970er Jahren während der Ölkrise.","fr":"Une rare condition économique combinant croissance stagnante, chômage élevé et forte inflation simultanément; survenue notamment dans les années 1970 lors de la crise pétrolière.","tr":"Durgun büyüme, yüksek işsizlik ve yüksek enflasyonu aynı anda birleştiren nadir bir ekonomik durum; özellikle 1970'lerdeki petrol krizi sırasında yaşanmıştır.","nl":"Een zeldzame economische toestand waarbij stagnerende groei, hoge werkloosheid en hoge inflatie gelijktijdig optreden; beroemd opgetreden in de jaren 1970 tijdens de oliecrisis.","ru":"Редкое экономическое явление, сочетающее стагнирующий рост, высокую безработицу и высокую инфляцию одновременно; широко известно произошедшим в 1970-х годах во время нефтяного кризиса.","zh":"一种罕见的经济状况，同时出现经济停滞、高失业率和高通胀；典型案例发生在1970年代石油危机期间。","pt_BR":"Uma rara condição econômica que combina crescimento estagnado, alto desemprego e alta inflação simultaneamente; ocorreu notavelmente nos anos 1970 durante a crise do petróleo.","pt_PT":"Uma rara condição económica que combina crescimento estagnado, desemprego elevado e inflação elevada em simultâneo; ocorreu notavelmente na década de 1970 durante a crise petrolífera."}},
  { id: 'dc-business-0133', deck_id: 'deck-business', front: 'Hyperinflation', back: 'Extremely rapid and out-of-control inflation, typically exceeding 50% per month; it destroys a currency\'s purchasing power and can collapse an economy, as seen in Weimar Germany and Zimbabwe.', sort_order: 133 , front_translations: {"es":"Hiperinflación","de":"Hyperinflation","fr":"Hyperinflation","tr":"Hiperenflasyon","nl":"Hyperinflatie","ru":"Гиперинфляция","zh":"恶性通货膨胀","pt_BR":"Hiperinflação","pt_PT":"Hiperinflação"}, back_translations: {"es":"Inflación extremamente rápida y fuera de controle, típicamente superior a 50% al mes; destruye el poder de compra de una moeda y puede colapsar una economía, como visto en la Alemanha de Weimar y en el Zimbábue.","de":"Extrem schnelle und unkontrollierbare Inflation, typischerweise über 50% pro Monat; sie zerstört die Kaufkraft einer Währung und kann eine Wirtschaft zum Zusammenbruch bringen, wie in der Weimarer Republik und Simbabwe.","fr":"Une inflation extrêmement rapide et incontrôlable, dépassant généralement 50% par mois; elle détruit le pouvoir d'achat d'une monnaie et peut faire s'effondrer une économie, comme on l'a vu en Allemagne de Weimar et au Zimbabwe.","tr":"Genellikle aylık %50'yi aşan son derece hızlı ve kontrolsüz enflasyon; bir para biriminin satın alma gücünü yok eder ve Weimar Almanyası ile Zimbabve'de görüldüğü gibi bir ekonomiyi çökertebilir.","nl":"Extreem snelle en oncontroleerbare inflatie, doorgaans meer dan 50% per maand; het vernietigt de koopkracht van een valuta en kan een economie laten instorten, zoals gezien in Weimar-Duitsland en Zimbabwe.","ru":"Чрезвычайно быстрая и неконтролируемая инфляция, как правило превышающая 50% в месяц; она разрушает покупательную способность валюты и может обрушить экономику, как это произошло в Веймарской Германии и Зимбабве.","zh":"极其迅速且失控的通货膨胀，通常超过每月50%；它会摧毁货币的购买力，甚至导致经济崩溃，如魏玛德国和津巴布韦所见。","pt_BR":"Inflação extremamente rápida e fora de controle, tipicamente superior a 50% ao mês; destrói o poder de compra de uma moeda e pode colapsar uma economia, como visto na Alemanha de Weimar e no Zimbábue.","pt_PT":"Inflação extremamente rápida e descontrolada, tipicamente superior a 50% por mês; destrói o poder de compra de uma moeda e pode colapsar uma economia, como visto na Alemanha de Weimar e no Zimbabué."}},
  { id: 'dc-business-0134', deck_id: 'deck-business', front: 'Deflation', back: 'A sustained decrease in the general price level of goods and services; while prices fall, deflation can signal weak demand, cause debt deflation spirals, and harm economic growth.', sort_order: 134 , front_translations: {"es":"Deflación","de":"Deflation","fr":"Déflation","tr":"Deflasyon","nl":"Deflatie","ru":"Дефляция","zh":"通货紧缩","pt_BR":"Deflação","pt_PT":"Deflação"}, back_translations: {"es":"Una caída sustentada en el nivel geral de precios de bens y serviços; aunque los precios caiam, a deflación puede sinalizar demanda débil, causar espirais de deflación de la dívida y prejudicar el crecimiento económico.","de":"Ein anhaltender Rückgang des allgemeinen Preisniveaus für Güter und Dienstleistungen; obwohl die Preise fallen, kann Deflation auf schwache Nachfrage hinweisen, Schuldendeflationsspiralen verursachen und das Wirtschaftswachstum hemmen.","fr":"Une baisse prolongée du niveau général des prix des biens et services; bien que les prix baissent, la déflation peut signaler une demande faible, provoquer des spirales de déflation par la dette et nuire à la croissance économique.","tr":"Mal ve hizmetlerin genel fiyat düzeyinde sürdürülebilir bir düşüş; fiyatlar düşse de deflasyon zayıf talebin işareti olabilir, borç deflasyonu sarmallarına yol açabilir ve ekonomik büyümeye zarar verebilir.","nl":"Een aanhoudende daling van het algemeen prijsniveau van goederen en diensten; hoewel prijzen dalen, kan deflatie wijzen op zwakke vraag, schulddeflatiespiralen veroorzaken en economische groei schaden.","ru":"Устойчивое снижение общего уровня цен на товары и услуги; несмотря на падение цен, дефляция может свидетельствовать о слабом спросе, вызывать долговые дефляционные спирали и тормозить экономический рост.","zh":"商品和服务总体价格水平的持续下降；虽然价格下跌，但通货紧缩可能表明需求疲弱，引发债务紧缩螺旋，并损害经济增长。","pt_BR":"Uma queda sustentada no nível geral de preços de bens e serviços; embora os preços caiam, a deflação pode sinalizar demanda fraca, causar espirais de deflação da dívida e prejudicar o crescimento econômico.","pt_PT":"Uma diminuição sustentada no nível geral de preços de bens e serviços; embora os preços caiam, a deflação pode sinalizar procura fraca, causar espirais de deflação da dívida e prejudicar o crescimento económico."}},
  { id: 'dc-business-0135', deck_id: 'deck-business', front: 'Price Elasticity of Supply', back: 'Measures the responsiveness of quantity supplied to a change in price. Elastic supply can increase quickly; inelastic supply cannot increase rapidly regardless of price changes.', sort_order: 135 , front_translations: {"es":"Elasticidad-Preço de la Oferta","de":"Preiselastizität des Angebots","fr":"Élasticité-prix de l'offre","tr":"Arzın Fiyat Esnekliği","nl":"Prijselasticiteit van het aanbod","ru":"Ценовая эластичность предложения","zh":"供给的价格弹性","pt_BR":"Elasticidade-Preço da Oferta","pt_PT":"Elasticidade-Preço da Oferta"}, back_translations: {"es":"Mede a capacidad de respuesta de la cantidad ofertada a una cambio de precio. La oferta elástica puede aumentar rápidamente; a oferta inelástica no consegue aumentar rápidamente independentemente de las variaciones de precio.","de":"Misst die Reaktionsfähigkeit der angebotenen Menge auf eine Preisänderung. Elastisches Angebot kann schnell zunehmen; unelastisches Angebot kann unabhängig von Preisänderungen nicht schnell zunehmen.","fr":"Mesure la réactivité de la quantité offerte à une variation de prix. Une offre élastique peut augmenter rapidement; une offre inélastique ne peut pas augmenter rapidement quelle que soit la variation de prix.","tr":"Arz edilen miktarın fiyat değişikliğine verdiği tepkiyi ölçer. Esnek arz hızla artabilir; esnek olmayan arz, fiyat değişikliklerinden bağımsız olarak hızlı artamaz.","nl":"Meet hoe de aangeboden hoeveelheid reageert op een prijsverandering. Elastisch aanbod kan snel toenemen; inelastisch aanbod kan niet snel toenemen ongeacht prijsveranderingen.","ru":"Измеряет реакцию предложенного количества на изменение цены. Эластичное предложение может быстро увеличиться; неэластичное предложение не может быстро возрасти независимо от изменений цены.","zh":"衡量供给量对价格变化的反应程度。弹性供给能够迅速增加；无论价格如何变化，非弹性供给都无法快速增加。","pt_BR":"Mede a capacidade de resposta da quantidade ofertada a uma mudança de preço. A oferta elástica pode aumentar rapidamente; a oferta inelástica não consegue aumentar rapidamente independentemente das variações de preço.","pt_PT":"Mede a capacidade de resposta da quantidade ofertada a uma variação de preço. A oferta elástica pode aumentar rapidamente; a oferta inelástica não consegue aumentar rapidamente independentemente das variações de preço."}},
  { id: 'dc-business-0136', deck_id: 'deck-business', front: 'Market Segmentation', back: 'Dividing a target market into distinct groups (by demographics, geography, psychographics, or behavior) to tailor marketing and products to each segment\'s specific needs.', sort_order: 136 , front_translations: {"es":"Segmentación de Mercado","de":"Marktsegmentierung","fr":"Segmentation du marché","tr":"Pazar Segmentasyonu","nl":"Marktsegmentatie","ru":"Сегментация рынка","zh":"市场细分","pt_BR":"Segmentação de Mercado","pt_PT":"Segmentação de Mercado"}, back_translations: {"es":"Divisão de un mercado-alvo en grupos distintos (por demografia, geografia, psicografia o comportamiento) para adaptar el marketing y los productos a las necesidades específicas de cada segmento.","de":"Aufteilung eines Zielmarktes in unterschiedliche Gruppen (nach Demografie, Geografie, Psychografie oder Verhalten), um Marketing und Produkte auf die spezifischen Bedürfnisse jedes Segments zuzuschneiden.","fr":"Division d'un marché cible en groupes distincts (par démographie, géographie, psychographie ou comportement) pour adapter le marketing et les produits aux besoins spécifiques de chaque segment.","tr":"Hedef pazarı farklı gruplara (demografik, coğrafi, psikografik veya davranışsal olarak) bölmek; pazarlama ve ürünleri her segmentin özel ihtiyaçlarına göre uyarlamak için.","nl":"Het verdelen van een doelmarkt in afzonderlijke groepen (op demografisch, geografisch, psychografisch of gedragsmatig vlak) om marketing en producten af te stemmen op de specifieke behoeften van elk segment.","ru":"Разделение целевого рынка на отдельные группы (по демографическим, географическим, психографическим или поведенческим признакам) для адаптации маркетинга и продуктов к специфическим потребностям каждого сегмента.","zh":"将目标市场划分为不同群体（按人口、地理、心理或行为特征），以便针对每个细分市场的特定需求定制营销策略和产品。","pt_BR":"Divisão de um mercado-alvo em grupos distintos (por demografia, geografia, psicografia ou comportamento) para adaptar o marketing e os produtos às necessidades específicas de cada segmento.","pt_PT":"Divisão de um mercado-alvo em grupos distintos (por demografia, geografia, psicografia ou comportamento) para adaptar o marketing e os produtos às necessidades específicas de cada segmento."}},
  { id: 'dc-business-0137', deck_id: 'deck-business', front: 'Total Addressable Market (TAM)', back: 'The total revenue opportunity available if a product achieved 100% market share. Investors use TAM to assess a startup\'s growth ceiling.', sort_order: 137 , front_translations: {"es":"Mercado Total Endereçable (TAM)","de":"Total Addressable Market (TAM)","fr":"Marché total adressable (TAM)","tr":"Toplam Adreslenebilir Pazar (TAM)","nl":"Totaal adresseerbare markt (TAM)","ru":"Общий адресуемый рынок (TAM)","zh":"总可寻址市场（TAM）","pt_BR":"Mercado Total Endereçável (TAM)","pt_PT":"Mercado Total Endereçável (TAM)"}, back_translations: {"es":"La oportunidad de ingreso total disponible se un producto alcançasse 100% de participación de mercado. Los investidores usam el TAM para avaliar el teto de crecimiento de una startup.","de":"Die gesamte Umsatzmöglichkeit, die verfügbar wäre, wenn ein Produkt 100% Marktanteil erreichen würde. Investoren nutzen den TAM, um das Wachstumspotenzial eines Startups zu beurteilen.","fr":"L'opportunité de revenus totale disponible si un produit atteignait 100% de part de marché. Les investisseurs utilisent le TAM pour évaluer le plafond de croissance d'une startup.","tr":"Bir ürün %100 pazar payına ulaşsaydı mevcut olacak toplam gelir fırsatı. Yatırımcılar, bir girişimin büyüme tavanını değerlendirmek için TAM'ı kullanır.","nl":"De totale omzetmogelijkheid die beschikbaar zou zijn als een product 100% marktaandeel zou bereiken. Beleggers gebruiken TAM om het groeiplafond van een startup te beoordelen.","ru":"Общая возможность получения выручки, доступная при условии достижения продуктом 100% доли рынка. Инвесторы используют TAM для оценки потолка роста стартапа.","zh":"若产品达到100%市场份额时可获得的总收入机会。投资者用TAM评估初创公司的增长上限。","pt_BR":"A oportunidade de receita total disponível se um produto alcançasse 100% de participação de mercado. Os investidores usam o TAM para avaliar o teto de crescimento de uma startup.","pt_PT":"A oportunidade de receita total disponível se um produto atingisse 100% de quota de mercado. Os investidores utilizam o TAM para avaliar o teto de crescimento de uma startup."}},
  { id: 'dc-business-0138', deck_id: 'deck-business', front: 'Serviceable Addressable Market (SAM)', back: 'The segment of TAM that a company can realistically target given its current product, geography, and business model constraints.', sort_order: 138 , front_translations: {"es":"Mercado Endereçable Atendible (SAM)","de":"Serviceable Addressable Market (SAM)","fr":"Marché adressable accessible (SAM)","tr":"Hizmet Verilebilir Adreslenebilir Pazar (SAM)","nl":"Bedienbare adresseerbare markt (SAM)","ru":"Обслуживаемый адресуемый рынок (SAM)","zh":"可服务的可寻址市场（SAM）","pt_BR":"Mercado Endereçável Atendível (SAM)","pt_PT":"Mercado Endereçável Atendível (SAM)"}, back_translations: {"es":"El segmento del TAM que una empresa puede realisticamente atingir dato su producto atual, geografia y restriciones del modelo de negocios.","de":"Das Segment des TAM, auf das ein Unternehmen angesichts seines aktuellen Produkts, seiner geografischen Lage und seiner Geschäftsmodellbeschränkungen realistischerweise abzielen kann.","fr":"Le segment du TAM qu'une entreprise peut réalistement cibler compte tenu de son produit actuel, de sa géographie et des contraintes de son modèle d'affaires.","tr":"Mevcut ürünü, coğrafyası ve iş modeli kısıtlamaları göz önünde bulundurulduğunda bir şirketin gerçekçi olarak hedefleyebileceği TAM segmenti.","nl":"Het segment van de TAM dat een bedrijf realistisch kan targeten gezien zijn huidige product, geografie en beperkingen van het bedrijfsmodel.","ru":"Сегмент TAM, на который компания может реалистично нацелиться с учётом текущего продукта, географии и ограничений бизнес-модели.","zh":"考虑到公司当前产品、地理范围和商业模式限制，能够实际瞄准的TAM细分市场。","pt_BR":"O segmento do TAM que uma empresa pode realisticamente atingir dado seu produto atual, geografia e restrições do modelo de negócios.","pt_PT":"O segmento do TAM que uma empresa pode realisticamente atingir tendo em conta o seu produto atual, a sua geografia e as restrições do modelo de negócio."}},
  { id: 'dc-business-0139', deck_id: 'deck-business', front: 'Serviceable Obtainable Market (SOM)', back: 'The realistic portion of SAM a company can capture in the near term, considering competition and execution capacity; a key planning metric for startups.', sort_order: 139 , front_translations: {"es":"Mercado Atendible Obtible (SOM)","de":"Serviceable Obtainable Market (SOM)","fr":"Marché obtainable accessible (SOM)","tr":"Elde Edilebilir Hizmet Pazarı (SOM)","nl":"Bedienbare bereikbare markt (SOM)","ru":"Достижимый обслуживаемый рынок (SOM)","zh":"可获得的服务市场（SOM）","pt_BR":"Mercado Atendível Obtível (SOM)","pt_PT":"Mercado Atendível Obtenível (SOM)"}, back_translations: {"es":"La parcela realista del SAM que una empresa puede capturar en el corto prazo, considerando a competencia y a capacidad de execución; una métrica de planejamento esencial para startups.","de":"Der realistische Anteil des SAM, den ein Unternehmen kurzfristig gewinnen kann, unter Berücksichtigung von Wettbewerb und Ausführungskapazität; eine wichtige Planungskennzahl für Startups.","fr":"La portion réaliste du SAM qu'une entreprise peut capturer à court terme, compte tenu de la concurrence et de la capacité d'exécution; une mesure de planification clé pour les startups.","tr":"Rekabet ve uygulama kapasitesi göz önünde bulundurulduğunda bir şirketin kısa vadede ele geçirebileceği SAM'ın gerçekçi bölümü; girişimler için önemli bir planlama metriği.","nl":"Het realistische deel van de SAM dat een bedrijf op korte termijn kan veroveren, rekening houdend met concurrentie en uitvoeringscapaciteit; een belangrijke planningsindicator voor startups.","ru":"Реалистичная доля SAM, которую компания может завоевать в краткосрочной перспективе с учётом конкуренции и производственных мощностей; ключевой плановый показатель для стартапов.","zh":"考虑竞争和执行能力后，公司近期能够实际占据的SAM份额；是初创公司的关键规划指标。","pt_BR":"A parcela realista do SAM que uma empresa pode capturar no curto prazo, considerando a concorrência e a capacidade de execução; uma métrica de planejamento essencial para startups.","pt_PT":"A parcela realista do SAM que uma empresa pode capturar a curto prazo, tendo em conta a concorrência e a capacidade de execução; uma métrica de planeamento essencial para startups."}},
  { id: 'dc-business-0140', deck_id: 'deck-business', front: 'Agile Methodology', back: 'An iterative project management framework emphasizing flexibility, collaboration, and delivering working products in short cycles (sprints); widely used in software development.', sort_order: 140 , front_translations: {"es":"Metodologia Ágil","de":"Agile Methodik","fr":"Méthodologie Agile","tr":"Çevik Metodoloji","nl":"Agile Methodologie","ru":"Гибкая методология (Agile)","zh":"敏捷方法论","pt_BR":"Metodologia Ágil","pt_PT":"Metodologia Ágil"}, back_translations: {"es":"Un framework de gerenciamento de projetos iterativo que enfatiza flexibilidad, colaboración y entrega de productos funcionais en ciclos curtos (sprints); amplamente usado en el desarrollo de software.","de":"Ein iteratives Projektmanagement-Framework, das Flexibilität, Zusammenarbeit und die Lieferung funktionierender Produkte in kurzen Zyklen (Sprints) betont; weit verbreitet in der Softwareentwicklung.","fr":"Un cadre de gestion de projet itératif mettant l'accent sur la flexibilité, la collaboration et la livraison de produits fonctionnels en cycles courts (sprints); largement utilisé dans le développement logiciel.","tr":"Esnekliği, iş birliğini ve kısa döngülerde (sprint'ler) çalışan ürünlerin teslimini vurgulayan yinelemeli bir proje yönetimi çerçevesi; yazılım geliştirmede yaygın olarak kullanılmaktadır.","nl":"Een iteratief projectmanagementkader dat de nadruk legt op flexibiliteit, samenwerking en het leveren van werkende producten in korte cycli (sprints); veel gebruikt in softwareontwikkeling.","ru":"Итерационная система управления проектами, акцентирующая гибкость, сотрудничество и поставку рабочих продуктов в коротких циклах (спринтах); широко применяется в разработке программного обеспечения.","zh":"一种迭代的项目管理框架，强调灵活性、协作以及在短周期（冲刺）内交付可用产品；在软件开发中广泛应用。","pt_BR":"Um framework de gerenciamento de projetos iterativo que enfatiza flexibilidade, colaboração e entrega de produtos funcionais em ciclos curtos (sprints); amplamente usado no desenvolvimento de software.","pt_PT":"Uma estrutura de gestão de projetos iterativa que enfatiza a flexibilidade, a colaboração e a entrega de produtos funcionais em ciclos curtos (sprints); amplamente utilizada no desenvolvimento de software."}},
  { id: 'dc-business-0141', deck_id: 'deck-business', front: 'Lean Startup Methodology', back: 'Eric Ries\' framework of Build-Measure-Learn cycles to rapidly test business hypotheses, validate assumptions with minimal waste, and iterate toward product-market fit.', sort_order: 141 , front_translations: {"es":"Metodologia Lean Startup","de":"Lean-Startup-Methodik","fr":"Méthodologie Lean Startup","tr":"Yalın Girişim Metodolojisi","nl":"Lean Startup Methodologie","ru":"Методология бережливого стартапа (Lean Startup)","zh":"精益创业方法论","pt_BR":"Metodologia Lean Startup","pt_PT":"Metodologia Lean Startup"}, back_translations: {"es":"El framework de Eric Ries con ciclos Construir-Medir-Aprender para testar rápidamente hipóteses de negocio, validar suposiciones con desperdício mínimo y iterar en dirección al product-market fit.","de":"Eric Ries' Framework aus Erstellen-Messen-Lernen-Zyklen, um Geschäftshypothesen schnell zu testen, Annahmen mit minimalem Aufwand zu validieren und zur Produkt-Markt-Passung zu iterieren.","fr":"Le cadre d'Eric Ries basé sur des cycles Construire-Mesurer-Apprendre pour tester rapidement des hypothèses commerciales, valider des suppositions avec un minimum de gaspillage et itérer vers l'adéquation produit-marché.","tr":"Eric Ries'in İnşa Et-Ölç-Öğren döngüleri çerçevesi; iş hipotezlerini hızla test etmek, minimum israfla varsayımları doğrulamak ve ürün-pazar uyumuna doğru yinelemek için kullanılır.","nl":"Eric Ries' framework van Bouwen-Meten-Leren-cycli om snel zakelijke hypothesen te testen, aannames met minimale verspilling te valideren en naar product-marktfit te itereren.","ru":"Фреймворк Эрика Риса на основе циклов \"Создай-Измерь-Научись\" для быстрого тестирования бизнес-гипотез, проверки допущений с минимальными потерями и итерации к соответствию продукта рынку.","zh":"埃里克·里斯的\"构建-测量-学习\"循环框架，用于快速验证商业假设、以最少浪费验证假设，并迭代实现产品-市场契合。","pt_BR":"O framework de Eric Ries com ciclos Construir-Medir-Aprender para testar rapidamente hipóteses de negócio, validar suposições com desperdício mínimo e iterar em direção ao product-market fit.","pt_PT":"O framework de Eric Ries com ciclos Construir-Medir-Aprender para testar rapidamente hipóteses de negócio, validar suposições com desperdício mínimo e iterar em direção ao ajuste produto-mercado."}},
  { id: 'dc-business-0142', deck_id: 'deck-business', front: 'Blue Ocean Strategy', back: 'A strategy of creating uncontested market space by making competition irrelevant; pioneered by Kim and Mauborgne as an alternative to competing in existing "red ocean" markets.', sort_order: 142 , front_translations: {"es":"Estratégia del Oceano Azul","de":"Blaue-Ozean-Strategie","fr":"Stratégie Océan Bleu","tr":"Mavi Okyanus Stratejisi","nl":"Blauwe Oceaan Strategie","ru":"Стратегия голубого океана","zh":"蓝海战略","pt_BR":"Estratégia do Oceano Azul","pt_PT":"Estratégia do Oceano Azul"}, back_translations: {"es":"Una estrategia de criación de espacio de mercado sin contestación, tornando a competencia irrelevante; desarrollada por Kim y Mauborgne como alternativa a competir en los mercados de \"oceano rojo\" existentes.","de":"Eine Strategie zur Schaffung eines unbestrittenen Marktplatzes, indem der Wettbewerb irrelevant gemacht wird; von Kim und Mauborgne als Alternative zum Konkurrieren in bestehenden \"roten Ozean\"-Märkten entwickelt.","fr":"Une stratégie de création d'un espace de marché incontesté en rendant la concurrence non pertinente; développée par Kim et Mauborgne comme alternative à la concurrence dans les marchés \"océan rouge\" existants.","tr":"Rekabeti önemsiz kılarak tartışmasız pazar alanı yaratma stratejisi; Kim ve Mauborgne tarafından mevcut \"kırmızı okyanus\" pazarlarında rekabet etmeye alternatif olarak öncülük edilmiştir.","nl":"Een strategie voor het creëren van onbetwiste marktruimte door concurrentie irrelevant te maken; ontwikkeld door Kim en Mauborgne als alternatief voor concurreren in bestaande \"rode oceaan\"-markten.","ru":"Стратегия создания неоспариваемого рыночного пространства путём превращения конкуренции в нечто несущественное; разработана Кимом и Моборном как альтернатива конкуренции на существующих рынках \"красного океана\".","zh":"通过使竞争变得无关紧要来开辟无争竞市场空间的战略；由金伟灿和莫博涅提出，作为在现有\"红海\"市场中竞争的替代方案。","pt_BR":"Uma estratégia de criação de espaço de mercado sem contestação, tornando a concorrência irrelevante; desenvolvida por Kim e Mauborgne como alternativa a competir nos mercados de \"oceano vermelho\" existentes.","pt_PT":"Uma estratégia de criação de espaço de mercado sem contestação, tornando a concorrência irrelevante; desenvolvida por Kim e Mauborgne como alternativa a competir nos mercados de \"oceano vermelho\" existentes."}},
  { id: 'dc-business-0143', deck_id: 'deck-business', front: 'Loss Leader Pricing', back: 'A strategy of selling a product below cost to attract customers who then buy more profitable items; common in retail and subscription businesses.', sort_order: 143 , front_translations: {"es":"Precificación Isca (Loss Leader Pricing)","de":"Lockvogelpreise (Loss Leader Pricing)","fr":"Prix d'appel (Loss Leader Pricing)","tr":"Kayıp Lider Fiyatlandırması","nl":"Verliesleider Prijsstelling (Loss Leader Pricing)","ru":"Ценообразование по принципу товара-приманки (Loss Leader)","zh":"亏本销售定价策略","pt_BR":"Precificação Isca (Loss Leader Pricing)","pt_PT":"Preço Isca (Loss Leader Pricing)"}, back_translations: {"es":"Una estrategia de vender un producto debajo del costo para atrair clientes que entonces compram itens más lucrativos; comum en el minorista y en negocios de assinatura.","de":"Eine Strategie, ein Produkt unter Selbstkosten zu verkaufen, um Kunden anzuziehen, die dann profitablere Artikel kaufen; verbreitet im Einzel- und Abonnementhandel.","fr":"Une stratégie consistant à vendre un produit en dessous de son coût pour attirer des clients qui achètent ensuite des articles plus rentables; courant dans le commerce de détail et les entreprises par abonnement.","tr":"Müşterileri çekmek amacıyla bir ürünü maliyetinin altında satma stratejisi; bu müşteriler daha sonra kârlı ürünler satın alır; perakende ve abonelik işletmelerinde yaygındır.","nl":"Een strategie waarbij een product onder de kostprijs wordt verkocht om klanten aan te trekken die vervolgens winstgevendere artikelen kopen; gebruikelijk in de detailhandel en abonnementsbedrijven.","ru":"Стратегия продажи товара ниже себестоимости для привлечения покупателей, которые затем приобретают более прибыльные позиции; распространена в розничной торговле и подписочных бизнесах.","zh":"以低于成本的价格销售产品来吸引顾客，随后促使其购买更高利润商品的策略；在零售业和订阅制企业中很常见。","pt_BR":"Uma estratégia de vender um produto abaixo do custo para atrair clientes que então compram itens mais lucrativos; comum no varejo e em negócios de assinatura.","pt_PT":"Uma estratégia de vender um produto abaixo do custo para atrair clientes que depois compram artigos mais lucrativos; comum no retalho e em negócios de subscrição."}},
  { id: 'dc-business-0144', deck_id: 'deck-business', front: 'Price Discrimination', back: 'Charging different prices to different customer segments for the same product based on willingness to pay; examples include student discounts, surge pricing, and geographic pricing.', sort_order: 144 , front_translations: {"es":"Discriminación de Preços","de":"Preisdifferenzierung","fr":"Discrimination par les prix","tr":"Fiyat Farklılaştırması","nl":"Prijsdiscriminatie","ru":"Ценовая дискриминация","zh":"价格歧视","pt_BR":"Discriminação de Preços","pt_PT":"Discriminação de Preços"}, back_translations: {"es":"Cobrar precios diferentes de diferentes segmentos de clientes por el mismo producto con base en la disposición para pagar; ejemplos incluyen descontos estudantis, precios dinamicos y precios geográficos.","de":"Das Berechnen unterschiedlicher Preise für verschiedene Kundensegmente für dasselbe Produkt basierend auf der Zahlungsbereitschaft; Beispiele sind Studentenrabatte, dynamische Preise und geografische Preisgestaltung.","fr":"Facturer des prix différents à différents segments de clients pour le même produit en fonction de leur disposition à payer; exemples: réductions étudiantes, tarification dynamique et tarification géographique.","tr":"Ödeme isteğine göre aynı ürün için farklı müşteri segmentlerine farklı fiyatlar uygulamak; örnekler arasında öğrenci indirimleri, dinamik fiyatlandırma ve coğrafi fiyatlandırma yer alır.","nl":"Het berekenen van verschillende prijzen aan verschillende klantsegmenten voor hetzelfde product op basis van betalingsbereidheid; voorbeelden zijn studentenkortingen, dynamische prijzen en geografische prijzen.","ru":"Установление разных цен для разных сегментов покупателей на один и тот же товар в зависимости от готовности платить; примеры — студенческие скидки, динамическое ценообразование и географическое ценообразование.","zh":"根据支付意愿，对不同客户群体就同一产品收取不同价格；例如学生折扣、动态定价和地区差异定价。","pt_BR":"Cobrar preços diferentes de diferentes segmentos de clientes pelo mesmo produto com base na disposição para pagar; exemplos incluem descontos estudantis, preços dinâmicos e preços geográficos.","pt_PT":"Cobrar preços diferentes a diferentes segmentos de clientes pelo mesmo produto com base na disposição para pagar; exemplos incluem descontos para estudantes, preços dinâmicos e preços geográficos."}},
  { id: 'dc-business-0145', deck_id: 'deck-business', front: 'Contribution Margin Ratio', back: 'Contribution Margin divided by Revenue, expressed as a percentage. It shows the proportion of each sales dollar available to cover fixed costs and generate profit.', sort_order: 145 , front_translations: {"es":"Índice de Margem de Contribuición","de":"Deckungsbeitragsquote","fr":"Taux de marge sur coût variable","tr":"Katkı Payı Oranı","nl":"Dekkingsbijdrageverhouding","ru":"Коэффициент маржинального дохода","zh":"贡献毛益率","pt_BR":"Índice de Margem de Contribuição","pt_PT":"Rácio de Margem de Contribuição"}, back_translations: {"es":"Margem de Contribuición dividida por la Receita, expressa como percentual. Mostra a proporción de cada real de ventas disponible para cobrir costos fixos y gerar ganancia.","de":"Deckungsbeitrag geteilt durch Umsatz, ausgedrückt als Prozentsatz. Sie zeigt den Anteil jedes Umsatz-Dollars, der zur Deckung der Fixkosten und zur Gewinnerzielung verfügbar ist.","fr":"La marge sur coût variable divisée par le chiffre d'affaires, exprimée en pourcentage. Il montre la proportion de chaque dollar de ventes disponible pour couvrir les coûts fixes et générer du profit.","tr":"Katkı Payının Gelire bölünmesiyle elde edilen yüzde. Her satış dolarının sabit maliyetleri karşılamak ve kâr elde etmek için kullanılabilecek oranını gösterir.","nl":"Contribution Margin gedeeld door omzet, uitgedrukt als percentage. Het toont het deel van elke verkoopdollar dat beschikbaar is om vaste kosten te dekken en winst te genereren.","ru":"Маржинальный доход, делённый на выручку, выраженный в процентах. Показывает долю каждого рубля продаж, доступную для покрытия постоянных затрат и получения прибыли.","zh":"贡献毛益除以收入，以百分比表示。显示每一元销售额中可用于覆盖固定成本并产生利润的比例。","pt_BR":"Margem de Contribuição dividida pela Receita, expressa como percentual. Mostra a proporção de cada real de vendas disponível para cobrir custos fixos e gerar lucro.","pt_PT":"Margem de Contribuição dividida pela Receita, expressa em percentagem. Mostra a proporção de cada euro de vendas disponível para cobrir custos fixos e gerar lucro."}},
  { id: 'dc-business-0146', deck_id: 'deck-business', front: 'Economic Moat', back: 'Warren Buffett\'s term for a sustainable competitive advantage that protects a company\'s market share and profits from competitors, such as brand, network effects, or switching costs.', sort_order: 146 , front_translations: {"es":"Fosso Economico (Economic Moat)","de":"Wirtschaftlicher Burggraben (Economic Moat)","fr":"Fossé économique (Economic Moat)","tr":"Ekonomik Hendek (Economic Moat)","nl":"Economische gracht (Economic Moat)","ru":"Экономический ров (Economic Moat)","zh":"经济护城河","pt_BR":"Fosso Econômico (Economic Moat)","pt_PT":"Fosso Económico (Economic Moat)"}, back_translations: {"es":"El termo de Warren Buffett para una vantaje competitiva sustentable que protege a participación de mercado y los ganancias de una empresa de los competidores, como marca, efectos de red o costos de troca.","de":"Warren Buffetts Begriff für einen nachhaltigen Wettbewerbsvorteil, der den Marktanteil und die Gewinne eines Unternehmens vor Konkurrenten schützt, wie Marke, Netzwerkeffekte oder Wechselkosten.","fr":"Le terme de Warren Buffett pour désigner un avantage concurrentiel durable qui protège la part de marché et les bénéfices d'une entreprise contre les concurrents, comme une marque forte, des effets de réseau ou des coûts de transition.","tr":"Warren Buffett'ın marka, ağ etkileri veya geçiş maliyetleri gibi unsurlarla bir şirketin pazar payını ve kârını rakiplerden koruyan sürdürülebilir rekabet avantajı için kullandığı terim.","nl":"Warren Buffetts term voor een duurzaam concurrentievoordeel dat het marktaandeel en de winst van een bedrijf beschermt tegen concurrenten, zoals merk, netwerkeffecten of overstapkosten.","ru":"Термин Уоррена Баффета для обозначения устойчивого конкурентного преимущества, защищающего долю рынка и прибыль компании от конкурентов — например, бренд, сетевые эффекты или издержки переключения.","zh":"沃伦·巴菲特用于描述可持续竞争优势的术语，如品牌、网络效应或转换成本，能保护公司的市场份额和利润不受竞争对手侵蚀。","pt_BR":"O termo de Warren Buffett para uma vantagem competitiva sustentável que protege a participação de mercado e os lucros de uma empresa dos concorrentes, como marca, efeitos de rede ou custos de troca.","pt_PT":"O termo de Warren Buffett para uma vantagem competitiva sustentável que protege a quota de mercado e os lucros de uma empresa dos concorrentes, como marca, efeitos de rede ou custos de mudança."}},
  { id: 'dc-business-0147', deck_id: 'deck-business', front: 'Switching Costs', back: 'The costs (financial, time, or effort) a customer incurs when switching from one product to a competitor\'s; high switching costs increase customer retention and pricing power.', sort_order: 147 , front_translations: {"es":"Custos de Troca (Switching Costs)","de":"Wechselkosten","fr":"Coûts de changement (Switching Costs)","tr":"Geçiş Maliyetleri","nl":"Overstapkosten (Switching Costs)","ru":"Издержки переключения","zh":"转换成本","pt_BR":"Custos de Troca (Switching Costs)","pt_PT":"Custos de Mudança (Switching Costs)"}, back_translations: {"es":"Los costos (financeros, de tiempo o esforço) que un cliente incorre al mudar de un producto para el de un competidor; altos costos de troca aumentan a retención de clientes y el poder de precificación.","de":"Die Kosten (finanziell, zeitlich oder aufwandsbezogen), die einem Kunden entstehen, wenn er von einem Produkt zu dem eines Konkurrenten wechselt; hohe Wechselkosten erhöhen die Kundenbindung und die Preisgestaltungsmacht.","fr":"Les coûts (financiers, temporels ou en efforts) qu'un client supporte lors du passage d'un produit à celui d'un concurrent; des coûts de changement élevés augmentent la rétention des clients et le pouvoir de fixation des prix.","tr":"Bir müşterinin bir üründen rakibin ürününe geçerken katlandığı maliyetler (finansal, zaman veya çaba); yüksek geçiş maliyetleri müşteriyi elde tutmayı ve fiyatlandırma gücünü artırır.","nl":"De kosten (financieel, tijd of inspanning) die een klant maakt bij het overstappen van één product naar dat van een concurrent; hoge overstapkosten verhogen klantbehoud en prijsmacht.","ru":"Затраты (финансовые, временные или усилия), которые несёт клиент при переходе с одного продукта на продукт конкурента; высокие издержки переключения повышают удержание клиентов и ценовую власть.","zh":"客户从一种产品转向竞争对手产品时所产生的成本（财务、时间或精力）；高转换成本能提升客户留存率和定价权。","pt_BR":"Os custos (financeiros, de tempo ou esforço) que um cliente incorre ao mudar de um produto para o de um concorrente; altos custos de troca aumentam a retenção de clientes e o poder de precificação.","pt_PT":"Os custos (financeiros, de tempo ou esforço) que um cliente suporta ao mudar de um produto para o de um concorrente; custos de mudança elevados aumentam a retenção de clientes e o poder de fixação de preços."}},
  { id: 'dc-business-0148', deck_id: 'deck-business', front: 'Vertical Integration', back: 'A strategy where a company expands into different stages of its supply chain (e.g., a manufacturer acquiring its supplier or distributor) to control costs and quality.', sort_order: 148 , front_translations: {"es":"Integración Vertical","de":"Vertikale Integration","fr":"Intégration verticale","tr":"Dikey Entegrasyon","nl":"Verticale integratie","ru":"Вертикальная интеграция","zh":"纵向整合","pt_BR":"Integração Vertical","pt_PT":"Integração Vertical"}, back_translations: {"es":"Una estrategia en que una empresa se expande para diferentes etapas de su cadena de suministro (ex.: un fabricante adquirindo su proveedor o distribuidor) para controlar costos y calidad.","de":"Eine Strategie, bei der ein Unternehmen in verschiedene Stufen seiner Lieferkette expandiert (z. B. ein Hersteller, der seinen Zulieferer oder Händler übernimmt), um Kosten und Qualität zu kontrollieren.","fr":"Une stratégie par laquelle une entreprise s'étend à différentes étapes de sa chaîne d'approvisionnement (ex: un fabricant acquérant son fournisseur ou distributeur) pour contrôler les coûts et la qualité.","tr":"Bir şirketin maliyetleri ve kaliteyi kontrol etmek amacıyla tedarik zincirinin farklı aşamalarına genişlediği strateji (örn. bir üreticinin tedarikçisini veya distribütörünü satın alması).","nl":"Een strategie waarbij een bedrijf uitbreidt naar verschillende stadia van zijn toeleveringsketen (bijv. een fabrikant die zijn leverancier of distributeur overneemt) om kosten en kwaliteit te beheersen.","ru":"Стратегия, при которой компания расширяется на различные этапы цепочки поставок (например, производитель приобретает поставщика или дистрибьютора) с целью контроля затрат и качества.","zh":"公司扩展至供应链不同阶段的战略（如制造商收购其供应商或分销商），以控制成本和质量。","pt_BR":"Uma estratégia em que uma empresa se expande para diferentes estágios de sua cadeia de suprimentos (ex.: um fabricante adquirindo seu fornecedor ou distribuidor) para controlar custos e qualidade.","pt_PT":"Uma estratégia em que uma empresa se expande para diferentes etapas da sua cadeia de abastecimento (ex.: um fabricante a adquirir o seu fornecedor ou distribuidor) para controlar custos e qualidade."}},
  { id: 'dc-business-0149', deck_id: 'deck-business', front: 'Horizontal Integration', back: 'A strategy where a company acquires or merges with competitors at the same stage of the supply chain to increase market share and reduce competition.', sort_order: 149 , front_translations: {"es":"Integración Horizontal","de":"Horizontale Integration","fr":"Intégration horizontale","tr":"Yatay Entegrasyon","nl":"Horizontale integratie","ru":"Горизонтальная интеграция","zh":"横向整合","pt_BR":"Integração Horizontal","pt_PT":"Integração Horizontal"}, back_translations: {"es":"Una estrategia en que una empresa adquire o se funde con competidores en el mismo etapa de la cadena de suministro para aumentar a participación de mercado y reduzir a competencia.","de":"Eine Strategie, bei der ein Unternehmen Wettbewerber auf derselben Stufe der Lieferkette übernimmt oder mit ihnen fusioniert, um den Marktanteil zu erhöhen und den Wettbewerb zu reduzieren.","fr":"Une stratégie par laquelle une entreprise acquiert ou fusionne avec des concurrents au même stade de la chaîne d'approvisionnement pour augmenter sa part de marché et réduire la concurrence.","tr":"Pazar payını artırmak ve rekabeti azaltmak amacıyla bir şirketin tedarik zincirinin aynı aşamasındaki rakiplerini satın aldığı veya onlarla birleştiği strateji.","nl":"Een strategie waarbij een bedrijf concurrenten op hetzelfde niveau van de toeleveringsketen overneemt of ermee fuseert om het marktaandeel te vergroten en de concurrentie te verminderen.","ru":"Стратегия, при которой компания приобретает конкурентов или сливается с ними на том же этапе цепочки поставок с целью увеличения доли рынка и снижения конкуренции.","zh":"公司收购或合并处于供应链同一阶段的竞争对手，以扩大市场份额、减少竞争的战略。","pt_BR":"Uma estratégia em que uma empresa adquire ou se funde com concorrentes no mesmo estágio da cadeia de suprimentos para aumentar a participação de mercado e reduzir a concorrência.","pt_PT":"Uma estratégia em que uma empresa adquire ou se funde com concorrentes no mesmo estágio da cadeia de abastecimento para aumentar a quota de mercado e reduzir a concorrência."}},
  { id: 'dc-business-0150', deck_id: 'deck-business', front: 'Profit Pool', back: 'The total profits available in an industry at all points along the value chain; analyzing the profit pool helps companies identify where to compete and where margins are highest.', sort_order: 150 , front_translations: {"es":"Pool de Lucros (Profit Pool)","de":"Gewinnpool (Profit Pool)","fr":"Bassin de profits (Profit Pool)","tr":"Kâr Havuzu (Profit Pool)","nl":"Winstpool (Profit Pool)","ru":"Пул прибыли (Profit Pool)","zh":"利润池","pt_BR":"Pool de Lucros (Profit Pool)","pt_PT":"Pool de Lucros (Profit Pool)"}, back_translations: {"es":"El total de ganancias disponible en un setor en todos los puntos a lo ancho de la cadeia de valor; analisar el pool de ganancias ayuda las empresas a identificar donde competir y donde las margens son más elevadas.","de":"Der Gesamtgewinn, der in einer Branche an allen Punkten der Wertschöpfungskette verfügbar ist; die Analyse des Gewinnpools hilft Unternehmen zu identifizieren, wo sie konkurrieren sollen und wo die Margen am höchsten sind.","fr":"Le total des profits disponibles dans un secteur à tous les points de la chaîne de valeur; l'analyse du bassin de profits aide les entreprises à identifier où concourir et où les marges sont les plus élevées.","tr":"Değer zincirinin tüm noktalarında bir sektörde mevcut olan toplam kârlar; kâr havuzu analizi, şirketlerin nerede rekabet edeceklerini ve marjların en yüksek olduğu yerleri belirlemelerine yardımcı olur.","nl":"De totale winsten beschikbaar in een sector op alle punten langs de waardeketen; het analyseren van de winstpool helpt bedrijven te identificeren waar ze moeten concurreren en waar de marges het hoogst zijn.","ru":"Совокупная прибыль, доступная в отрасли на всех этапах цепочки создания стоимости; анализ пула прибыли помогает компаниям определить, где конкурировать и где маржа наиболее высока.","zh":"在价值链所有节点上，一个行业中可获得的总利润；分析利润池有助于企业确定在哪里竞争以及哪里的利润率最高。","pt_BR":"O total de lucros disponível em um setor em todos os pontos ao longo da cadeia de valor; analisar o pool de lucros ajuda as empresas a identificar onde competir e onde as margens são mais elevadas.","pt_PT":"O total de lucros disponível num setor em todos os pontos ao longo da cadeia de valor; analisar o pool de lucros ajuda as empresas a identificar onde competir e onde as margens são mais elevadas."}},
];
